-- Poems batch 451
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('yuding-66','題梨嶺','歐陽詹','唐','御定全唐诗','yuding','','[]','南北風煙即異方，連峰危棧倚蒼蒼。',32,'御定全唐詩/json/349.json','["南北風煙即異方，連峰危棧倚蒼蒼。", "哀猿咽水偏高處，誰不沾衣望故鄉。"]'),
('yuding-67','秋夜寄僧','歐陽詹','唐','御定全唐诗','yuding','','[]','尚被浮名誘此身，今時誰與德為鄰。',32,'御定全唐詩/json/349.json','["尚被浮名誘此身，今時誰與德為鄰。", "遙知是夜檀溪上，月照千峰為一人。"]'),
('yuding-68','觀送葬','歐陽詹','唐','御定全唐诗','yuding','','[]','何事悲酸淚滿巾，浮生共是北邙塵。',32,'御定全唐詩/json/349.json','["何事悲酸淚滿巾，浮生共是北邙塵。", "他時不見北山路，死者還曾哭送人。"]'),
('yuding-69','宿建溪中宵即事','歐陽詹','唐','御定全唐诗','yuding','','[]','nNvF一席眠還坐，蛙噪螢飛夜未央。',34,'御定全唐詩/json/349.json','["nNvF一席眠還坐，蛙噪螢飛夜未央。", "僮僕舟人空寂寂，隔簾微月入中倉。"]'),
('yuding-70','題王明府郊亭','歐陽詹','唐','御定全唐诗','yuding','','[]','日日郊亭啟竹扉，論桑勸穡是常機。',32,'御定全唐詩/json/349.json','["日日郊亭啟竹扉，論桑勸穡是常機。", "山城要得牛羊下，方與農人分背歸。"]'),
('yuding-71','塞上行','歐陽詹','唐','御定全唐诗','yuding','','[]','聞說胡兵欲利秋，昨來投筆到營州。',32,'御定全唐詩/json/349.json','["聞說胡兵欲利秋，昨來投筆到營州。", "驍雄已許將軍用，邊塞無勞天子憂。"]'),
('yuding-72','題別業','歐陽詹','唐','御定全唐诗','yuding','','[]','千山江上背斜暉，一徑中峰見所歸。',32,'御定全唐詩/json/349.json','["千山江上背斜暉，一徑中峰見所歸。", "不信扁舟回在晚，宿雲先已到柴扉。"]'),
('yuding-73','九日廣陵登高懷邵二先輩','歐陽詹','唐','御定全唐诗','yuding','','[]','簪萸泛菊俯平阡，飲過三杯卻惘然。',32,'御定全唐詩/json/349.json','["簪萸泛菊俯平阡，飲過三杯卻惘然。", "十歲此辰同醉友，登高各處已三年。"]'),
('yuding-74','題延平劍潭','歐陽詹','唐','御定全唐诗','yuding','','[]','想像精靈欲見難，通津一去水漫漫。',32,'御定全唐詩/json/349.json','["想像精靈欲見難，通津一去水漫漫。", "空餘昔日淩霜色，長與澄潭生晝寒。"]'),
('yuding-75','晚泊漳州營頭亭','歐陽詹','唐','御定全唐诗','yuding','','[]','回峰疊嶂繞庭隅，散點煙霞勝畫圖。',32,'御定全唐詩/json/349.json','["回峰疊嶂繞庭隅，散點煙霞勝畫圖。", "日暮華軒卷長箔，太清雲上對蓬壺。"]'),
('yuding-76','贈山南嚴兵馬使','歐陽詹','唐','御定全唐诗','yuding','','[]','為雁為鴻弟與兄，如雕如鶚傑連英。',32,'御定全唐詩/json/349.json','["為雁為鴻弟與兄，如雕如鶚傑連英。", "天旋地轉煙雲黑，共鼓長風六合清。"]'),
('yuding-77','除夜侍酒呈諸兄示舍弟','歐陽詹','唐','御定全唐诗','yuding','','[]','莫歎明朝又一春，相看堪共貴茲身。',32,'御定全唐詩/json/349.json','["莫歎明朝又一春，相看堪共貴茲身。", "悠悠寰宇同今夜，膝下傳杯有幾人。"]'),
('yuding-0','奉平淮夷雅表：皇武命丞相度董師集大功也','柳宗元','唐','御定全唐诗','yuding','','[]','皇耆其武，于溵於淮。既巾乃車，環蔡具來。',420,'御定全唐詩/json/350.json','["皇耆其武，于溵於淮。既巾乃車，環蔡具來。", "狡眾昏嚚，甚毒於酲。狂奔叫呶，以幹大刑。", "皇咨於度，惟汝一德。曠誅四紀，其徯汝克。", "錫汝斧鉞，其往視師。師是蔡人，以宥以厘。", "度拜稽首，廟於元龜。既祃既類，於社是宜。", "金節煌煌，錫質雕戈。犀甲熊旗，威命是荷。", "度拜稽首，出次於東。天子餞之，罍斝是崇。", "鼎臑俎胾，五獻百籩。凡百卿士，班以周旋。", "既涉於滻，乃翼乃前。孰圖厥猶，其佐多賢。", "宛宛周道，于山於川。遠揚邇昭，陟降連連。", "我旆我旗，于道於陌。訓于群帥，拳勇來格。", "公曰徐之，無恃額額。式和爾容，惟義之宅。", "進次於郾，彼昏卒狂。裒凶鞠頑，鋒蝟斧螗，", "王旅渾渾，是佚是怙。既獲敵師，若饑得餔。", "蔡凶伊窘，悉起來聚。左搗其虛，靡愆厥慮。", "載辟載袚，丞相是臨。弛其武刑，諭我德心。", "其危既安，有長如林。曾是讙譊，化為謳吟。", "皇曰來歸，汝複相予。爵之成國，胙以夏區。", "度拜稽首，天子聖神。度拜稽首，皇佑下人。", "淮夷既平，震是朔南。宜廟宜郊，以告德音。", "歸牛休馬，豐稼於野。我武惟皇，永保無疆。"]'),
('yuding-1','奉平淮夷雅表：方城命愬守也卒入蔡得其大醜以平淮右','柳宗元','唐','御定全唐诗','yuding','','[]','方城臨臨，王卒峙之。匪徼匪競，皇有正命。',402,'御定全唐詩/json/350.json','["方城臨臨，王卒峙之。匪徼匪競，皇有正命。", "皇命於愬，往舒餘仁。踣彼艱頑，柔惠是馴。", "愬拜即命，於皇之訓。既礪既攻，以後厥刃。", "王師嶷嶷，熊羆是式。銜勇韜力，日思予殛。", "寇昏以狂，敢蹈愬疆。士獲厥心，大袒高驤。", "長戟酋矛，粲其綏章。右翦左屠，聿禽其良。", "其良既宥，告以父母。恩柔于肌，卒貢爾有。", "維彼攸恃，乃偵乃誘。維彼攸宅，乃發乃守。", "其恃爰獲，我功我多。陰諜厥圖，以究爾訛。", "雨雪洋洋，大風來加，於燠其寒，於邇其遐。", "汝陰之茫，懸瓠之峨。是震是拔，大殲厥家。", "狡虜既縻，輸于國都。示之市人，即社行誅。", "乃諭乃止，蔡有厚喜。完其室家，仰父俯子。", "汝水沄沄，既清而彌。蔡人行歌，我步逶遲。", "蔡人歌矣，蔡風和矣。孰纇蔡初，胡甈爾居。", "式慕以康，為願有餘。是究是咨，皇德既舒。", "皇曰咨愬，裕乃父功。昔我文祖，惟西平是庸。", "內誨於家，外刑於邦。孰是蔡人，而不率從。", "蔡人率止，惟西平有子。西平有子，惟我有臣。", "疇允大邦，俾惠我人。于廟告功，以顧萬方。"]'),
('yuding-2','唐鐃歌鼓吹曲十二篇：隋亂既極唐師起晉陽平姦豪為生人義主以仁興武為晉陽武第一','柳宗元','唐','御定全唐诗','yuding','','[]','晉陽武，奮義威。煬之渝，德焉歸。氓畢屠，綏者誰。',104,'御定全唐詩/json/350.json','["晉陽武，奮義威。煬之渝，德焉歸。氓畢屠，綏者誰。", "皇烈烈，專天機。號以仁，揚其旗。日之升，九土晞。", "斥田坼，流洪輝。有其二，翼餘隋。斫梟鷔，連熊螭。", "枯以肉，勍者羸。後土蕩，玄穹彌。合之育，莽然施。", "惟德輔，慶無期。"]'),
('yuding-3','唐鐃歌鼓吹曲十二篇：唐既受命李密自敗來歸以開黎陽斥東土為獸之窮第二','柳宗元','唐','御定全唐诗','yuding','','[]','獸之窮，奔大麓。天厚黃德，狙獷服。甲之櫜，弓弭矢箙。',93,'御定全唐詩/json/350.json','["獸之窮，奔大麓。天厚黃德，狙獷服。甲之櫜，弓弭矢箙。", "皇旅靖，敵逾蹙。自亡其徒，匪予戮。屈rH猛，虔栗栗。", "縻以尺組，啖以秩。黎之陽，土茫茫。富兵戎，盈倉箱。", "乏者德，莫能享。驅豺兕，授我疆。"]'),
('yuding-4','唐鐃歌鼓吹曲十二篇：太宗師討王充竇建德助逆師奮擊武牢下擒之遂降充為戰武牢第三','柳宗元','唐','御定全唐诗','yuding','','[]','戰武牢，動河朔。逆之助，圖掎角。怒鷇麛，抗喬嶽。',75,'御定全唐詩/json/350.json','["戰武牢，動河朔。逆之助，圖掎角。怒鷇麛，抗喬嶽。", "翹萌牙，傲霜雹。王謀內定，申掌握。鋪施芟夷，二主縛。", "憚華戎，廓封略。命之vG，卑以斫。歸有德，唯先覺。"]'),
('yuding-5','唐鐃歌鼓吹曲十二篇：薛舉據涇以死子仁杲尤勇以暴師平之為涇水黃第四','柳宗元','唐','御定全唐诗','yuding','','[]','涇水黃，隴野茫。負太白，騰天狼。有鳥鷙立，羽翼張。',72,'御定全唐詩/json/350.json','["涇水黃，隴野茫。負太白，騰天狼。有鳥鷙立，羽翼張。", "鉤喙決前，鉅趯傍。怒飛饑嘯，翾不可當。老雄死，", "列缺掉幟，招搖耀鋩。鬼神來助，夢嘉祥。腦塗原野，"]'),
('yuding-6','唐鐃歌鼓吹曲十二篇：輔氏憑江淮竟東海命將平之為奔鯨沛第五','柳宗元','唐','御定全唐诗','yuding','','[]','奔鯨沛，蕩海垠。吐霓翳日，腥浮雲。帝怒下顧，',45,'御定全唐詩/json/350.json','["奔鯨沛，蕩海垠。吐霓翳日，腥浮雲。帝怒下顧，", "披攘蒙霿，開海門。地平水靜，浮天根。羲和顯耀，"]'),
('yuding-7','唐鐃歌鼓吹曲十二篇：梁之餘保荊衡巴巫窮南越良將取之不以師為苞蘗第六','柳宗元','唐','御定全唐诗','yuding','','[]','苞枿ba矣，惟恨之蟠。彌巴蔽荊，負南極以安。',112,'御定全唐詩/json/350.json','["苞枿ba矣，惟恨之蟠。彌巴蔽荊，負南極以安。", "曰我舊梁氏，緝綏艱難。江漢之阻，都邑固以完。聖人作，", "化敵為家，慮則中。浩浩海裔，不威而同。系縲降王。", "定厥功。澶漫萬里，宣唐風。蠻夷九譯，咸來從。", "凱旋金奏，象形容。震赫萬國，罔不龔。"]'),
('yuding-8','唐鐃歌鼓吹曲十二篇：李軌保河右師臨之不克變或執以降為河右平第七','柳宗元','唐','御定全唐诗','yuding','','[]','河右澶漫，頑為之魁。王師如雷震，昆侖以頹。',87,'御定全唐詩/json/350.json','["河右澶漫，頑為之魁。王師如雷震，昆侖以頹。", "上聾下聰，驁不可回。助仇抗有德，惟人之災。", "乃潰乃奮，執縛歸厥命。萬室蒙其仁，一夫則病。", "濡以鴻澤，皇之聖。威畏德懷，功以定。順之於理，"]'),
('yuding-9','唐鐃歌鼓吹曲十二篇：突厥之大古夷狄莫疆焉師大破之降其國告于廟為鐵山碎第八','柳宗元','唐','御定全唐诗','yuding','','[]','鐵山碎，大漠舒。二虜勁，連穹廬。背北海，專坤隅。',74,'御定全唐詩/json/350.json','["鐵山碎，大漠舒。二虜勁，連穹廬。背北海，專坤隅。", "歲來侵邊。或傅於都。天子命元帥，奮其雄圖。破定襄，", "威武輝耀，明鬼區。利澤彌萬祀，功不可逾。官臣拜手，"]'),
('yuding-10','唐鐃歌鼓吹曲十二篇：劉武周敗裴寂咸有晉地太宗滅之為靖本邦第九','柳宗元','唐','御定全唐诗','yuding','','[]','本邦伊晉，惟時不靖。根柢之搖，枯葉攸病。守臣不任，',45,'御定全唐詩/json/350.json','["本邦伊晉，惟時不靖。根柢之搖，枯葉攸病。守臣不任，", "群頑既夷，庶績咸正。皇謨載大，惟人之慶。"]'),
('yuding-11','唐鐃歌鼓吹曲十二篇：李靖滅吐谷渾西海上為吐谷渾第十','柳宗元','唐','御定全唐诗','yuding','','[]','吐谷渾盛強，背西海以誇。歲侵擾我疆，退匿險且遐。',156,'御定全唐詩/json/350.json','["吐谷渾盛強，背西海以誇。歲侵擾我疆，退匿險且遐。", "帝謂神武師，往征靖皇家。烈烈旆其旗，熊虎雜龍蛇。", "王旅千萬人，銜枚默無嘩。束刃逾山徼，張翼縱漠沙。", "一舉刈膻腥，屍骸積如麻。除惡務本根，況敢遺萌芽。", "洋洋西海水，威命窮天涯。系虜來王都，犒樂窮休嘉。", "登高望還師，竟野如春華。行者靡不歸，親戚讙要遮。", "凱旋獻清廟，萬國思無邪。"]'),
('yuding-12','唐鐃歌鼓吹曲十二篇：李靖滅高昌為高昌第十一','柳宗元','唐','御定全唐诗','yuding','','[]','麹氏雄西北，別絕臣外區。既恃遠且險，縱傲不我虞。',132,'御定全唐詩/json/350.json','["麹氏雄西北，別絕臣外區。既恃遠且險，縱傲不我虞。", "烈烈王者師，熊螭以為徒。龍旗翻海浪，馹騎馳坤隅。", "賁育搏嬰兒，一掃不復餘。平沙際天極，但見黃雲驅。", "臣靖執長纓，智勇伏囚拘。文皇南面坐，夷狄千群趨。", "咸稱天子神，往古不得俱。獻號天可汗，以覆我國都。", "兵戎不交害，各保性與軀。"]'),
('yuding-13','唐鐃歌鼓吹曲十二篇：既克東蠻群臣請圖蠻夷狀如周書王會為東蠻第十二','柳宗元','唐','御定全唐诗','yuding','','[]','東蠻有謝氏，冠帶理海中。自言我異世，雖聖莫能通。',132,'御定全唐詩/json/350.json','["東蠻有謝氏，冠帶理海中。自言我異世，雖聖莫能通。", "王卒如飛翰，鵬鶱駭群龍。轟然自天墜，乃信神武功。", "系虜君臣人，累累來自東。無思不服從，唐業如山崇。", "百辟拜稽首，咸願圖形容。如周王會書，永永傳無窮。", "睢盱萬狀乖，咿嗢九譯重。廣輪撫四海，浩浩知皇風。", "歌詩鐃鼓閑，以壯我元戎。"]'),
('yuding-14','貞符','柳宗元','唐','御定全唐诗','yuding','','[]','于穆敬德，黎人皇之。惟貞厥符，浩浩將之。仁函於膚，',147,'御定全唐詩/json/350.json','["于穆敬德，黎人皇之。惟貞厥符，浩浩將之。仁函於膚，", "懿其休風，是喣是吹。父子熙熙，相寧以嬉。賦徹而藏，", "十聖嗣於理，仁後之子。子思孝父，易患於己。拱之戴之，", "神之曷依，宜仁之歸。濮沿于北，祝栗于南。幅員西東，", "曷徒祝之，心誠篤之。神協人同，道以告之。俾彌憶萬年，", "有號於天，僉曰嗚呼。咨爾皇靈，無替厥符。"]'),
('yuding-15','視民詩','柳宗元','唐','御定全唐诗','yuding','','[]','帝視民情，匪幽匪明。慘或在腹，已如色聲。亦無動威，',106,'御定全唐詩/json/350.json','["帝視民情，匪幽匪明。慘或在腹，已如色聲。亦無動威，", "乃定天子，乃開萬國。萬國既分，乃釋蠹民，乃學與仕，", "士實蕩蕩，農實董董，工實濛濛，賈實融融。左右惟一，", "品物載休，惟天子守，乃二公之久。惟天子明，", "四夷是則，永懷不忒。"]'),
('yuding-0','同劉二十八院長述舊言懷感時書事奉寄澧州張員外使君五十二韻之作因其韻增至八十通贈二君子','柳宗元','唐','御定全唐诗','yuding','','[]','弱歲游玄圃，先容幸棄瑕。名勞長者記，文許後生誇。',578,'御定全唐詩/json/351.json','["弱歲游玄圃，先容幸棄瑕。名勞長者記，文許後生誇。", "鷃翼嘗披隼，蓬心類倚麻。繼酬天祿署，俱尉甸侯家。", "憲府初收跡，丹墀共拜嘉。分行參瑞獸，傳點亂宮鴉。", "執簡寧循枉，持書每去邪。鸞鳳標魏闕，熊武負崇牙。", "辨色宜相顧，傾心自不嘩。金爐仄流月，紫殿啟晨霞。", "未竟遷喬樂，俄成失路嗟。還如渡遼水，更似謫長沙。", "別怨秦城暮，途窮越嶺斜。訟庭閑枳棘，候吏逐麋麚。", "三載皇恩暢，千年聖曆遐。朝宗延駕海，師役罷梁溠。", "京邑搜貞幹，南宮步渥窪。世惟材是梓，人仰驥中驊。", "欻刺苗入地，仍逾贛石崖。禮容垂gb琫，戍備響錏鍜。", "寵即郎官舊，威從太守加。建旟翻鷙鳥，負弩繞文蛇。", "冊府榮八命，中闈盛六珈。肯隨胡質矯，方惡馬融奢。", "褒德符新換，懷仁道並遮。俗嫌龍節晚，朝訝介圭賒。", "禹貢輸苞匭，周官賦秉秅。雄風吞七澤，異產控三巴。", "即事觀農稼，因時展物華。秋原被蘭葉，春渚漲桃花。", "令肅軍無擾，程懸市禁貰。不應虞竭澤，寧複歎棲苴。", "蹀躞騶先駕，籠銅鼓報衙。染毫東國素，濡印錦溪砂。", "貨積舟難泊，人歸山倍畬。吳歈工折柳，楚舞舊傳芭。", "隱幾松為曲，傾樽石作汙。寒初榮橘柚，夏首薦枇杷。", "祀變荊巫禱，風移魯婦髽。已聞施愷悌，還睹正奇邪。", "慕友慚連璧，言姻喜附葭。沉埋全死地，流落半生涯。", "入郡腰恒折，逢人手盡叉。敢辭親恥汙，唯恐長疵瘕。", "善幻迷冰火，齊諧笑柏塗。東門牛屢飯，中散虱空爬。", "逸戲看猿鬥，殊音辨馬撾。渚行狐作孽，林宿鳥為ff。"]'),
('yuding-1','弘農公以碩德偉材屈于誣枉左官三歲復為大僚天監昭明人心感悅宗元竄仗湘浦拜賀末由謹獻詩五十韻以畢微志','柳宗元','唐','御定全唐诗','yuding','','[]','知命儒為貴，時中聖所臧。處心齊寵辱，遇物任行藏。',576,'御定全唐詩/json/351.json','["知命儒為貴，時中聖所臧。處心齊寵辱，遇物任行藏。", "關識新安地，封傳臨晉鄉。挺生推豹蔚，遐步仰龍驤。", "幹有千尋竦，精聞百煉鋼。茂功期舜禹，高韻狀羲黃。", "足逸詩書囿，鋒搖翰墨場。雅歌張仲德，頌祝魯侯昌。", "憲府初騰價，神州轉耀鋩。右言盈簡策，左轄備條綱。", "響切晨趨佩，煙濃近侍香。司儀六禮洽，論將七兵揚。", "合樂來儀鳳，尊祠重餼羊。卿材優柱石，公器擅岩廊。", "峻節臨衡嶠，和風滿豫章。人歸父母育，郡得股肱良。", "細故誰留念，煩言肯過防。璧非真盜客，金有誤持郎。", "龜虎休前寄，貂蟬冠舊行。訓刑方命呂，理劇複推張。", "直用明銷惡，還將道勝剛。敬逾齊國社，恩比召南棠。", "希怨猶逢怒，多容競忤強。火炎侵琬琰，鷹擊謬鸞凰。", "刻木終難對，焚芝未改芳。遠遷逾桂嶺，中徙滯餘杭。", "顧土雖懷趙，知天詎畏匡。論嫌齊物誕，騷愛遠遊傷。", "麗澤周群品，重明照萬方。鬥間收紫氣，臺上掛清光。", "福為深仁集，妖從盛德禳。秦民啼畎畝，周士舞康莊。", "采綬還垂艾，華簪更截肪。高居遷鼎邑，遙傅好書王。", "碧樹環金穀，丹霞映上陽。留歡唱容與，要醉對清涼。", "故友仍同裏，常僚每合堂。淵龍過許劭，冰鯉吊王祥。", "玉漏天門靜，銅駝禦路荒。澗瀍秋瀲灩，嵩少暮微茫。", "遵渚徒雲樂，沖天自不遑。降神終入輔，種德會明揚。", "獨棄傖人國，難窺夫子牆。通家殊孔李，舊好即潘楊。", "世議排張摯，時情棄仲翔。不言縲絏枉，徒恨纆徽長。", "賈賦愁單閼，鄒書怯大樑。炯心那自是，昭世懶佯狂。"]'),
('yuding-2','酬韶州裴曹長使君寄道州呂八大使因以見示二十韻一首','柳宗元','唐','御定全唐诗','yuding','','[]','金馬嘗齊入，銅魚亦共頒。疑山看積翠，湞水想澄灣。',243,'御定全唐詩/json/351.json','["金馬嘗齊入，銅魚亦共頒。疑山看積翠，湞水想澄灣。", "標榜同驚俗，清明兩照奸。乘軺參孔僅，按節服侯狦。", "賈傅辭甯切，虞童發未sG。秉心方的的，騰口任es々。", "聖理高懸象，爰書降罰鍰。德風流海外，和氣滿人寰。", "禦魅恩猶貸，思賢淚自潸。在亡均寂寞，零落間惸鰥。", "夙志隨憂盡，殘肌觸瘴m5。月光搖淺瀨，風韻碎枯菅。", "海俗衣猶卉，山夷髻不鬟。泥沙潛虺蜮，榛莽鬥豺獌。", "循省誠知懼，安排只自憪。食貧甘莽鹵，被褐謝斕斒。", "遠物裁青罽，時珍饌白鷳。長捐楚客佩，未賜大夫環。", "異政徒雲仰，高蹤不可攀。空勞慰憔悴，妍唱劇妖嫻。"]'),
('yuding-3','酬婁秀才將之淮南見贈之什','柳宗元','唐','御定全唐诗','yuding','','[]','遠棄甘幽獨，誰雲值故人。好音憐鎩羽，濡沫慰窮鱗。',144,'御定全唐詩/json/351.json','["遠棄甘幽獨，誰雲值故人。好音憐鎩羽，濡沫慰窮鱗。", "困志情惟舊，相知樂更新。浪遊輕費日，醉舞詎傷春。", "風月歡寧間，星霜分益親。已將名是患，還用道為鄰。", "機事齊飄瓦，嫌猜比拾塵。高冠餘肯賦，長鋏子忘貧。", "晼晚驚移律，暌攜忽此辰。開顏時不再，絆足去何因。", "海上銷魂別，天邊吊影身。只應西澗水，寂寞但垂綸。"]'),
('yuding-4','酬婁秀才寓居開元寺，早秋月夜病中見寄','柳宗元','唐','御定全唐诗','yuding','','[]','客有故園思，瀟湘生夜愁。病依居士室，夢繞羽人丘。',72,'御定全唐詩/json/351.json','["客有故園思，瀟湘生夜愁。病依居士室，夢繞羽人丘。", "味道憐知止，遺名得自求。壁空殘月曙，門掩候蟲秋。", "謬委雙金重，難征雜佩酬。碧霄無枉路，徒此助離憂。"]'),
('yuding-5','初秋夜坐贈吳武陵','柳宗元','唐','御定全唐诗','yuding','','[]','稍稍雨侵竹，翻翻鵲驚叢。美人隔湘浦，一夕生秋風。',96,'御定全唐詩/json/351.json','["稍稍雨侵竹，翻翻鵲驚叢。美人隔湘浦，一夕生秋風。", "積霧杳難極，滄波浩無窮。相思豈雲遠，即席莫與同。", "若人抱奇音，朱弦縆枯桐。清商激西顥，泛灩淩長空。", "自得本無作，天成諒非功。希聲閟大樸，聾俗何由聰。"]'),
('yuding-6','晨詣超師院讀禪經','柳宗元','唐','御定全唐诗','yuding','','[]','汲井漱寒齒，清心拂塵服。閑持貝葉書，步出東齋讀。',84,'御定全唐詩/json/351.json','["汲井漱寒齒，清心拂塵服。閑持貝葉書，步出東齋讀。", "真源了無取，妄跡世所逐。遺言冀可冥，繕性何由熟。", "道人庭宇靜，苔色連深竹。日出霧露餘，青松如膏沐。", "澹然離言說，悟悅心自足。"]'),
('yuding-7','贈江華長老','柳宗元','唐','御定全唐诗','yuding','','[]','老僧道機熟，默語心皆寂。去歲別舂陵，沿流此投跡。',72,'御定全唐詩/json/351.json','["老僧道機熟，默語心皆寂。去歲別舂陵，沿流此投跡。", "室空無侍者，巾屨唯掛壁。一飯不願餘，跏趺便終夕。", "風窗疏竹響，露井寒松滴。偶地即安居，滿庭芳草積。"]'),
('yuding-8','巽上人以竹閑自采新茶見贈，酬之以詩','柳宗元','唐','御定全唐诗','yuding','','[]','芳叢翳湘竹，零露凝清華。複此雪山客，晨朝掇靈芽。',96,'御定全唐詩/json/351.json','["芳叢翳湘竹，零露凝清華。複此雪山客，晨朝掇靈芽。", "蒸煙俯石瀨，咫尺淩丹崖。圓方麗奇色，圭璧無纖瑕。", "呼兒爨金鼎，餘馥延幽遐。滌慮發真照，還源蕩昏邪。", "猶同甘露飯，佛事熏毗耶。咄此蓬瀛侶，無乃貴流霞。"]'),
('yuding-9','零陵贈李卿元侍禦簡吳武陵','柳宗元','唐','御定全唐诗','yuding','','[]','理世固輕士，棄捐湘之湄。陽光競四溟，敲石安所施。',96,'御定全唐詩/json/351.json','["理世固輕士，棄捐湘之湄。陽光競四溟，敲石安所施。", "鎩羽集枯乾，低昂互鳴悲。朔雲吐風寒，寂曆窮秋時。", "君子尚容與，小人守競危。慘淒日相視，離憂坐自滋。", "尊酒聊可酌，放歌諒徒為。惜無協律者，窈眇弦吾詩。"]'),
('yuding-10','界圍岩水簾','柳宗元','唐','御定全唐诗','yuding','','[]','界圍匯湘曲，青壁環澄流。懸泉粲成簾，羅注無時休。',120,'御定全唐詩/json/351.json','["界圍匯湘曲，青壁環澄流。懸泉粲成簾，羅注無時休。", "韻磬叩凝碧，鏘鏘徹岩幽。丹霞冠其巔，想像淩虛遊。", "靈境不可狀，鬼工諒難求。忽如朝玉皇，天冕垂前旒。", "楚臣昔南逐，有意仍丹丘。今我始北旋，新詔釋縲囚。", "采真誠眷戀，許國無淹留。再來寄幽夢，遺貯催行舟。"]'),
('yuding-11','古東門行','柳宗元','唐','御定全唐诗','yuding','','[]','漢家三十六將軍，東方雷動橫陣雲。雞鳴函穀客如霧，',72,'御定全唐詩/json/351.json','["漢家三十六將軍，東方雷動橫陣雲。雞鳴函穀客如霧，", "當街一叱百吏走，馮敬胸中函匕首。凶徒側耳潛愜心，", "羌胡轂下一朝起，敵國舟中非所擬。安陵誰辨削礪功，"]'),
('yuding-12','寄韋珩','柳宗元','唐','御定全唐诗','yuding','','[]','初拜柳州出東郊，道旁相送皆賢豪。回眸炫晃別群玉，',120,'御定全唐詩/json/351.json','["初拜柳州出東郊，道旁相送皆賢豪。回眸炫晃別群玉，", "桂州西南又千里，漓水鬥石麻蘭高。陰森野葛交蔽日，", "饑行夜坐設方略，籠銅枹鼓手所操。奇瘡釘骨狀如箭，", "邇來氣少筋骨露，蒼白瀄汩盈顛毛。君今矻矻又竄逐，", "聖恩倘忽念地葦，十年踐蹈久已勞。幸因解網入鳥獸，"]'),
('yuding-13','奉和楊尚書郴州追和故李中書夏日登北樓十韻之作依本詩韻次用','柳宗元','唐','御定全唐诗','yuding','','[]','郡樓有遺唱，新和敵南金。境以道情得，人期幽夢尋。',120,'御定全唐詩/json/351.json','["郡樓有遺唱，新和敵南金。境以道情得，人期幽夢尋。", "層軒隔炎暑，迥野恣窺臨。鳳去徽音續，芝焚芳意深。", "遊鱗出陷浦，唳鶴繞仙岑。風起三湘浪，雲生萬里陰。", "宏規齊德宇，麗藻競詞林。靜契分憂術，閑同遲客心。", "驊騮當遠步，鶗鴂莫相侵。今日登高處，還聞梁父吟。"]'),
('yuding-14','楊尚書寄郴筆知是小生本樣令更商榷使盡其功輒獻長句','柳宗元','唐','御定全唐诗','yuding','','[]','截玉銛錐作妙形，貯雲含霧到南溟。尚書舊用裁天詔，',40,'御定全唐詩/json/351.json','["截玉銛錐作妙形，貯雲含霧到南溟。尚書舊用裁天詔，", "桂陽卿月光輝遍，毫末應傳顧兔靈。"]'),
('yuding-15','南省轉牒欲具江國圖令盡通風俗故事','柳宗元','唐','御定全唐诗','yuding','','[]','聖代提封盡海壖，狼荒猶得紀山川。華夷圖上應初錄，',40,'御定全唐詩/json/351.json','["聖代提封盡海壖，狼荒猶得紀山川。華夷圖上應初錄，", "南宮有意求遺俗，試檢周書王會篇。"]'),
('yuding-16','與浩初上人同看山寄京華親故','柳宗元','唐','御定全唐诗','yuding','','[]','海畔尖山似劍鋩，秋來處處割愁腸。',32,'御定全唐詩/json/351.json','["海畔尖山似劍鋩，秋來處處割愁腸。", "若為化得身千億，散上峰頭望故鄉。"]'),
('yuding-17','再至界圍岩水簾遂宿岩下','柳宗元','唐','御定全唐诗','yuding','','[]','發春念長違，中夏欣再睹。是時植物秀，杳若臨懸圃。',108,'御定全唐詩/json/351.json','["發春念長違，中夏欣再睹。是時植物秀，杳若臨懸圃。", "歊陽訝垂冰，白日驚雷雨。笙簧潭際起，鸛鶴雲間舞。", "古苔凝青枝，陰草濕翠羽。蔽空素彩列，激浪寒光聚。", "的皪沉珠淵，鏘鳴捐佩浦。幽岩畫屏倚，新月玉鉤吐。", "夜涼星滿川，忽疑眠洞府。"]'),
('yuding-18','詔追赴都回寄零陵親故','柳宗元','唐','御定全唐诗','yuding','','[]','每憶纖鱗遊尺澤，翻愁弱羽上丹霄。',32,'御定全唐詩/json/351.json','["每憶纖鱗遊尺澤，翻愁弱羽上丹霄。", "岸傍古堠應無數，次第行看別路遙。"]'),
('yuding-19','過衡山見新花開卻寄弟','柳宗元','唐','御定全唐诗','yuding','','[]','故國名園久別離，今朝楚樹發南枝。',32,'御定全唐詩/json/351.json','["故國名園久別離，今朝楚樹發南枝。", "晴天歸路好相逐，正是峰前回雁時。"]'),
('yuding-20','汨羅遇風','柳宗元','唐','御定全唐诗','yuding','','[]','南來不作楚臣悲，重入修門自有期。',32,'御定全唐詩/json/351.json','["南來不作楚臣悲，重入修門自有期。", "為報春風汨羅道，莫將波浪枉明時。"]'),
('yuding-21','朗州竇常員外寄劉二十八詩，見促行騎走筆酬贈','柳宗元','唐','御定全唐诗','yuding','','[]','投荒垂一紀，新詔下荊扉。疑比莊周夢，情如蘇武歸。',48,'御定全唐詩/json/351.json','["投荒垂一紀，新詔下荊扉。疑比莊周夢，情如蘇武歸。", "賜環留逸響，五馬助征騑。不羨衡陽雁，春來前後飛。"]'),
('yuding-22','離觴不醉，至驛卻寄相送諸公','柳宗元','唐','御定全唐诗','yuding','','[]','無限居人送獨醒，可憐寂寞到長亭。',32,'御定全唐詩/json/351.json','["無限居人送獨醒，可憐寂寞到長亭。", "荊州不遇高陽侶，一夜春寒滿下廳。"]'),
('yuding-23','北還登漢陽北原題臨川驛','柳宗元','唐','御定全唐诗','yuding','','[]','驅車方向闕，回首一臨川。多壘非餘恥，無謀終自憐。',48,'御定全唐詩/json/351.json','["驅車方向闕，回首一臨川。多壘非餘恥，無謀終自憐。", "亂松知野寺，餘雪記山田。惆悵樵漁事，今還又落然。"]'),
('yuding-24','善謔驛和劉夢得酹淳于先生','柳宗元','唐','御定全唐诗','yuding','','[]','水上鵠已去，亭中鳥又鳴。辭因使楚重，名為救齊成。',48,'御定全唐詩/json/351.json','["水上鵠已去，亭中鳥又鳴。辭因使楚重，名為救齊成。", "荒壟遽千古，羽觴難再傾。劉伶今日意，異代是同聲。"]'),
('yuding-25','詔追赴都二月至灞亭上','柳宗元','唐','御定全唐诗','yuding','','[]','十一年前南渡客，四千裏外北歸人。',32,'御定全唐詩/json/351.json','["十一年前南渡客，四千裏外北歸人。", "詔書許逐陽和至，驛路開花處處新。"]'),
('yuding-26','李西川薦琴石','柳宗元','唐','御定全唐诗','yuding','','[]','遠師騶忌鼓鳴琴，去和南風愜舜心。',32,'御定全唐詩/json/351.json','["遠師騶忌鼓鳴琴，去和南風愜舜心。", "從此他山千古重，殷勤曾是奉徽音。"]'),
('yuding-27','同劉二十八哭呂衡州，兼寄江陵李元二侍禦','柳宗元','唐','御定全唐诗','yuding','','[]','衡嶽新摧天柱峰，士林憔悴泣相逢。只令文字傳青簡，',40,'御定全唐詩/json/351.json','["衡嶽新摧天柱峰，士林憔悴泣相逢。只令文字傳青簡，", "遙想荊州人物論，幾回中夜惜元龍。"]'),
('yuding-28','奉酬楊侍郎丈因送八叔拾遺戲贈詔追南來諸賓二首','柳宗元','唐','御定全唐诗','yuding','','[]','貞一來時送彩箋，一行歸雁慰驚弦。',60,'御定全唐詩/json/351.json','["貞一來時送彩箋，一行歸雁慰驚弦。", "翰林寂寞誰為主，鳴鳳應須早上天。", "一生判卻歸休，謂著南冠到頭。", "冶長雖解縲絏，無由得見東周。"]'),
('yuding-29','商山鄰路有孤松往來斫以為明好事者憐之編竹成楥遂其生植感而賦詩','柳宗元','唐','御定全唐诗','yuding','','[]','孤松停翠蓋，托根臨廣路。不以險自防，遂為明所誤。',48,'御定全唐詩/json/351.json','["孤松停翠蓋，托根臨廣路。不以險自防，遂為明所誤。", "幸逢仁惠意，重此藩籬護。猶有半心存，時將承雨露。"]'),
('yuding-30','衡陽與夢得分路贈別','柳宗元','唐','御定全唐诗','yuding','','[]','十年憔悴到秦京，誰料翻為嶺外行。伏波故道風煙在，',40,'御定全唐詩/json/351.json','["十年憔悴到秦京，誰料翻為嶺外行。伏波故道風煙在，", "今朝不用臨河別，垂淚千行便濯纓。"]'),
('yuding-31','重別夢得','柳宗元','唐','御定全唐诗','yuding','','[]','二十年來萬事同，今朝岐路忽西東。',32,'御定全唐詩/json/351.json','["二十年來萬事同，今朝岐路忽西東。", "皇恩若許歸田去，晚歲當為鄰舍翁。"]'),
('yuding-32','三贈劉員外','柳宗元','唐','御定全唐诗','yuding','','[]','信書成自誤，經事漸知非。今日臨岐別，何年待汝歸。',24,'御定全唐詩/json/351.json','["信書成自誤，經事漸知非。今日臨岐別，何年待汝歸。"]'),
('yuding-33','再上湘江','柳宗元','唐','御定全唐诗','yuding','','[]','好在湘江水，今朝又上來。不知從此去，更遣幾年回。',24,'御定全唐詩/json/351.json','["好在湘江水，今朝又上來。不知從此去，更遣幾年回。"]'),
('yuding-34','清水驛叢竹天水趙雲餘手種一十二莖','柳宗元','唐','御定全唐诗','yuding','','[]','簷下疏篁十二莖，襄陽從事寄幽情。',32,'御定全唐詩/json/351.json','["簷下疏篁十二莖，襄陽從事寄幽情。", "只應更使伶倫見，寫盡雌雄雙鳳鳴。"]'),
('yuding-35','長沙驛前南樓感舊','柳宗元','唐','御定全唐诗','yuding','','[]','海鶴一為別，存亡三十秋。今來數行淚，獨上驛南樓。',24,'御定全唐詩/json/351.json','["海鶴一為別，存亡三十秋。今來數行淚，獨上驛南樓。"]'),
('yuding-36','桂州北望秦驛，手開竹徑至釣磯，留待徐容州','柳宗元','唐','御定全唐诗','yuding','','[]','幽徑為誰開，美人城北來。王程倘餘暇，一上子陵台。',24,'御定全唐詩/json/351.json','["幽徑為誰開，美人城北來。王程倘餘暇，一上子陵台。"]'),
('yuding-37','登柳州城樓寄漳汀封連四州','柳宗元','唐','御定全唐诗','yuding','','[]','城上高樓接大荒，海天愁思正茫茫。驚風亂颭芙蓉水，',40,'御定全唐詩/json/351.json','["城上高樓接大荒，海天愁思正茫茫。驚風亂颭芙蓉水，", "共來百越文身地，猶自音書滯一鄉。"]'),
('yuding-38','柳州寄丈人周韶州','柳宗元','唐','御定全唐诗','yuding','','[]','越絕孤城千萬峰，空齋不語坐高舂。印文生綠經旬合，',40,'御定全唐詩/json/351.json','["越絕孤城千萬峰，空齋不語坐高舂。印文生綠經旬合，", "丈人本自忘機事，為想年來憔悴容。"]'),
('yuding-0','登柳州峨山','柳宗元','唐','御定全唐诗','yuding','','[]','荒山秋日午，獨上意悠悠。如何望鄉處，西北是融州。',24,'御定全唐詩/json/352.json','["荒山秋日午，獨上意悠悠。如何望鄉處，西北是融州。"]'),
('yuding-1','得盧衡州書因以詩寄','柳宗元','唐','御定全唐诗','yuding','','[]','臨蒸且莫歎炎方，為報秋來雁幾行。林邑東回山似戟，',40,'御定全唐詩/json/352.json','["臨蒸且莫歎炎方，為報秋來雁幾行。林邑東回山似戟，", "非是白蘋洲畔客，還將遠意問瀟湘。"]'),
('yuding-2','答劉連州邦字','柳宗元','唐','御定全唐诗','yuding','','[]','連璧本難雙，分符刺小邦。崩雲下漓水，劈箭上潯江。',48,'御定全唐詩/json/352.json','["連璧本難雙，分符刺小邦。崩雲下漓水，劈箭上潯江。", "負弩啼寒狖，鳴枹驚夜狵。遙憐郡山好，謝守但臨窗。"]'),
('yuding-3','嶺南江行','柳宗元','唐','御定全唐诗','yuding','','[]','瘴江南去入雲煙，望盡黃茆是海邊。山腹雨晴添象跡，',40,'御定全唐詩/json/352.json','["瘴江南去入雲煙，望盡黃茆是海邊。山腹雨晴添象跡，", "從此憂來非一事，豈容華髮待流年。"]'),
('yuding-4','柳州峒氓','柳宗元','唐','御定全唐诗','yuding','','[]','郡城南下接通津，異服殊音不可親。青箬裹鹽歸峒客，',40,'御定全唐詩/json/352.json','["郡城南下接通津，異服殊音不可親。青箬裹鹽歸峒客，", "愁向公庭問重譯，欲投章甫作文身。"]'),
('yuding-5','酬徐二中丞普甯郡內池館即事見寄','柳宗元','唐','御定全唐诗','yuding','','[]','鵷鴻念舊行，虛館對芳塘。落日明朱檻，繁花照羽觴。',48,'御定全唐詩/json/352.json','["鵷鴻念舊行，虛館對芳塘。落日明朱檻，繁花照羽觴。", "泉歸滄海近，樹入楚山長。榮賤俱為累，相期在故鄉。"]'),
('yuding-6','酬賈鵬山人郡內新栽松寓興見贈二首','柳宗元','唐','御定全唐诗','yuding','','[]','芳朽自為別，無心乃玄功。夭夭日放花，榮耀將安窮。',120,'御定全唐詩/json/352.json','["芳朽自為別，無心乃玄功。夭夭日放花，榮耀將安窮。", "青松遺澗底，擢蒔茲庭中。積雪表明秀，寒花助蔥蘢。", "貞幽夙有慕，持以延清風。", "無能常閉閣，偶以靜見名。奇姿來遠山，忽似人家生。", "勁色不改舊，芳心與誰榮。喧卑豈所安，任物非我情。", "清韻動竽瑟，諧此風中聲。"]'),
('yuding-7','種柳戲題','柳宗元','唐','御定全唐诗','yuding','','[]','柳州柳刺史，種柳柳江邊。談笑為故事，推移成昔年。',48,'御定全唐詩/json/352.json','["柳州柳刺史，種柳柳江邊。談笑為故事，推移成昔年。", "垂陰當覆地，聳幹會參天。好作思人樹，慚無惠化傳。"]'),
('yuding-8','柳州二月榕葉落盡偶題','柳宗元','唐','御定全唐诗','yuding','','[]','宦情羈思共淒淒，春半如秋意轉迷。',32,'御定全唐詩/json/352.json','["宦情羈思共淒淒，春半如秋意轉迷。", "山城過雨百花盡，榕葉滿庭鶯亂啼。"]'),
('yuding-9','浩初上人見貽絕句欲登仙人山因以酬之','柳宗元','唐','御定全唐诗','yuding','','[]','珠樹玲瓏隔翠微，病來方外事多違。',32,'御定全唐詩/json/352.json','["珠樹玲瓏隔翠微，病來方外事多違。", "仙山不屬分符客，一任淩空錫杖飛。"]'),
('yuding-10','雨中贈仙人山賈山人','柳宗元','唐','御定全唐诗','yuding','','[]','寒江夜雨聲潺潺，曉雲遮盡仙人山。',32,'御定全唐詩/json/352.json','["寒江夜雨聲潺潺，曉雲遮盡仙人山。", "遙知玄豹在深處，下笑羈絆泥塗間。"]'),
('yuding-11','別舍弟宗一','柳宗元','唐','御定全唐诗','yuding','','[]','零落殘紅倍黯然，雙垂別淚越江邊。一身去國六千里，',40,'御定全唐詩/json/352.json','["零落殘紅倍黯然，雙垂別淚越江邊。一身去國六千里，", "欲知此後相思夢，長在荊門郢樹煙。"]'),
('yuding-12','奉和周二十二丈酬郴州侍郎衡江夜泊得韶州書并附當州生黃茶一封率然成篇代意之作','柳宗元','唐','御定全唐诗','yuding','','[]','丘山仰德耀，天路下征騑。夢喜三刀近，書嫌五載違。',48,'御定全唐詩/json/352.json','["丘山仰德耀，天路下征騑。夢喜三刀近，書嫌五載違。", "凝情江月落，屬思嶺雲飛。會入司徒府，還邀周掾歸。"]'),
('yuding-13','殷賢戲批書後寄劉連州並示孟侖二童','柳宗元','唐','御定全唐诗','yuding','','[]','書成欲寄庾安西，紙背應勞手自題。',32,'御定全唐詩/json/352.json','["書成欲寄庾安西，紙背應勞手自題。", "聞道近來諸子弟，臨池尋已厭家雞。"]'),
('yuding-14','重贈二首','柳宗元','唐','御定全唐诗','yuding','','[]','聞道將雛向墨池，劉家還有異同詞。',64,'御定全唐詩/json/352.json','["聞道將雛向墨池，劉家還有異同詞。", "如今試遣隈牆問，已道世人那得知。", "世上悠悠不識真，薑芽儘是捧心人。", "若道柳家無子弟，往年何事乞西賓。"]'),
('yuding-15','疊前','柳宗元','唐','御定全唐诗','yuding','','[]','小學新翻墨沼波，羨君瓊樹散枝柯。',32,'御定全唐詩/json/352.json','["小學新翻墨沼波，羨君瓊樹散枝柯。", "左家弄玉唯嬌女，空覺庭前鳥跡多。"]'),
('yuding-16','疊後','柳宗元','唐','御定全唐诗','yuding','','[]','事業無成恥藝成，南宮起草舊連名。',32,'御定全唐詩/json/352.json','["事業無成恥藝成，南宮起草舊連名。", "勸君火急添功用，趁取當時二妙聲。"]'),
('yuding-17','銅魚使赴都寄親友','柳宗元','唐','御定全唐诗','yuding','','[]','行盡關山萬里餘，到時閭井是荒墟。',32,'御定全唐詩/json/352.json','["行盡關山萬里餘，到時閭井是荒墟。", "附庸唯有銅魚使，此後無因寄遠書。"]'),
('yuding-18','韓漳州書報徹上人亡因寄二絕','柳宗元','唐','御定全唐诗','yuding','','[]','早歲京華聽越吟，聞君江海分逾深。',64,'御定全唐詩/json/352.json','["早歲京華聽越吟，聞君江海分逾深。", "他時若寫蘭亭會，莫畫高僧支道林。", "頻把瓊書出袖中，獨吟遺句立秋風。", "桂江日夜流千里，揮淚何時到甬東。"]'),
('yuding-19','柳州城西北隅種柑樹','柳宗元','唐','御定全唐诗','yuding','','[]','手種黃柑二百株，春來新葉遍城隅。方同楚客憐皇樹，',40,'御定全唐詩/json/352.json','["手種黃柑二百株，春來新葉遍城隅。方同楚客憐皇樹，", "若教坐待成林日，滋味還堪養老夫。"]'),
('yuding-20','聞徹上人亡寄侍郎楊丈','柳宗元','唐','御定全唐诗','yuding','','[]','東越高僧還姓湯，幾時瓊佩觸鳴璫。',32,'御定全唐詩/json/352.json','["東越高僧還姓湯，幾時瓊佩觸鳴璫。", "空花一散不知處，誰採金英與侍郎。"]'),
('yuding-21','段九秀才處見亡友呂衡州書跡','柳宗元','唐','御定全唐诗','yuding','','[]','交侶平生意最親，衡陽往事似分身。',32,'御定全唐詩/json/352.json','["交侶平生意最親，衡陽往事似分身。", "袖中忽見三行字，拭淚相看是故人。"]'),
('yuding-22','柳州寄京中親故','柳宗元','唐','御定全唐诗','yuding','','[]','林邑山連瘴海秋，牂牁水向郡前流。',32,'御定全唐詩/json/352.json','["林邑山連瘴海秋，牂牁水向郡前流。", "勞君遠問龍城地，正北三千到錦州。"]'),
('yuding-23','種木槲花','柳宗元','唐','御定全唐诗','yuding','','[]','上苑年年占物華，飄零今日在天涯。',32,'御定全唐詩/json/352.json','["上苑年年占物華，飄零今日在天涯。", "只因長作龍城守，剩種庭前木槲花。"]'),
('yuding-24','摘櫻桃贈元居士，時在望仙亭南樓與朱道士同處','柳宗元','唐','御定全唐诗','yuding','','[]','海上朱櫻贈所思，樓居況是望仙時。',32,'御定全唐詩/json/352.json','["海上朱櫻贈所思，樓居況是望仙時。", "蓬萊羽客如相訪，不是偷桃一小兒。"]'),
('yuding-25','酬曹侍禦過象縣見寄','柳宗元','唐','御定全唐诗','yuding','','[]','破額山前碧玉流，騷人遙駐木蘭舟。',32,'御定全唐詩/json/352.json','["破額山前碧玉流，騷人遙駐木蘭舟。", "春風無限瀟湘意，欲采蘋花不自由。"]'),
('yuding-26','法華寺石門精舍三十韻','柳宗元','唐','御定全唐诗','yuding','','[]','拘情病幽鬱，曠志寄高爽。',360,'御定全唐詩/json/352.json','["拘情病幽鬱，曠志寄高爽。", "願言懷名緇，東峰旦夕仰。始欣雲雨霽，尤悅草木長。", "道同有愛弟，披拂恣心賞。松溪窈窕入，石棧夤緣上。", "蘿葛綿層甍，莓苔侵標榜。密林互對聳，絕壁儼雙敞。", "塹峭出蒙籠，墟險臨滉漾。稍疑地脈斷，悠若天梯往。", "結構罩群崖，回環驅萬象。小劫不逾瞬，大千若在掌。", "體空得化元，觀有遺細想。喧煩困蠛蠓，局蹐疲魍魎。", "寸進諒何營，尋直非所枉。探奇極遙矚，窮妙閟清響。", "理會方在今，神開庶殊曩。茲游苟不嗣，浩氣竟誰養。", "道異誠所希，名賓匪餘仗。超攄藉外獎，俯默有內朗。", "鑒爾揖古風，終焉乃吾黨。潛軀委韁鎖，高步謝塵坱。", "蓄志徒為勞，追蹤將焉仿。淹留值頹暮，眷戀睇遐壤。", "映日雁聯軒，翻雲波泱漭。殊風紛已萃，鄉路悠且廣。", "羈木畏漂浮，離旌倦搖盪。昔人歎違志，出處今已兩。", "何用期所歸，浮圖有遺像。幽蹊不盈尺，虛室有函丈。", "微言信可傳，申旦稽吾顙。"]'),
('yuding-27','遊朝陽岩遂登西亭二十韻','柳宗元','唐','御定全唐诗','yuding','','[]','謫棄殊隱淪，登陟非遠郊。所懷緩伊鬱，詎欲肩夷巢。',240,'御定全唐詩/json/352.json','["謫棄殊隱淪，登陟非遠郊。所懷緩伊鬱，詎欲肩夷巢。", "高岩瞰清江，幽窟潛神蛟。開曠延陽景，回薄攢林梢。", "西亭構其巔，反宇臨呀庨。背瞻星辰興，下見雲雨交。", "惜非吾鄉土，得以蔭菁茆。羈貫去江介，世仕尚函崤。", "故墅即灃川，數畝均肥磽。台館葺荒丘，池塘疏沉坳。", "會有圭組戀，遂貽山林嘲。薄軀信無庸，瑣屑劇鬥筲。", "囚居固其宜，厚羞久已包。庭除植蓬艾，隟牖懸蠨蛸。", "所賴山川客，扁舟枉長梢。挹流敵清觴，掇野代嘉肴。", "適道有高言，取樂非弦匏。逍遙屏幽昧，淡薄辭喧呶。", "晨雞不餘欺，風雨聞嘐嘐。再期永日閑，提挈移中庖。"]'),
('yuding-28','湘口館瀟湘二水所會','柳宗元','唐','御定全唐诗','yuding','','[]','九疑浚傾奔，臨源委縈回。會合屬空曠，泓澄停風雷。',108,'御定全唐詩/json/352.json','["九疑浚傾奔，臨源委縈回。會合屬空曠，泓澄停風雷。", "高館軒霞表，危樓臨山隈。茲辰始澄霽，纖雲盡褰開。", "天秋日正中，水碧無塵埃。杳杳漁父吟，叫叫羈鴻哀。", "境勝豈不豫，慮分固難裁。升高欲自舒，彌使遠念來。", "歸流駛且廣，泛舟絕沿洄。"]'),
('yuding-29','登蒲州石磯望橫江口潭島深迥斜對香零山','柳宗元','唐','御定全唐诗','yuding','','[]','隱憂倦永夜，淩霧臨江津。猿鳴稍已疏，登石娛清淪。',132,'御定全唐詩/json/352.json','["隱憂倦永夜，淩霧臨江津。猿鳴稍已疏，登石娛清淪。", "日出洲渚靜，澄明皛無垠。浮暉翻高禽，沉景照文鱗。", "雙江匯西奔，詭怪潛坤珍。孤山乃北峙，森爽棲靈神。", "洄潭或動容，島嶼疑搖振。陶埴茲擇土，蒲魚相與鄰。", "信美非所安，羈心屢逡巡。糾結良可解，紆鬱亦已伸。", "高歌返故室，自罔非所欣。"]'),
('yuding-30','南澗中題','柳宗元','唐','御定全唐诗','yuding','','[]','秋氣集南澗，獨遊亭午時。回風一蕭瑟，林影久參差。',96,'御定全唐詩/json/352.json','["秋氣集南澗，獨遊亭午時。回風一蕭瑟，林影久參差。", "始至若有得，稍深遂忘疲。羈禽響幽谷，寒藻舞淪漪。", "去國魂已遠，懷人淚空垂。孤生易為感，失路少所宜。", "索寞竟何事，徘徊只自知。誰為後來者，當與此心期。"]'),
('yuding-31','游石角過小嶺至長烏村','柳宗元','唐','御定全唐诗','yuding','','[]','志適不期貴，道存豈偷生。久忘上封事，複笑升天行。',168,'御定全唐詩/json/352.json','["志適不期貴，道存豈偷生。久忘上封事，複笑升天行。", "竄逐宦湘浦，搖心劇懸旌。始驚陷世議，終欲逃天刑。", "歲月殺憂栗，慵疏寡將迎。追遊疑所愛，且複舒吾情。", "石角恣幽步，長烏遂遐征。磴回茂樹斷，景晏寒川明。", "曠望少行人，時聞田鸛鳴。風篁冒水遠，霜稻侵山平。", "稍與人事閑，益知身世輕。為農信可樂，居寵真虛榮。", "喬木餘故國，願言果丹誠。四支反田畝，釋志東皋耕。"]'),
('yuding-32','與崔策登西山','柳宗元','唐','御定全唐诗','yuding','','[]','鶴鳴楚山靜，露白秋江曉。連袂度危橋，縈回出林杪。',144,'御定全唐詩/json/352.json','["鶴鳴楚山靜，露白秋江曉。連袂度危橋，縈回出林杪。", "西岑極遠目，毫末皆可了。重疊九疑高，微茫洞庭小。", "迥窮兩儀際，高出萬象表。馳景泛頹波，遙風遞寒筱。", "謫居安所習，稍厭從紛擾。生同胥靡遺，壽比彭鏗夭。", "蹇連困顛踣，愚蒙怯幽眇。非令親愛疏，誰使心神悄。", "偶茲遁山水，得以觀魚鳥。吾子幸淹留，緩我愁腸繞。"]'),
('yuding-33','構法華寺西亭','柳宗元','唐','御定全唐诗','yuding','','[]','竄身楚南極，山水窮險艱。步登最高寺，蕭散任疏頑。',168,'御定全唐詩/json/352.json','["竄身楚南極，山水窮險艱。步登最高寺，蕭散任疏頑。", "西垂下鬥絕，欲似窺人寰。反如在幽谷，榛翳不可攀。", "命童恣披翦，葺宇橫斷山。割如判清濁，飄若升雲間。", "遠岫攢眾頂，澄江抱清灣。夕照臨軒墮，棲鳥當我還。", "菡萏溢嘉色，筼簹遺清斑。神舒屏羈鎖，志適忘幽孱。", "棄逐久枯槁，迨今始開顏。賞心難久留，離念來相關。", "北望間親愛，南瞻雜夷蠻。置之勿複道，且寄須臾閑。"]'),
('yuding-34','夏夜苦熱登西樓','柳宗元','唐','御定全唐诗','yuding','','[]','苦熱中夜起，登樓獨褰衣。山澤凝暑氣，星漢湛光輝。',84,'御定全唐詩/json/352.json','["苦熱中夜起，登樓獨褰衣。山澤凝暑氣，星漢湛光輝。", "火晶燥露滋，野靜停風威。探湯汲陰井，煬灶開重扉。", "憑闌久彷徨，流汗不可揮。莫辯亭毒意，仰訴璿與璣。", "諒非姑射子，靜勝安能希。"]'),
('yuding-35','覺衰','柳宗元','唐','御定全唐诗','yuding','','[]','久知老會至，不謂便見侵。今年宜未衰，稍已來相尋。',132,'御定全唐詩/json/352.json','["久知老會至，不謂便見侵。今年宜未衰，稍已來相尋。", "齒疏發就種，奔走力不任。咄此可奈何，未必傷我心。", "彭聃安在哉，周孔亦已沉。古稱壽聖人，曾不留至今。", "但願得美酒，朋友常共酙。是時春向暮，桃李生繁陰。", "日照天正綠，杳杳歸鴻吟。出門呼所親，扶杖登西林。", "高歌足自快，商頌有遺音。"]'),
('yuding-36','游南亭夜還敘志七十韻','柳宗元','唐','御定全唐诗','yuding','','[]','夙抱丘壑尚，率性恣遊遨。中為吏役牽，十祀空悁勞。',577,'御定全唐詩/json/352.json','["夙抱丘壑尚，率性恣遊遨。中為吏役牽，十祀空悁勞。", "外曲徇塵轍，私心寄英髦。進乏廓廟器，退非鄉曲豪。", "天命斯不易，鬼責將安逃。屯難果見淩，剝喪宜所遭。", "神明固浩浩，眾口徒嗷嗷。投跡山水地，放情詠離騷。", "再懷曩歲期，容與馳輕舠。虛館背山郭，前軒面江皋。", "重疊間浦漵，邐迤驅岩嶅。積翠浮澹灩，始疑負靈鼇。", "叢林留沖飆，石礫迎飛濤。曠朗天景霽，樵蘇遠相號。", "澄潭湧沉鷗，半壁跳懸猱。鹿鳴驗食野，魚樂知觀濠。", "孤賞誠所悼，暫欣良足褒。留連俯欞檻，注我壺中醪。", "朵頤進芰實，擢手持蟹螯。炊稻視爨鼎，膾鮮聞操刀。", "野蔬盈傾筐，頗雜池沼芼。緬慕鼓枻翁，嘯詠哺其糟。", "退想於陵子，三咽資李螬。斯道難為偕，沉憂安所韜。", "曲渚怨鴻鵠，環洲凋蘭mL。暮景回西岑，北流逝滔滔。", "徘徊遂昏黑，遠火明連艘。木落寒山靜，江空秋月高。", "斂袂戒還徒，善遊矜所操。趣淺戢長枻，乘深屏輕篙。", "曠望援深竿，哀歌叩鳴艚。中川恣超忽，漫若翔且翱。", "淹泊遂所止，野風自颾颾。澗急驚鱗奔，蹊荒饑獸嗥。", "入門守拘縶，淒戚增郁陶。慕士情未忘，懷人首徒搔。", "內顧乃無有，德輶甚鴻毛。名竊久自欺，食浮固雲叨。", "問牛悲釁鐘，說彘驚臨牢。永遁刀筆吏，寧期簿書曹。", "中興遂群物，裂壤分鞬櫜。岷凶既雲捕，吳虜亦已鏖。", "捍禦盛方虎，謨明富伊咎。披山窮木禾，駕海逾蟠桃。", "重來越裳雉，再返西旅獒。左右抗槐棘，縱橫羅雁羔。", "三辟咸肆宥，眾生均覆燾。安得奉皇靈，在宥解天弢。"]'),
('yuding-37','韋道安','柳宗元','唐','御定全唐诗','yuding','','[]','道安本儒士，頗擅弓劍名。二十游太行，暮聞號哭聲。',384,'御定全唐詩/json/352.json','["道安本儒士，頗擅弓劍名。二十游太行，暮聞號哭聲。", "疾驅前致問，有叟垂華纓。言我故刺史，失職還西京。", "偶為群盜得，毫縷無餘贏。貨財足非吝，二女皆娉婷。", "蒼黃見驅逐，誰識死與生。便當此殞命，休複事晨征。", "一聞激高義，眥裂肝膽橫。掛弓問所往，趫捷超崢嶸。", "見盜寒澗陰，羅列方忿爭。一矢斃酋帥，餘黨號且驚。", "麾令遞束縛，纆索相拄撐。彼姝久褫魄，刃下俟誅刑。", "卻立不親授，諭以從父行。捃收自擔肩，轉道趨前程。", "夜發敲石火，山林如晝明。父子更抱持，涕血紛交零。", "頓首願歸貨，納女稱舅甥。道安奮衣去，義重利固輕。", "師婚古所病，合姓非用兵。朅來事儒術，十載所能逞。", "慷慨張徐州，朱邸揚前旌。投軀獲所願，前馬出王城。", "轅門立奇士，淮水秋風生。君侯既即世，麾下相欹傾。", "立孤抗王命，鐘鼓四野鳴。橫潰非所壅，逆節非所嬰。", "舉頭自引刃，顧義誰顧形。烈士不忘死，所死在忠貞。", "咄嗟徇權子，翕習猶趨榮。我歌非悼死，所悼時世情。"]'),
('yuding-38','哭連州淩員外司馬','柳宗元','唐','御定全唐诗','yuding','','[]','廢逐人所棄，遂為鬼神欺。才難不其然，卒與大患期。',348,'御定全唐詩/json/352.json','["廢逐人所棄，遂為鬼神欺。才難不其然，卒與大患期。", "淩人古受氏，吳世誇雄姿。寂寞富春水，英氣方在斯。", "六學誠一貫，精義窮發揮。著書逾十年，幽頤靡不推。", "天庭掞高文，萬字若波馳。記室征西府，宏謀耀其奇。", "輶軒下東越，列郡蘇疲羸。宛宛淩江羽，來棲翰林枝。", "孝文留弓劍，中外方危疑。抗聲促遺詔，定命由陳辭。", "徒隸肅曹官，征賦參有司。出守烏江滸，老遷湟水湄。", "高堂傾故國，葬祭限囚羈。仲叔繼幽淪，狂叫唯童兒。", "一門既無主，焉用徒生為。舉聲但呼天，孰知神者誰。", "泣盡目無見，腎傷足不持。溘死委炎荒，臧獲守靈帷。", "平生負國譴，骸骨非敢私。蓋棺未塞責，孤旐凝寒颸。", "念昔始相遇，腑腸為君知。進身齊選擇，失路同瑕疵。", "本期濟仁義，今為眾所嗤。滅名竟不試，世義安可支。", "恬死百憂盡，苟生萬慮滋。顧餘九逝魂，與子各何之。", "我歌誠自慟，非獨為君悲。"]'),
('yuding-39','旦攜謝山人至愚池','柳宗元','唐','御定全唐诗','yuding','','[]','新沐換輕幘，曉池風露清。自諧塵外意，況與幽人行。',48,'御定全唐詩/json/352.json','["新沐換輕幘，曉池風露清。自諧塵外意，況與幽人行。", "霞散眾山迥，天高數雁鳴。機心付當路，聊適羲皇情。"]'),
('yuding-40','獨覺','柳宗元','唐','御定全唐诗','yuding','','[]','覺來窗牖空，寥落雨聲曉。良遊怨遲暮，末事驚紛擾。',36,'御定全唐詩/json/352.json','["覺來窗牖空，寥落雨聲曉。良遊怨遲暮，末事驚紛擾。", "為問經世心，古人難盡了。"]'),
('yuding-41','首春逢耕者','柳宗元','唐','御定全唐诗','yuding','','[]','南楚春候早，餘寒已滋榮。土膏釋原野，百蟄競所營。',108,'御定全唐詩/json/352.json','["南楚春候早，餘寒已滋榮。土膏釋原野，百蟄競所營。", "綴景未及郊，穡人先耦耕。園林幽鳥囀，渚澤新泉清。", "農事誠素務，羈囚阻平生。故池想蕪沒，遺畝當榛荊。", "慕隱既有系，圖功遂無成。聊從田父言，款曲陳此情。", "眷然撫耒耜，回首煙雲橫。"]'),
('yuding-42','溪居','柳宗元','唐','御定全唐诗','yuding','','[]','久為簪組累，幸此南夷謫。閑依農圃鄰，偶似山林客。',48,'御定全唐詩/json/352.json','["久為簪組累，幸此南夷謫。閑依農圃鄰，偶似山林客。", "曉耕翻露草，夜榜響溪石。來往不逢人，長歌楚天碧。"]'),
('yuding-43','夏初雨後尋愚溪','柳宗元','唐','御定全唐诗','yuding','','[]','悠悠雨初霽，獨繞清溪曲。引杖試荒泉，解帶圍新竹。',48,'御定全唐詩/json/352.json','["悠悠雨初霽，獨繞清溪曲。引杖試荒泉，解帶圍新竹。", "沉吟亦何事，寂寞固所欲。幸此息營營，嘯歌靜炎燠。"]'),
('yuding-44','入黃溪聞猿','柳宗元','唐','御定全唐诗','yuding','','[]','溪路千里曲，哀猿何處鳴。孤臣淚已盡，虛作斷腸聲。',24,'御定全唐詩/json/352.json','["溪路千里曲，哀猿何處鳴。孤臣淚已盡，虛作斷腸聲。"]'),
('yuding-45','韋使君黃溪祈雨見召從行至祠下口號','柳宗元','唐','御定全唐诗','yuding','','[]','驕陽愆歲事，良牧念菑畬。列騎低殘月，鳴笳度碧虛。',96,'御定全唐詩/json/352.json','["驕陽愆歲事，良牧念菑畬。列騎低殘月，鳴笳度碧虛。", "稍窮樵客路，遙駐野人居。谷口寒流淨，叢祠古木疏。", "焚香秋霧濕，奠玉曉光初。肸蚃巫言報，精誠禮物餘。", "惠風仍偃草，靈雨會隨車。俟罪非真吏，翻慚奉簡書。"]'),
('yuding-46','郊居歲暮','柳宗元','唐','御定全唐诗','yuding','','[]','屏居負山郭，歲暮驚離索。野迥樵唱來，庭空燒燼落。',48,'御定全唐詩/json/352.json','["屏居負山郭，歲暮驚離索。野迥樵唱來，庭空燒燼落。", "世紛因事遠，心賞隨年薄。默默諒何為，徒成今與昨。"]'),
('yuding-47','秋曉行南穀經荒村','柳宗元','唐','御定全唐诗','yuding','','[]','杪秋霜露重，晨起行幽谷。黃葉覆溪橋，荒村唯古木。',48,'御定全唐詩/json/352.json','["杪秋霜露重，晨起行幽谷。黃葉覆溪橋，荒村唯古木。", "寒花疏寂曆，幽泉微斷續。機心久已忘，何事驚麋鹿。"]'),
('yuding-48','雨後曉行獨至愚溪北池','柳宗元','唐','御定全唐诗','yuding','','[]','宿雲散洲渚，曉日明村塢。高樹臨清池，風驚夜來雨。',36,'御定全唐詩/json/352.json','["宿雲散洲渚，曉日明村塢。高樹臨清池，風驚夜來雨。", "予心適無事，偶此成賓主。"]'),
('yuding-49','中夜起望西園值月上','柳宗元','唐','御定全唐诗','yuding','','[]','覺聞繁露墜，開戶臨西園。寒月上東嶺，泠泠疏竹根。',48,'御定全唐詩/json/352.json','["覺聞繁露墜，開戶臨西園。寒月上東嶺，泠泠疏竹根。", "石泉遠逾響，山鳥時一喧。倚楹遂至旦，寂寞將何言。"]'),
('yuding-50','零陵春望','柳宗元','唐','御定全唐诗','yuding','','[]','平野春草綠，曉鶯啼遠林。日晴瀟湘渚，雲斷岣嶁岑。',48,'御定全唐詩/json/352.json','["平野春草綠，曉鶯啼遠林。日晴瀟湘渚，雲斷岣嶁岑。", "仙駕不可望，世途非所任。凝情空景慕，萬里蒼梧陰。"]'),
('yuding-51','從崔中丞過盧少尹郊居','柳宗元','唐','御定全唐诗','yuding','','[]','寓居湘岸四無鄰，世網難嬰每自珍。蒔藥閒庭延國老，',40,'御定全唐詩/json/352.json','["寓居湘岸四無鄰，世網難嬰每自珍。蒔藥閒庭延國老，", "聞道偏為五禽戲，出門鷗鳥更相親。"]'),
('yuding-52','夏晝偶作','柳宗元','唐','御定全唐诗','yuding','','[]','南州溽暑醉如酒，隱幾熟眠開北牖。',32,'御定全唐詩/json/352.json','["南州溽暑醉如酒，隱幾熟眠開北牖。", "日午獨覺無餘聲，山童隔竹敲茶臼。"]'),
('yuding-53','雨晴至江渡','柳宗元','唐','御定全唐诗','yuding','','[]','江雨初晴思遠步，日西獨向愚溪渡。',32,'御定全唐詩/json/352.json','["江雨初晴思遠步，日西獨向愚溪渡。", "渡頭水落村徑成，撩亂浮槎在高樹。"]'),
('yuding-54','江雪','柳宗元','唐','御定全唐诗','yuding','','[]','千山鳥飛絕，萬徑人蹤滅。孤舟蓑笠翁，獨釣寒江雪。',24,'御定全唐詩/json/352.json','["千山鳥飛絕，萬徑人蹤滅。孤舟蓑笠翁，獨釣寒江雪。"]'),
('yuding-55','冉溪','柳宗元','唐','御定全唐诗','yuding','','[]','少時陳力希公侯，許國不復為身謀。風波一跌逝萬里，',40,'御定全唐詩/json/352.json','["少時陳力希公侯，許國不復為身謀。風波一跌逝萬里，", "卻學壽張樊敬侯，種漆南園待成器。"]'),
('yuding-56','法華寺西亭夜飲','柳宗元','唐','御定全唐诗','yuding','','[]','祇樹夕陽亭，共傾三昧酒。霧暗水連階，月明花覆牖。',36,'御定全唐詩/json/352.json','["祇樹夕陽亭，共傾三昧酒。霧暗水連階，月明花覆牖。", "莫厭尊前醉，相看未白首。"]'),
('yuding-57','戲題石門長老東軒','柳宗元','唐','御定全唐诗','yuding','','[]','石門長老身如夢，旃檀成林手所種。坐來念念非昔人，',40,'御定全唐詩/json/352.json','["石門長老身如夢，旃檀成林手所種。坐來念念非昔人，", "莫向東軒春野望，花開日出雉皆飛。"]'),
('yuding-0','茅簷下始栽竹','柳宗元','唐','御定全唐诗','yuding','','[]','瘴茅葺為宇，溽暑常侵肌。適有重膇疾，蒸郁寧所宜。',180,'御定全唐詩/json/353.json','["瘴茅葺為宇，溽暑常侵肌。適有重膇疾，蒸郁寧所宜。", "東鄰幸導我，樹竹邀涼颸。欣然愜吾志，荷鍤西岩垂。", "楚壤多怪石，墾鑿力已疲。江風忽雲暮，輿曳還相追。", "蕭瑟過極浦，旖旎附幽墀。貞根期永固，貽爾寒泉滋。", "夜窗遂不掩，羽扇寧複持。清泠集濃露，枕簟淒已知。", "網蟲依密葉，曉禽棲迥枝。豈伊紛囂間，重以心慮怡。", "嘉爾亭亭質，自遠棄幽期。不見野蔓草，蓊蔚有華姿。", "諒無淩寒色，豈與青山辭。"]'),
('yuding-1','《種仙靈毗','柳宗元','唐','御定全唐诗','yuding','','[]','窮陋闕自養，癘氣劇囂煩。隆冬乏霜霰，日夕南風溫。',204,'御定全唐詩/json/353.json','["窮陋闕自養，癘氣劇囂煩。隆冬乏霜霰，日夕南風溫。", "杖藜下庭際，曳踵不及門。門有野田吏，慰我飄零魂。", "及言有靈藥，近在湘西原。服之不盈旬，蹩躠皆騰鶱。", "笑忭前即吏，為我擢其根。蔚蔚遂充庭，英翹忽已繁。", "晨起自采曝，杵臼通夜喧。靈和理內藏，攻疾貴自源。", "擁覆逃積霧，伸舒委餘暄。奇功苟可征，甯複資蘭蓀。", "我聞畸人術，一氣中夜存。能令深深息，呼吸還歸跟。", "疏放固難效，且以藥餌論。痿者不忘起，窮者寧複言。", "神哉輔吾足，幸及兒女奔。"]'),
('yuding-2','種朮','柳宗元','唐','御定全唐诗','yuding','','[]','守閒事服餌，采朮東山阿。東山幽且阻，疲苶煩經過。',144,'御定全唐詩/json/353.json','["守閒事服餌，采朮東山阿。東山幽且阻，疲苶煩經過。", "戒徒劚靈根，封植閟天和。違爾澗底石，徹我庭中莎。", "土膏滋玄液，松露墜繁柯。南東自成畝，繚繞紛相羅。", "晨步佳色媚，夜眠幽氣多。離憂苟可怡，孰能知其他。", "爨竹茹芳葉，寧慮瘵與瘥。留連樹蕙辭，婉娩采薇歌。", "悟拙甘自足，激清愧同波。單豹且理內，高門複如何。"]'),
('yuding-3','種白蘘荷','柳宗元','唐','御定全唐诗','yuding','','[]','血蟲化為癘，夷俗多所神。銜猜每臘毒，謀富不為仁。',132,'御定全唐詩/json/353.json','["血蟲化為癘，夷俗多所神。銜猜每臘毒，謀富不為仁。", "蔬果自遠至，杯酒盈肆陳。言甘中必苦，何用知其真。", "華潔事外飾，尤病中州人。錢刀恐賈害，饑至益逡巡。", "竄伏常戰慄，懷故逾悲辛。庶氏有嘉草，攻禬事久泯。", "炎帝垂靈編，言此殊足珍。崎嶇乃有得，托以全餘身。", "紛敷碧樹陰，眄睞心所親。"]'),
('yuding-4','新植海石榴','柳宗元','唐','御定全唐诗','yuding','','[]','弱植不盈尺，遠意駐蓬瀛。月寒空階曙，幽夢彩雲生。',48,'御定全唐詩/json/353.json','["弱植不盈尺，遠意駐蓬瀛。月寒空階曙，幽夢彩雲生。", "糞壤擢珠樹，莓苔插瓊英。芳根閟顏色，徂歲為誰榮。"]'),
('yuding-5','戲題階前芍藥','柳宗元','唐','御定全唐诗','yuding','','[]','凡卉與時謝，妍華麗茲晨。欹紅醉濃露，窈窕留餘春。',60,'御定全唐詩/json/353.json','["凡卉與時謝，妍華麗茲晨。欹紅醉濃露，窈窕留餘春。", "孤賞白日暮，暄風動搖頻。夜窗藹芳氣，幽臥知相親。", "願致溱洧贈，悠悠南國人。"]'),
('yuding-6','始見白髮題所植海石榴','柳宗元','唐','御定全唐诗','yuding','','[]','幾年封植愛芳叢，韻豔朱顏竟不同。',32,'御定全唐詩/json/353.json','["幾年封植愛芳叢，韻豔朱顏竟不同。", "從此休論上春事，看成古木對衰翁。"]'),
('yuding-7','植靈壽木','柳宗元','唐','御定全唐诗','yuding','','[]','白華照寒水，怡我適野情。前趨問長老，重複欣嘉名。',96,'御定全唐詩/json/353.json','["白華照寒水，怡我適野情。前趨問長老，重複欣嘉名。", "蹇連易衰朽，方剛謝經營。敢期齒杖賜，聊且移孤莖。", "叢萼中競秀，分房外舒英。柔條乍反植，勁節常對生。", "循玩足忘疲，稍覺步武輕。安能事翦伐，持用資徒行。"]'),
('yuding-8','自衡陽移桂十餘本植零陵所住精舍','柳宗元','唐','御定全唐诗','yuding','','[]','謫官去南裔，清湘繞靈嶽。晨登蒹葭岸，霜景霽紛濁。',108,'御定全唐詩/json/353.json','["謫官去南裔，清湘繞靈嶽。晨登蒹葭岸，霜景霽紛濁。", "離披得幽桂，芳本欣盈握。火耕困煙燼，薪采久摧剝。", "道旁且不願，岑嶺況悠邈。傾筐壅故壤，棲息期鸞鷟。", "路遠清涼宮，一雨悟無學。南人始珍重，微我誰先覺。", "芳意不可傳，丹心徒自渥。"]'),
('yuding-9','湘岸移木芙蓉植龍興精舍','柳宗元','唐','御定全唐诗','yuding','','[]','有美不自蔽，安能守孤根。盈盈湘西岸，秋至風露繁。',48,'御定全唐詩/json/353.json','["有美不自蔽，安能守孤根。盈盈湘西岸，秋至風露繁。", "麗影別寒水，穠芳委前軒。芰荷諒難雜，反此生高原。"]'),
('yuding-10','早梅','柳宗元','唐','御定全唐诗','yuding','','[]','早梅發高樹，迥映楚天碧。朔吹飄夜香，繁霜滋曉白。',48,'御定全唐詩/json/353.json','["早梅發高樹，迥映楚天碧。朔吹飄夜香，繁霜滋曉白。", "欲為萬里贈，杳杳山水隔。寒英坐銷落，何用慰遠客。"]'),
('yuding-11','南中榮橘柚','柳宗元','唐','御定全唐诗','yuding','','[]','橘柚懷貞質，受命此炎方。密林耀朱綠，晚歲有餘芳。',48,'御定全唐詩/json/353.json','["橘柚懷貞質，受命此炎方。密林耀朱綠，晚歲有餘芳。", "殊風限清漢，飛雪滯故鄉。攀條何所歎，北望熊與湘。"]'),
('yuding-12','紅蕉','柳宗元','唐','御定全唐诗','yuding','','[]','晚英值窮節，綠潤含朱光。以茲正陽色，窈窕淩清霜。',48,'御定全唐詩/json/353.json','["晚英值窮節，綠潤含朱光。以茲正陽色，窈窕淩清霜。", "遠物世所重，旅人心獨傷。回暉眺林際，摵摵無遺芳。"]'),
('yuding-13','巽公院五詠：淨土堂','柳宗元','唐','御定全唐诗','yuding','','[]','結習自無始，淪溺窮苦源。流形及茲世，始悟三空門。',60,'御定全唐詩/json/353.json','["結習自無始，淪溺窮苦源。流形及茲世，始悟三空門。", "華堂開淨域，圖像煥且繁。清泠焚眾香，微妙歌法言。", "稽首愧導師，超遙謝塵昏。"]'),
('yuding-14','巽公院五詠：曲講堂','柳宗元','唐','御定全唐诗','yuding','','[]','寂滅本非斷，文字安可離。曲堂何為設，高士方在斯。',60,'御定全唐詩/json/353.json','["寂滅本非斷，文字安可離。曲堂何為設，高士方在斯。", "聖默寄言宣，分別乃無知。趣中即空假，名相與誰期。", "願言絕聞得，忘意聊思惟。"]'),
('yuding-15','巽公院五詠：禪堂','柳宗元','唐','御定全唐诗','yuding','','[]','發地結菁茅，團團抱虛白。山花落幽戶，中有忘機客。',60,'御定全唐詩/json/353.json','["發地結菁茅，團團抱虛白。山花落幽戶，中有忘機客。", "涉有本非取，照空不待析。萬籟俱緣生，窅然喧中寂。", "心境本洞如，鳥飛無遺跡。"]'),
('yuding-16','巽公院五詠：芙蓉亭','柳宗元','唐','御定全唐诗','yuding','','[]','新亭俯朱檻，嘉木開芙蓉。清香晨風遠，溽彩寒露濃。',60,'御定全唐詩/json/353.json','["新亭俯朱檻，嘉木開芙蓉。清香晨風遠，溽彩寒露濃。", "瀟灑出人世，低昂多異容。嘗聞色空喻，造物誰為工。", "留連秋月晏，迢遞來山鐘。"]'),
('yuding-17','巽公院五詠：苦竹橋','柳宗元','唐','御定全唐诗','yuding','','[]','危橋屬幽徑，繚繞穿疏林。迸籜分苦節，輕筠抱虛心。',60,'御定全唐詩/json/353.json','["危橋屬幽徑，繚繞穿疏林。迸籜分苦節，輕筠抱虛心。", "俯瞰涓涓流，仰聆蕭蕭吟。差池下煙日，嘲哳鳴山禽。", "諒無要津用，棲息有餘陰。"]'),
('yuding-18','梅雨','柳宗元','唐','御定全唐诗','yuding','','[]','梅實迎時雨，蒼茫值晚春。愁深楚猿夜，夢斷越雞晨。',48,'御定全唐詩/json/353.json','["梅實迎時雨，蒼茫值晚春。愁深楚猿夜，夢斷越雞晨。", "海霧連南極，江雲暗北津。素衣今盡化，非為帝京塵。"]'),
('yuding-19','零陵早春','柳宗元','唐','御定全唐诗','yuding','','[]','問春從此去，幾日到秦原。憑寄還鄉夢，殷勤入故園。',24,'御定全唐詩/json/353.json','["問春從此去，幾日到秦原。憑寄還鄉夢，殷勤入故園。"]'),
('yuding-20','田家三首','柳宗元','唐','御定全唐诗','yuding','','[]','蓐食徇所務，驅牛向東阡。雞鳴村巷白，夜色歸暮田。',264,'御定全唐詩/json/353.json','["蓐食徇所務，驅牛向東阡。雞鳴村巷白，夜色歸暮田。", "劄劄耒耜聲，飛飛來烏鳶。竭茲筋力事，持用窮歲年。", "盡輸助徭役，聊就空自眠。子孫日已長，世世還複然。", "籬落隔煙火，農談四鄰夕。庭際秋蟲鳴，疏麻方寂曆。", "蠶絲盡輸稅，機杼空倚壁。裏胥夜經過，雞黍事筵席。", "各言官長峻，文字多督責。東鄉後租期，車轂陷泥澤。", "公門少推恕，鞭樸恣狼藉。努力慎經營，肌膚真可惜。", "迎新在此歲，唯恐踵前跡。", "古道饒蒺藜，縈回古城曲。蓼花被堤岸，陂水寒更綠。", "是時收穫竟，落日多樵牧。風高榆柳疏，霜重梨棗熟。", "行人迷去住，野鳥競棲宿。田翁笑相念，昏黑慎原陸。", "今年幸少豐，無厭饘與粥。"]'),
('yuding-21','行路難三首','柳宗元','唐','御定全唐诗','yuding','','[]','君不見夸父追日窺虞淵，跳踉北海超昆侖。',222,'御定全唐詩/json/353.json','["君不見夸父追日窺虞淵，跳踉北海超昆侖。", "披霄決漢出沆漭，瞥裂左右遺星辰。須臾力盡道渴死。", "狐鼠蜂蟻爭噬吞。北方竫人長九寸，開口抵掌更笑喧。", "啾啾飲食滴與粒，生死亦足終天年。睢盱大志小成遂，", "虞衡斤斧羅千山，工命采斫杙與椽。深林土剪十取一，", "遺餘毫末不見保，躪躒澗壑何當存。群材未成質已夭，", "君不見南山棟樑益稀少，愛材養育誰複論。", "飛雪斷道冰成梁，侯家熾炭雕玉房。蟠龍吐耀虎喙張，", "美人四向回明璫，雪山冰穀晞太陽。星躔奔走不得止，", "盛時一去貴反賤，桃笙葵扇安可當。"]'),
('yuding-22','聞籍田有感','柳宗元','唐','御定全唐诗','yuding','','[]','天田不日降皇輿，留滯長沙歲又除。',32,'御定全唐詩/json/353.json','["天田不日降皇輿，留滯長沙歲又除。", "宣室無由問厘事，周南何處托成書。"]'),
('yuding-23','跂烏詞','柳宗元','唐','御定全唐诗','yuding','','[]','城上日出群烏飛，鴉鴉爭赴朝陽枝。刷毛伸翼和且樂，',72,'御定全唐詩/json/353.json','["城上日出群烏飛，鴉鴉爭赴朝陽枝。刷毛伸翼和且樂，", "無乃饑啼走道旁，貪鮮攫肉人所傷。翹肖獨足下叢薄，", "左右六翮利如刀，踴身失勢不得高。支離無趾猶自免，"]'),
('yuding-24','籠鷹詞','柳宗元','唐','御定全唐诗','yuding','','[]','淒風淅瀝飛嚴霜，蒼鷹上擊翻曙光。雲披霧裂虹蜺斷，',64,'御定全唐詩/json/353.json','["淒風淅瀝飛嚴霜，蒼鷹上擊翻曙光。雲披霧裂虹蜺斷，", "爪毛吻血百鳥逝，獨立四顧時激昂。炎風溽暑忽然至，", "但願清商複為假，拔去萬累雲間翔。"]'),
('yuding-25','放鷓鴣詞','柳宗元','唐','御定全唐诗','yuding','','[]','楚越有鳥甘且腴，嘲嘲自名為鷓鴣。徇媒得食不復慮，',64,'御定全唐詩/json/353.json','["楚越有鳥甘且腴，嘲嘲自名為鷓鴣。徇媒得食不復慮，", "鼎前芍藥調五味，膳夫攘腕左右視。齊王不忍觳觫牛，", "破籠展翅當遠去，同類相呼莫相顧。"]'),
('yuding-26','龜背戲','柳宗元','唐','御定全唐诗','yuding','','[]','長安新技出宮掖，喧喧初遍王侯宅。玉盤滴瀝黃金錢，',88,'御定全唐詩/json/353.json','["長安新技出宮掖，喧喧初遍王侯宅。玉盤滴瀝黃金錢，", "投變轉動玄機卑，星流霞破相參差。四分五裂勢未已，", "徒言萬事有盈虛，終朝一擲知勝負。修門象棋不復貴，", "廟堂巾笥非余慕，錢刀兒女徒紛紛。"]'),
('yuding-27','聞黃鸝','柳宗元','唐','御定全唐诗','yuding','','[]','倦聞子規朝暮聲，不意忽有黃鸝鳴。一聲夢斷楚江曲，',72,'御定全唐詩/json/353.json','["倦聞子規朝暮聲，不意忽有黃鸝鳴。一聲夢斷楚江曲，", "王畿優本少賦役，務閑酒熟饒經過。此時晴煙最深處，", "我今誤落千萬山，身同傖人不思還。鄉禽何事亦來此，"]'),
('yuding-28','渾鴻臚宅聞歌效白紵','柳宗元','唐','御定全唐诗','yuding','','[]','翠帷雙卷出傾城，龍劍破匣霜月明。朱唇掩抑悄無聲，',24,'御定全唐詩/json/353.json','["翠帷雙卷出傾城，龍劍破匣霜月明。朱唇掩抑悄無聲，"]'),
('yuding-29','楊白花','柳宗元','唐','御定全唐诗','yuding','','[]','楊白花，風吹渡江水。坐令宮樹無顏色，',18,'御定全唐詩/json/353.json','["楊白花，風吹渡江水。坐令宮樹無顏色，"]'),
('yuding-30','漁翁','柳宗元','唐','御定全唐诗','yuding','','[]','漁翁夜傍西岩宿，曉汲清湘燃楚竹。煙銷日出不見人，',24,'御定全唐詩/json/353.json','["漁翁夜傍西岩宿，曉汲清湘燃楚竹。煙銷日出不見人，"]'),
('yuding-31','飲酒','柳宗元','唐','御定全唐诗','yuding','','[]','今夕少愉樂，起坐開清尊。舉觴酹先酒，為我驅憂煩。',96,'御定全唐詩/json/353.json','["今夕少愉樂，起坐開清尊。舉觴酹先酒，為我驅憂煩。", "須臾心自殊，頓覺天地暄。連山變幽晦，綠水函晏溫。", "藹藹南郭門，樹木一何繁。清陰可自庇，竟夕聞佳言。", "盡醉無複辭，偃臥有芳蓀。彼哉晉楚富，此道未必存。"]'),
('yuding-32','讀書','柳宗元','唐','御定全唐诗','yuding','','[]','幽沉謝世事，俯默窺唐虞。上下觀古今，起伏千萬途。',168,'御定全唐詩/json/353.json','["幽沉謝世事，俯默窺唐虞。上下觀古今，起伏千萬途。", "遇欣或自笑，感戚亦以籲。縹帙各舒散，前後互相逾。", "瘴痾擾靈府，日與往昔殊。臨文乍了了，徹卷兀若無。", "竟夕誰與言，但與竹素俱。倦極便倒臥，熟寐乃一蘇。", "欠伸展肢體，吟詠心自愉。得意適其適，非願為世儒。", "道盡即閉口，蕭散捐囚拘。巧者為我拙，智者為我愚。", "書史足自悅，安用勤與劬。貴爾六尺軀，勿為名所驅。"]'),
('yuding-33','感遇二首','柳宗元','唐','御定全唐诗','yuding','','[]','西陸動涼氣，驚烏號北林。棲息豈殊性，集枯安可任。',169,'御定全唐詩/json/353.json','["西陸動涼氣，驚烏號北林。棲息豈殊性，集枯安可任。", "鴻鵠去不返，勾吳阻且深。徒嗟日沉湎，丸鼓騖奇音。", "東海久搖盪，南風已駸駸。坐使青天暮，小星愁太陰。", "眾情嗜奸利，居貨捐千金。危根一以振，齊斧來相尋。", "攬衣中夜起，感物涕盈襟。微霜眾所踐，誰念歲寒心。", "旭日照寒野，pL斯起蒿萊。啁啾有餘樂，飛舞西陵隈。", "回風旦夕至，零葉委陳荄。所棲不足恃，鷹隼縱橫來。"]'),
('yuding-34','詠史','柳宗元','唐','御定全唐诗','yuding','','[]','燕有黃金台，遠致望諸君。嗛嗛事強怨，三歲有奇勳。',96,'御定全唐詩/json/353.json','["燕有黃金台，遠致望諸君。嗛嗛事強怨，三歲有奇勳。", "悠哉辟疆理，東海漫浮雲。甯知世情異，嘉穀坐熇焚。", "致令委金石，誰顧蠢蠕群。風波欻潛構，遺恨意紛紜。", "豈不善圖後，交私非所聞。為忠不顧內，晏子亦垂文。"]'),
('yuding-35','詠三良','柳宗元','唐','御定全唐诗','yuding','','[]','束帶值明後，顧盼流輝光。一心在陳力，鼎列誇四方。',108,'御定全唐詩/json/353.json','["束帶值明後，顧盼流輝光。一心在陳力，鼎列誇四方。", "款款效忠信，恩義皎如霜。生時亮同體，死沒甯分張。", "壯軀閉幽隧，猛志填黃腸。殉死禮所非，況乃用其良。", "霸基弊不振，晉楚更張惶。疾病命固亂，魏氏言有章。", "從邪陷厥父，吾欲討彼狂。"]'),
('yuding-36','詠荊軻','柳宗元','唐','御定全唐诗','yuding','','[]','燕秦不兩立，太子已為虞。千金奉短計，匕首荊卿趨。',192,'御定全唐詩/json/353.json','["燕秦不兩立，太子已為虞。千金奉短計，匕首荊卿趨。", "窮年徇所欲，兵勢且見屠。微言激幽憤，怒目辭燕都。", "朔風動易水，揮爵前長驅。函首致宿怨，獻田開版圖。", "炯然耀電光，掌握罔正夫。造端何其銳，臨事竟趑趄。", "長虹吐白日，倉卒反受誅。按劍赫憑怒，風雷助號呼。", "慈父斷子首，狂走無容軀。夷城芟七族，台觀皆焚汙。", "始期憂患弭，卒動災禍樞。秦皇本詐力，事與桓公殊。", "奈何效曹子，實謂勇且愚。世傳故多謬，太史征無且。"]'),
('yuding-37','掩役夫張進骸','柳宗元','唐','御定全唐诗','yuding','','[]','生死悠悠爾，一氣聚散之。偶來紛喜怒，奄忽已複辭。',180,'御定全唐詩/json/353.json','["生死悠悠爾，一氣聚散之。偶來紛喜怒，奄忽已複辭。", "為役孰賤辱，為貴非神奇。一朝纊息定，枯朽無妍媸。", "生平勤皂櫪，剉秣不告疲。既死給槥櫝，葬之東山基。", "奈何值崩湍，蕩析臨路垂。髐然暴百骸，散亂不復支。", "從者幸告餘，眷之涓然悲。貓虎獲迎祭，犬馬有蓋帷。", "佇立唁爾魂，豈複識此為。畚鍤載埋瘞，溝瀆護其危。", "我心得所安，不謂爾有知。掩骼著春令，茲焉適其時。", "及物非吾事，聊且顧爾私。"]'),
('yuding-38','省試觀慶雲圖詩','柳宗元','唐','御定全唐诗','yuding','','[]','設色既成象，卿雲示國都。九天開秘祉，百辟贊嘉謨。',72,'御定全唐詩/json/353.json','["設色既成象，卿雲示國都。九天開秘祉，百辟贊嘉謨。", "抱日依龍袞，非煙近禦爐。高標連汗漫，迥望接虛無。", "裂素榮光發，舒華瑞色敷。恒將配堯德，垂慶代河圖。"]'),
('yuding-39','春懷故園','柳宗元','唐','御定全唐诗','yuding','','[]','九扈鳴已晚，楚鄉農事春。悠悠故池水，空待灌園人。',24,'御定全唐詩/json/353.json','["九扈鳴已晚，楚鄉農事春。悠悠故池水，空待灌園人。"]'),
('yuding-0','團扇歌','劉禹錫','唐','御定全唐诗','yuding','','[]','團扇複團扇，奉君清暑殿。秋風入庭樹，從此不相見。',48,'御定全唐詩/json/354.json','["團扇複團扇，奉君清暑殿。秋風入庭樹，從此不相見。", "上有乘鸞女，蒼蒼蟲網遍。明年入懷袖，別是機中練。"]'),
('yuding-1','宜城歌','劉禹錫','唐','御定全唐诗','yuding','','[]','野水繞空城，行塵起孤驛。荒台側生樹，石碣陽鐫額。',36,'御定全唐詩/json/354.json','["野水繞空城，行塵起孤驛。荒台側生樹，石碣陽鐫額。", "靡靡度行人，溫風吹宿麥。"]'),
('yuding-2','順陽歌','劉禹錫','唐','御定全唐诗','yuding','','[]','朝辭官軍驛，前望順陽路。野水齧荒墳，秋蟲鏤宮樹。',48,'御定全唐詩/json/354.json','["朝辭官軍驛，前望順陽路。野水齧荒墳，秋蟲鏤宮樹。", "曾聞天寶末，胡馬西南騖。城守魯將軍，拔城從此去。"]'),
('yuding-3','莫瑤歌','劉禹錫','唐','御定全唐诗','yuding','','[]','莫瑤自生長，名字無符籍。市易雜鮫人，婚姻通木客。',48,'御定全唐詩/json/354.json','["莫瑤自生長，名字無符籍。市易雜鮫人，婚姻通木客。", "星居占泉眼，火種開山脊。夜渡千仞溪，含沙不能射。"]'),
('yuding-4','度桂嶺歌','劉禹錫','唐','御定全唐诗','yuding','','[]','桂陽嶺，下下複高高。人稀鳥獸駭，地遠草木豪。',34,'御定全唐詩/json/354.json','["桂陽嶺，下下複高高。人稀鳥獸駭，地遠草木豪。", "寄言遷金子，知余歌者勞。"]'),
('yuding-5','插田歌','劉禹錫','唐','御定全唐诗','yuding','','[]','岡頭花草齊，燕子東西飛。田塍望如線，白水光參差。',192,'御定全唐詩/json/354.json','["岡頭花草齊，燕子東西飛。田塍望如線，白水光參差。", "農婦白紵裙，農父綠蓑衣。齊唱郢中歌，嚶佇如竹枝。", "但聞怨響音，不辨俚語詞。時時一大笑，此必相嘲嗤。", "水準苗漠漠，煙火生墟落。黃犬往復還，赤雞鳴且啄。", "路旁誰家郎，烏帽衫袖長。自言上計吏，年幼離帝鄉。", "田夫語計吏，君家儂定諳。一來長安道，眼大不相參。", "計吏笑致辭，長安真大處。省門高軻峨，儂入無度數。", "昨來補衛士，唯用筒竹布。君看二三年，我作官人去。"]'),
('yuding-6','葡萄歌','劉禹錫','唐','御定全唐诗','yuding','','[]','野田生葡萄，纏繞一枝高。移來碧墀下，張王日日高。',144,'御定全唐詩/json/354.json','["野田生葡萄，纏繞一枝高。移來碧墀下，張王日日高。", "分岐浩繁縟，修蔓蟠詰曲。揚翹向庭柯，意思如有屬。", "為之立長檠，布濩當軒綠。米液溉其根，理疏看滲漉。", "繁葩組綬結，懸實珠璣蹙。馬乳帶輕霜，龍鱗曜初旭。", "有客汾陰至，臨堂瞪雙目。自言我晉人，種此如種玉。", "釀之成美酒，令人飲不足。為君持一鬥，往取涼州牧。"]'),
('yuding-7','蠻子歌','劉禹錫','唐','御定全唐诗','yuding','','[]','蠻語鉤輈音，蠻衣斑斕布。熏狸掘沙鼠，時節祠盤瓠。',48,'御定全唐詩/json/354.json','["蠻語鉤輈音，蠻衣斑斕布。熏狸掘沙鼠，時節祠盤瓠。", "忽逢乘馬客，恍若驚麏顧。腰斧上高山，意行無舊路。"]'),
('yuding-8','馬嵬行','劉禹錫','唐','御定全唐诗','yuding','','[]','綠野扶風道，黃塵馬嵬驛。路邊楊貴人，墳高三四尺。',192,'御定全唐詩/json/354.json','["綠野扶風道，黃塵馬嵬驛。路邊楊貴人，墳高三四尺。", "乃問裏中兒，皆言幸蜀時。軍家誅戚族，天子舍妖姬。", "群吏伏門屏，貴人牽帝衣。低回轉美目，風日為無暉。", "貴人飲金屑，倏忽舜英暮。平生服杏丹，顏色真如故。", "屬車塵已遠，裏巷來窺覷。共愛宿妝妍，君王畫眉處。", "履綦無複有，履組光未滅。不見岩畔人，空見淩波襪。", "郵童愛蹤跡，私手解鞶結。傳看千萬眼，縷絕香不歇。", "指環照骨明，首飾敵連城。將入咸陽市，猶得賈胡驚。"]'),
('yuding-9','百花行','劉禹錫','唐','御定全唐诗','yuding','','[]','長安百花時，風景宜輕薄。無人不沽酒，何處不聞樂。',120,'御定全唐詩/json/354.json','["長安百花時，風景宜輕薄。無人不沽酒，何處不聞樂。", "春風連夜動，微雨淩曉濯。紅焰出牆頭，雪光映樓角。", "繁紫韻松竹，遠黃繞籬落。臨路不勝愁，輕煙去何托。", "滿庭蕩魂魄，照廡成丹渥。爛熳簇顛狂，飄零勸行樂。", "時節易晼晚，清陰覆池閣。唯有安石榴，當軒慰寂寞。"]'),
('yuding-10','壯士行','劉禹錫','唐','御定全唐诗','yuding','','[]','陰風振寒郊，猛虎正咆哮。徐行出燒地，連吼入黃茅。',96,'御定全唐詩/json/354.json','["陰風振寒郊，猛虎正咆哮。徐行出燒地，連吼入黃茅。", "壯士走馬去，鐙前彎玉弰。叱之使人立，一發如鈹交。", "悍睛忽星墮，飛血濺林梢。彪炳為我席，膻腥充我庖。", "裏中欣害除，賀酒紛呶號。明日長橋上，傾城看斬蛟。"]'),
('yuding-11','苦雨行','劉禹錫','唐','御定全唐诗','yuding','','[]','悠悠飛走情，同樂在陽和。歲中三百日，常恐風雨多。',48,'御定全唐詩/json/354.json','["悠悠飛走情，同樂在陽和。歲中三百日，常恐風雨多。", "天人信遐遠，時節易蹉跎。洞房有明燭，無乃酣且歌。"]'),
('yuding-12','華山歌','劉禹錫','唐','御定全唐诗','yuding','','[]','洪壚作高山，元氣鼓其橐。俄然神功就，峻拔在寥廓。',96,'御定全唐詩/json/354.json','["洪壚作高山，元氣鼓其橐。俄然神功就，峻拔在寥廓。", "靈跡露指爪，殺氣見棱角。凡木不敢生，神仙聿來托。", "天資帝王宅，以我為關鑰。能令下國人，一見換神骨。", "高山固無限，如此方為嶽。丈夫無特達，雖貴猶碌碌。"]'),
('yuding-13','拋球樂詞','劉禹錫','唐','御定全唐诗','yuding','','[]','五彩繡團圓，登君玳瑁筵。最宜紅燭下，偏稱落花前。',72,'御定全唐詩/json/354.json','["五彩繡團圓，登君玳瑁筵。最宜紅燭下，偏稱落花前。", "上客如先起，應須贈一船。春早見花枝，朝朝恨發遲。", "及看花落後，卻憶未開時。幸有拋球樂，一杯君莫辭。"]'),
('yuding-14','華清詞','劉禹錫','唐','御定全唐诗','yuding','','[]','日出驪山東，裴回照溫泉。樓臺影玲瓏，稍稍開白煙。',96,'御定全唐詩/json/354.json','["日出驪山東，裴回照溫泉。樓臺影玲瓏，稍稍開白煙。", "言昔太上皇，常居此祈年。風中聞清樂，往往來列仙。", "翠華入五雲，紫氣歸上玄。哀哀生人淚，泣盡弓劍前。", "聖道本自我，凡情徒顒然。小臣感玄化，一望青冥天。"]'),
('yuding-15','送春曲三首','劉禹錫','唐','御定全唐诗','yuding','','[]','春向晚，春晚思悠哉。風雲日已改，花葉自相催。',102,'御定全唐詩/json/354.json','["春向晚，春晚思悠哉。風雲日已改，花葉自相催。", "漠漠空中去，何時天際來。", "春已暮，冉冉如人老，映葉見殘花，連天是青草。", "可憐桃與李，從此同桑棗。", "春景去，此去何時回。遊人千萬恨，落日上高臺。", "寂寞繁花盡，流鶯歸莫來。"]'),
('yuding-16','初夏曲三首','劉禹錫','唐','御定全唐诗','yuding','','[]','銅壺方促夜，斗柄暫南回。稍嫌單衣重，初憐北戶開。',108,'御定全唐詩/json/354.json','["銅壺方促夜，斗柄暫南回。稍嫌單衣重，初憐北戶開。", "西園花已盡，新月為誰來。", "時節過繁華，陰陰千萬家。巢禽命子戲，園果墜枝斜。", "寂寞孤飛蝶，窺叢覓晚花。", "綠水風初暖，青林露早晞。麥隴雉朝雊，桑野人暮歸。", "百舌悲花盡，平蕪來去飛。"]'),
('yuding-17','擣衣曲','劉禹錫','唐','御定全唐诗','yuding','','[]','爽砧應秋律，繁杵含淒風。一一遠相續，家家音不同。',96,'御定全唐詩/json/354.json','["爽砧應秋律，繁杵含淒風。一一遠相續，家家音不同。", "戶庭凝露清，伴侶明月中。長裾委襞積，輕佩垂璁瓏。", "汗餘衫更馥，鈿移麝半空。報寒驚邊雁，促思聞候蟲。", "天狼正芒角，虎落定相攻。盈篋寄何處，征人如轉蓬。"]'),
('yuding-18','畬田行','劉禹錫','唐','御定全唐诗','yuding','','[]','何處好畬田，團團縵山腹。鑽龜得雨卦，上山燒臥木。',168,'御定全唐詩/json/354.json','["何處好畬田，團團縵山腹。鑽龜得雨卦，上山燒臥木。", "驚麏走且顧，群雉聲咿喔。紅焰遠成霞，輕煤飛入郭。", "風引上高岑，獵獵度青林。青林望靡靡，赤光低複起。", "照潭出老蛟，爆竹驚山鬼。夜色不見山，孤明星漢間。", "如星複如月，俱逐曉風滅。本從敲石光，遂至烘天熱。", "下種暖灰中，乘陽拆牙孽。蒼蒼一雨後，苕穎如雲發。", "巴人拱手吟，耕耨不關心。由來得地勢，徑寸有餘金。"]'),
('yuding-19','鶗鴂吟','劉禹錫','唐','御定全唐诗','yuding','','[]','朝陽有鳴鳳，不聞千萬祀。鶗鴂催眾芳，晨間先入耳。',48,'御定全唐詩/json/354.json','["朝陽有鳴鳳，不聞千萬祀。鶗鴂催眾芳，晨間先入耳。", "秋風白露晞，從是爾啼時。如何上春日，唧唧滿庭飛。"]'),
('yuding-20','觀雲篇','劉禹錫','唐','御定全唐诗','yuding','','[]','興雲感陰氣，疾足如見機。晴來意態行，有若功成歸。',48,'御定全唐詩/json/354.json','["興雲感陰氣，疾足如見機。晴來意態行，有若功成歸。", "蔥蘢含晚景，潔白凝秋暉。夜深度銀漢，漠漠仙人衣。"]'),
('yuding-21','養鷙詞','劉禹錫','唐','御定全唐诗','yuding','','[]','養鷙非玩形，所資擊鮮力。少年昧其理，日日哺不息。',72,'御定全唐詩/json/354.json','["養鷙非玩形，所資擊鮮力。少年昧其理，日日哺不息。", "探雛網黃口，旦暮有餘食。甯知下鞲時，翅重飛不得。", "毰毸止林表，狡兔自南北。飲啄既已盈，安能勞羽翼。"]'),
('yuding-22','別友人後得書因以詩贈','劉禹錫','唐','御定全唐诗','yuding','','[]','前時送君去，揮手青門橋。路轉不相見，猶聞馬蕭蕭。',48,'御定全唐詩/json/354.json','["前時送君去，揮手青門橋。路轉不相見，猶聞馬蕭蕭。", "今得出關書，行程日已遙。春還遲君至，共結芳蘭苕。"]'),
('yuding-23','送華陰尉張苕赴邕府使幕','劉禹錫','唐','御定全唐诗','yuding','','[]','昔忝南宮郎，往來東觀頻。嘗披燕公傳，聳若窺三辰。',216,'御定全唐詩/json/354.json','["昔忝南宮郎，往來東觀頻。嘗披燕公傳，聳若窺三辰。", "翊聖崇國本，像賢正朝倫。高視緬今古，清風夐無鄰。", "蘭錡照通衢，一家十朱輪。酂國嗣侯絕，韋卿世業貧。", "夫子承大名，少年振芳塵。青袍仙掌下，矯首淩煙旻。", "公冶本非罪，潘郎一為民。風霜苦搖落，堅白無緇磷。", "一旦逢良時，天光燭幽淪。重為長裾客，佐彼觀風臣。", "分野窮禹畫，人煙過虞巡。不言此行遠，所樂相知新。", "雨起巫山陽，鳥鳴湘水濱。離筵出蒼莽，別曲多悲辛。", "今朝一杯酒，明日千里人。從此孤舟去，悠悠天海春。"]'),
('yuding-24','送湘陽熊判官孺登府罷歸鐘陵因寄呈江西裴中丞二十三兄','劉禹錫','唐','御定全唐诗','yuding','','[]','射策志未就，從事歲雲除。篋留馬卿賦，袖有劉弘書。',240,'御定全唐詩/json/354.json','["射策志未就，從事歲雲除。篋留馬卿賦，袖有劉弘書。", "忽見夏木深，悵然憶吾廬。複持州民刺，歸謁專城居。", "君家誠易知，勝絕傾裏閭。人言北郭生，門有卿相輿。", "鐘陵靄千里，帶郭西江水。朱檻照河宮，旗亭綠雲裏。", "前年初缺守，慎簡由宸扆。臨軒弄郡章，得人方付此。", "是時左馮翊，天下第一理。貴臣持牙璋，優詔發青紙。", "迎風奸吏免，先令疲人喜。何武劾腐儒，陳蕃禮高士。", "昔升君子堂，腰下綬猶黃。汾陰有寶氣，赤堇多奇鋩。", "束簡下曲台，佩鞬來歷陽。綺筵陪一笑，蘭室襲餘芳。", "風水忽異勢，江湖遂相忘。因君倘借問，為話老滄浪。"]'),
('yuding-25','送韋秀才道沖赴制舉','劉禹錫','唐','御定全唐诗','yuding','','[]','驚禽一辭巢，棲息無少安。秋扇一離手，流塵蔽霜紈。',264,'御定全唐詩/json/354.json','["驚禽一辭巢，棲息無少安。秋扇一離手，流塵蔽霜紈。", "故侶不可追，涼風日已寒。遠逢杜陵士，別盡平生歡。", "逐客無印綬，楚江多芷蘭。因居暇時遊，長鋏不復彈。", "閱書南軒霽，縆瑟清夜闌。萬境身外寂，一杯腹中寬。", "伊昔玄宗朝，冬卿冠鴛鸞。肅穆升內殿，從容領儒冠。", "游夏無措詞，陽秋垂不刊。至今群玉府，學者空縱觀。", "世人希德門，揭若攀峰巒。之子尚明訓，鏘如振琅玕。", "一旦西上書，斑衣拂征鞍。荊台宿暮雨，漢水浮春瀾。", "君門起天中，多士如星攢。煙霞覆雙闕，抃舞羅千官。", "清漏滴銅壺，仙廚下雕盤。熒煌仰金榜，錯落濡飛翰。", "古來才傑士，所嗟遭時難。一鳴從此始，相望青雲端。"]'),
('yuding-26','送李策秀才還湖南，因寄幕中親故兼簡衡州呂八郎中','劉禹錫','唐','御定全唐诗','yuding','','[]','深春風日淨，晝長幽鳥鳴。僕夫前致詞，門有白麵生。',576,'御定全唐詩/json/354.json','["深春風日淨，晝長幽鳥鳴。僕夫前致詞，門有白麵生。", "攝衣相問訊，解帶坐南榮。端志見眉睫，苦言發精誠。", "因出懷中文，調孤詞亦清。悄如促柱弦，掩抑多不平。", "乃言本蜀士，世降岷山靈。前人秉藝文，高視來上京。", "曳綬司徒府，所從信國楨。析薪委寶林，善響繼家聲。", "何處翳附郭，幾人思郈成。雲天望喬木，風水悲流萍。", "前與計吏西，始列貢士名。森然就筆劄，從試春官卿。", "帝城岐路多，萬足伺晨星。茫茫風塵中，工拙同有營。", "寒女勞夜織，山苗榮寸莖。侯門方擊鐘，衣褐誰將迎。", "弱羽果摧頹，壯心鬱怦怦。諒無蟠木容，聊複蓬累行。", "昨日訊靈龜，繇言利艱貞。當求舍拔中，必在審己明。", "誓將息薄游，焦思窮筆精。蒔蘭在幽渚，安得揚芬馨。", "曰餘摧落者，散質負華纓。一聆苦辛詞，再動伊鬱情。", "身棄言不動，愛才心尚驚。恨無羊角風，使爾化北溟。", "論罷情益親，涉旬忘歸程。日攜邑中客，閑眺江上城。", "晝憩命金罍，宵談轉璿衡。熏風香麈尾，月露濡桃笙。", "忽被戒羸驂，薄言事南征。火雲蔚千里，旅思浩已盈。", "湘江含碧虛，衡嶺浮翠晶。豈伊山水異，適與人事並。", "油幕侶昆丘，粲然疊瑤瓊。庾樓見清月，孔坐多綠醽。", "複有衡山守，本自雲龍庭。抗志在靈府，發越侔咸英。", "一揮出滎陽，惠彼嗤嗤氓。隼旟辭灞水，居者皆涕零。", "惟昔與伊人，交歡經宿齡。一從雲雨散，滋我鄙吝萌。", "北渚不堪愁，南音誰複聽。離憂若去水，浩漾無時停。", "嘗聞祝融峰，上有神禹銘。古石琅玕姿，秘文螭虎形。"]'),
('yuding-27','送張盥赴舉詩','劉禹錫','唐','御定全唐诗','yuding','','[]','爾生始懸弧，我作座上賓。引箸舉湯餅，祝詞天麒麟。',216,'御定全唐詩/json/354.json','["爾生始懸弧，我作座上賓。引箸舉湯餅，祝詞天麒麟。", "今成一丈夫，坎坷愁風塵。長裾來謁我，自號廬山人。", "道舊與撫孤，悄然傷我神。依依見眉睫，嘿嘿含悲辛。", "永懷同年友，追想出穀晨。三十二君子，齊飛淩煙旻。", "曲江一會時，後會已凋淪。況今三十載，閱世難重陳。", "盛時一已過，來者日日新。不如搖落樹，重有明年春。", "火後見琮璜，霜餘識松筠。肅風乃獨秀，武部亦絕倫。", "爾今持我詩，西見二重臣。成賢必念舊，保貴在安貧。", "清時為丞郎，氣力侔陶鈞。乞取鬥升水，因之雲漢津。"]'),
('yuding-28','和州送錢侍禦自宣州幕拜官便於華州覲省','劉禹錫','唐','御定全唐诗','yuding','','[]','五彩繡衣裳，當年正相稱。春風舊關路，歸去真多興。',72,'御定全唐詩/json/354.json','["五彩繡衣裳，當年正相稱。春風舊關路，歸去真多興。", "蘭陔行可采，蓮府猶回瞪。楊家紺幰迎，謝守瑤華贈。", "禦街草泛灩，台柏煙含凝。曾是平生遊，無因理歸乘。"]'),
('yuding-29','送僧方及南謁柳員外','劉禹錫','唐','御定全唐诗','yuding','','[]','昔事廬山遠，精舍虎溪東。朝陽照瀑水，樓閣虹霓中。',216,'御定全唐詩/json/354.json','["昔事廬山遠，精舍虎溪東。朝陽照瀑水，樓閣虹霓中。", "騁望羨遊雲，振衣若秋蓬。舊房閉松月，遠思吟江風。", "古寺曆頭陀，奇峰扳祝融。南登小桂嶺，卻望歸塞鴻。", "衣裓貯文章，自言學雕蟲。搶榆念陵厲，覆簣圖穹崇。", "遠郡多暇日，有詩訪禪宮。石門聳峭絕，竹院含空蒙。", "幽響滴岩溜，晴芳飄野叢。海雲懸颶母，山果屬狙公。", "忽憶吳興郡，白蘋正蔥蘢。願言挹風采，邈若窺華嵩。", "桂水夏瀾急，火山宵焰紅。三衣濡菌露，一錫飛煙空。", "勿謂翻譯徒，不為文雅雄。古來賞音者，燋爨得孤桐。"]'),
('yuding-30','送惟良上人','劉禹錫','唐','御定全唐诗','yuding','','[]','高齋灑寒水，是夕山僧至。玄牝無關鎖，瓊書舍文字。',48,'御定全唐詩/json/354.json','["高齋灑寒水，是夕山僧至。玄牝無關鎖，瓊書舍文字。", "燈明香滿室，月午霜凝地。語到不言時，世間人盡睡。"]'),
('yuding-31','翠微寺有感','劉禹錫','唐','御定全唐诗','yuding','','[]','吾王昔遊幸，離宮雲際開。朱旗迎夏早，涼軒避暑來。',48,'御定全唐詩/json/354.json','["吾王昔遊幸，離宮雲際開。朱旗迎夏早，涼軒避暑來。", "湯餅賜都尉，寒冰頒上才。龍髯不可望，玉座生塵埃。"]'),
('yuding-32','觀柘枝舞二首','劉禹錫','唐','御定全唐诗','yuding','','[]','胡服何葳蕤，仙仙登綺墀。神飆獵紅蕖，龍燭映金枝。',120,'御定全唐詩/json/354.json','["胡服何葳蕤，仙仙登綺墀。神飆獵紅蕖，龍燭映金枝。", "垂帶覆纖腰，安鈿當嫵眉。翹袖中繁鼓，傾眸溯華榱。", "燕秦有舊曲，淮南多冶詞。欲見傾城處，君看赴節時。", "山雞臨清鏡，石燕赴遙津。何如上客會，長袖入華裀。", "體輕似無骨，觀者皆聳神。曲盡回身處，層波猶注人。"]'),
('yuding-33','連州臘日觀莫徭獵西山','劉禹錫','唐','御定全唐诗','yuding','','[]','海天殺氣薄，蠻軍步伍囂。林紅葉盡變，原黑草初燒。',96,'御定全唐詩/json/354.json','["海天殺氣薄，蠻軍步伍囂。林紅葉盡變，原黑草初燒。", "圍合繁鉦息，禽興大旆搖。張羅依道口，嗾犬上山腰。", "猜鷹慮奮迅，驚鹿時局跳。瘴雲四面起，臘雪半空消。", "箭頭餘鵠血，鞍傍見雉翹。日暮還城邑，金笳發麗譙。"]'),
('yuding-34','寄陝州姚中丞','劉禹錫','唐','御定全唐诗','yuding','','[]','八月天氣肅，二陵風雨收。旌旗闕下來，雲日關東秋。',72,'御定全唐詩/json/354.json','["八月天氣肅，二陵風雨收。旌旗闕下來，雲日關東秋。", "禹跡想前事，漢台餘故丘。徘徊襟帶地，左右帝王州。", "留滯悲昔老，恩光榮徹侯。相思望棠樹，一寄商聲謳。"]'),
('yuding-35','奉酬湖州崔郎中見寄五韻','劉禹錫','唐','御定全唐诗','yuding','','[]','山陽昔相遇，灼灼晨葩鮮。同遊翰墨場，和樂塤篪然。',60,'御定全唐詩/json/354.json','["山陽昔相遇，灼灼晨葩鮮。同遊翰墨場，和樂塤篪然。", "一落名宦途，浩如乘風船。行當衰暮日，臥理淮海邊。", "猶期謝病後，共樂桑榆年。"]'),
('yuding-36','學阮公體三首','劉禹錫','唐','御定全唐诗','yuding','','[]','少年負志氣，通道不從時。只言繩自直，安知室可欺。',144,'御定全唐詩/json/354.json','["少年負志氣，通道不從時。只言繩自直，安知室可欺。", "百勝難慮敵，三折乃良醫。人生不失意，焉能慕知己。", "朔風悲老驥，秋霜動鷙禽。出門有遠道，平野多層陰。", "滅沒馳絕塞，振迅拂華林。不因感衰節，安能激壯心。", "昔賢多使氣，憂國不謀身。目覽千載事，心交上古人。", "侯門有仁義，靈台多苦辛。不學腰如磬，徒使甑生塵。"]'),
('yuding-37','秋晚題湖城驛池上亭','劉禹錫','唐','御定全唐诗','yuding','','[]','秋次池上館，林塘照南榮。塵衣紛未解，幽思浩已盈。',48,'御定全唐詩/json/354.json','["秋次池上館，林塘照南榮。塵衣紛未解，幽思浩已盈。", "風蓮墜故萼，露菊含晚英。恨為一夕客，愁聽晨雞鳴。"]'),
('yuding-38','賈客詞','劉禹錫','唐','御定全唐诗','yuding','','[]','賈客無定游，所遊唯利並。眩俗雜良苦，乘時取重輕。',132,'御定全唐詩/json/354.json','["賈客無定游，所遊唯利並。眩俗雜良苦，乘時取重輕。", "心計析秋毫，搖鉤侔懸衡。錐刀既無棄，轉化日已盈。", "邀福禱波神，施財遊化城。妻約雕金釧，女垂貫珠纓。", "高貲比封君，奇貨通幸卿。趨時鷙鳥思，藏鏹盤龍形。", "大艑浮通川，高樓次旗亭。行止皆有樂，關梁自無征。", "農夫何為者，辛苦事寒耕。"]'),
('yuding-39','調瑟詞','劉禹錫','唐','御定全唐诗','yuding','','[]','調瑟在張弦，弦平音自足。朱弦二十五，缺一不成曲。',72,'御定全唐詩/json/354.json','["調瑟在張弦，弦平音自足。朱弦二十五，缺一不成曲。", "美人愛高張，瑤軫再三促。上弦雖獨響，下應不相屬。", "日暮聲未和，寂寥一枯木。卻顧膝上弦，流淚難相續。"]'),
('yuding-40','讀張曲江集作','劉禹錫','唐','御定全唐诗','yuding','','[]','聖言貴忠恕，至道重觀身。法在何所恨，色相斯為仁。',48,'御定全唐詩/json/354.json','["聖言貴忠恕，至道重觀身。法在何所恨，色相斯為仁。", "良時難久恃，陰謫豈無因。寂寞韶陽廟，魂歸不見人。"]'),
('yuding-41','偶作二首','劉禹錫','唐','御定全唐诗','yuding','','[]','終朝對尊酒，嗜興非嗜甘。終日偶眾人，縱言不縱談。',96,'御定全唐詩/json/354.json','["終朝對尊酒，嗜興非嗜甘。終日偶眾人，縱言不縱談。", "世情閒靜見，藥性病多諳。寄謝嵇中散，予無甚不堪。", "萬卷堆床書，學者識其真。萬里長江水，征夫渡要津。", "養生非但藥，悟佛不因人。燕石何須辨，逢時即至珍。"]'),
('yuding-42','昏鏡詞','劉禹錫','唐','御定全唐诗','yuding','','[]','昏鏡非美金，漠然喪其晶。陋容多自欺，謂若他鏡明。',72,'御定全唐詩/json/354.json','["昏鏡非美金，漠然喪其晶。陋容多自欺，謂若他鏡明。", "瑕疵既不見，妍態隨意生。一日四五照，自言美傾城。", "飾帶以紋繡，裝匣以瓊瑛。秦宮豈不重，非適乃為輕。"]'),
('yuding-43','詠古二首有所寄','劉禹錫','唐','御定全唐诗','yuding','','[]','車音想轔轔，不見綦下塵。可憐平陽第，歌舞嬌青春。',96,'御定全唐詩/json/354.json','["車音想轔轔，不見綦下塵。可憐平陽第，歌舞嬌青春。", "金屋容色在，文園詞賦新。一朝複得幸，應知失意人。", "寂寥照鏡臺，遺基古南陽。真人昔來游，翠鳳相隨翔。", "目成在桑野，志遂貯椒房。豈無三千女，初心不可忘。"]'),
('yuding-44','磨鏡篇','劉禹錫','唐','御定全唐诗','yuding','','[]','流塵翳明鏡，歲久看如漆。門前負局人，為我一磨拂。',72,'御定全唐詩/json/354.json','["流塵翳明鏡，歲久看如漆。門前負局人，為我一磨拂。", "萍開綠池滿，暈盡金波溢。白日照空心，圓光走幽室。", "山神妖氣沮，野魅真形出。卻思未磨時，瓦礫來唐突。"]'),
('yuding-0','登司馬錯古城','劉禹錫','唐','御定全唐诗','yuding','','[]','將軍將秦師，西南奠遐服。故壘清江上，蒼煙晦喬木。',96,'御定全唐詩/json/355.json','["將軍將秦師，西南奠遐服。故壘清江上，蒼煙晦喬木。", "登臨直蕭辰，周覽壯前躅。塹平陳葉滿，墉高秋蔓綠。", "廢井抽寒菜，毀台生魯穀。耕人得古器，宿雨多遺鏃。", "楚塞鬱重疊，蠻溪紛詰曲。留此數仞基，幾人傷遠目。"]'),
('yuding-1','謁柱山會禪師','劉禹錫','唐','御定全唐诗','yuding','','[]','我本山東人，平生多感慨。弱冠游咸京，上書金馬外。',192,'御定全唐詩/json/355.json','["我本山東人，平生多感慨。弱冠游咸京，上書金馬外。", "結交當世賢，馳聲溢四塞。勉修貴及早，狃捷不知退。", "錙銖揚芬馨，尋尺招瑕纇。淹留郢南都，摧頹羽翰碎。", "安能咎往事，且欲去沉痗。吾師得真如，寄在人寰內。", "哀我墮名網，有如翾飛輩。曈曈揭智燭，照使出昏昧。", "靜見玄關啟，歆然初心會。夙尚一何微，今得信可大。", "覺路明證入，便門通懺悔。悟理言自忘，處屯道猶泰。", "色身豈吾寶，慧性非形礙。思此靈山期，未卜何年載。"]'),
('yuding-2','臥病聞常山旋師策勳宥過王澤大洽因寄李六侍郎','劉禹錫','唐','御定全唐诗','yuding','','[]','寂寂重寂寂，病夫臥秋齋。夜蛩思幽壁，槁葉鳴空階。',120,'御定全唐詩/json/355.json','["寂寂重寂寂，病夫臥秋齋。夜蛩思幽壁，槁葉鳴空階。", "南國異氣候，火旻尚昏霾。瘴煙跕飛羽，沴氣傷百骸。", "昨聞凱歌旋，飲至酒如淮。無戰陋丹水，垂仁輕槁街。", "清廟既策勳，圓丘俟燔柴。車書一以混，幽遠靡不懷。", "逐客憔悴久，故鄉雲雨乖。禽魚各有化，予欲問齊諧。"]'),
('yuding-3','善卷壇下作','劉禹錫','唐','御定全唐诗','yuding','','[]','先生見堯心，相與去九有。斯民既已治，我得安林藪。',48,'御定全唐詩/json/355.json','["先生見堯心，相與去九有。斯民既已治，我得安林藪。", "道為自然貴，名是無窮壽。瑤壇在此山，識者常回首。"]'),
('yuding-4','武陵觀火詩','劉禹錫','唐','御定全唐诗','yuding','','[]','楚鄉祝融分，炎火常為虞。是時直突煙，發自晨炊徒。',384,'御定全唐詩/json/355.json','["楚鄉祝融分，炎火常為虞。是時直突煙，發自晨炊徒。", "盲風扇其威，白晝曛陽烏。操綆不暇汲，循牆還避逾。", "怒如列缺光，迅與芬輪俱。聯延掩四遠，赫奕成洪爐。", "洶疑雲濤翻，颯若鬼神趨。當前迎焮赩，是物同膏腴。", "金烏入梵天，赤龍游玄都。騰煙透窗戶，飛焰生欒櫨。", "火山摧半空，星雨灑中衢。瑤壇被髹漆，寶樹攢珊瑚。", "光縣與琴焦，旗亭無酒濡。市人委百貨，邑令遺雙鳧。", "餘勢下隈隩，長熛烘舳艫。吹焚照水府，炙浪愁天吳。", "災罷雲日晚，心驚視聽殊。高灰辨廩庾，黑土連闉闍。", "眾燼合星羅，遊氛鑠人膚。厚地藏宿熱，遙林呈驟枯。", "火德資生人，庸可一日無。禦之失其道，敲石彌天隅。", "晉庫走龍劍，吳宮傷燕雛。五行有沴氣，先哲垂籲謨。", "宋鄭同日起，時當賢大夫。無苛自可樂，弭患非所圖。", "賢守恤人瘼，臨煙駐驪駒。吊場色慘忸，顏失詞劬愉。", "下令蠲裏布，指期輕市租。閈垣適未立，苫蓋自相娛。", "山木行剪伐，江泥宜墐途。邑臣不必曾，何用征越巫。"]'),
('yuding-5','崔元受少府自貶所還，遺山薑花，以詩答之','劉禹錫','唐','御定全唐诗','yuding','','[]','故人博羅尉，遺我山薑花。采從碧海上，來自謫仙家。',120,'御定全唐詩/json/355.json','["故人博羅尉，遺我山薑花。采從碧海上，來自謫仙家。", "雲濤潤孤根，陰火照晨葩。靜搖扶桑日，豔對瀛洲霞。", "世人愛芳辛，搴擷忘幽遐。傳名入帝裏，飛驛辭天涯。", "王濟本尚味，石崇方鬥奢。雕盤多不識，綺席乃增華。", "驛馬損筋骨，貴人滋齒牙。顧予藜藿士，持此重咨嗟。"]'),
('yuding-6','途中早發','劉禹錫','唐','御定全唐诗','yuding','','[]','馬踏塵上霜，月明江頭路。行人朝氣銳，宿鳥相辭去。',48,'御定全唐詩/json/355.json','["馬踏塵上霜，月明江頭路。行人朝氣銳，宿鳥相辭去。", "流水隔遠村，縵山多紅樹。悠悠關塞內，往來無閒步。"]'),
('yuding-7','和董庶中古散調詞贈尹果毅','劉禹錫','唐','御定全唐诗','yuding','','[]','昔聽東武吟，壯年心已悲。如何今濩落，聞君辛苦辭。',408,'御定全唐詩/json/355.json','["昔聽東武吟，壯年心已悲。如何今濩落，聞君辛苦辭。", "言有窮巷士，弱齡頗尚奇。讀得玄女符，生當事邊時。", "借名遊俠窟，結客幽並兒。往來長楸間，能帶雙鞬馳。", "崩騰天寶末，塵暗燕南垂。爟火入咸陽，詔征神武師。", "是時占軍幕，插羽揚金羈。萬夫列轅門，觀射中戟支。", "誓當雪國讎，親愛從此辭。中宵倚長劍，起視蚩尤旗。", "介馬晨蕭蕭，陣雲竟天涯。陰風獵白草，旗槊光參差。", "勇氣貫中腸，視身忽如遺。生擒白馬將，虜騎不敢追。", "貴臣上戰功，名姓隨意移。終歲肌骨苦，他人印累累。", "謁者既清宮，諸侯各罷戲。上將賜甲第，門戟不可窺。", "眥血下沾襟，天高問無期。卻尋故鄉路，孤影空相隨。", "行逢裏中舊，撲樕昔所嗤。一言合侯王，腰佩黃金龜。", "問我何自苦，可憐真數奇。遲回顧徒禦，得色懸雙眉。", "翻然悟世途，撫己昧所宜。田園已蕪沒，流浪江海湄。", "鷙禽毛翮摧，不見翔雲姿。衰容蔽逸氣，孑孑無人知。", "寂寞草玄徒，長吟下書帷。為君發哀韻，若扣瑤林枝。", "有客識其真，潺湲涕交頤。飲爾一杯酒，陶然足自怡。"]'),
('yuding-8','望衡山','劉禹錫','唐','御定全唐诗','yuding','','[]','東南倚蓋卑，維嶽資柱石。前當祝融居，上拂朱鳥翮。',48,'御定全唐詩/json/355.json','["東南倚蓋卑，維嶽資柱石。前當祝融居，上拂朱鳥翮。", "青冥結精氣，磅礴宣地脈。還聞膚寸陰，能致彌天澤。"]'),
('yuding-9','遊桃源一百韻','劉禹錫','唐','御定全唐诗','yuding','','[]','沅江清悠悠，連山鬱岑寂。回流抱絕巘，皎鏡含虛碧。',576,'御定全唐詩/json/355.json','["沅江清悠悠，連山鬱岑寂。回流抱絕巘，皎鏡含虛碧。", "昏旦遞明媚，煙嵐分委積。香蔓垂綠潭，暴龍照孤磧。", "淵明著前志，子驥思遠蹠。寂寂無何鄉，密爾天地隔。", "金行太元歲，漁者偶探賾。尋花得幽蹤，窺洞穿暗隙。", "依微聞雞犬，豁達值阡陌。居人互將迎，笑語如平昔。", "廣樂雖交奏，海禽心不懌。揮手一來歸，故溪無處覓。", "綿綿五百載，市朝幾遷革。有路在壺中，無人知地脈。", "皇家感至道，聖祚自天錫。金闕傳本枝，玉函留寶曆。", "禁山開秘宇，複戶潔靈宅。蕊檢香氛氳，醮壇煙冪冪。", "我來塵外躅，瑩若朝星析。崖轉對翠屏，水窮留畫鷁。", "三休俯喬木，千級扳峭壁。旭日聞撞鐘，彩雲迎躡屐。", "遂登最高頂，縱目還楚澤。平湖見草青，遠岸連霞赤。", "幽尋如夢想，綿思屬空闃。夤緣且忘疲，耽玩近成癖。", "清猿伺曉發，瑤草淩寒坼。祥禽舞蔥蘢，珠樹搖玓瓅。", "羽人顧我笑，勸我稅歸軛。霓裳何飄颻，童顏潔白皙。", "重岩是藩屏，馴鹿受羈靮。樓居彌清霄，蘿蔦成翠帟。", "仙翁遺竹杖，王母留桃核。姹女飛丹砂，青童護金液。", "寶氣浮鼎耳，神光生劍脊。虛無天樂來，僁窣鬼兵役。", "丹丘肅朝禮，玉劄工紬繹。枕中淮南方，床下阜鄉舄。", "明燈坐遙夜，幽籟聽淅瀝。因話近世仙，聳然心神惕。", "乃言瞿氏子，骨狀非凡格。往事黃先生，群兒多侮劇。", "謷然不屑意，元氣貯肝膈。往往遊不歸，洞中觀博弈。", "言高未易信，猶複加訶責。一旦前致辭，自雲仙期迫。", "言師有道骨，前事常被謫。如今三山上，名字在真籍。"]'),
('yuding-10','客有為餘話登天壇遇雨之狀，因以賦之','劉禹錫','唐','御定全唐诗','yuding','','[]','清晨登天壇，半路逢陰晦。疾行穿雨過，卻立視雲背。',168,'御定全唐詩/json/355.json','["清晨登天壇，半路逢陰晦。疾行穿雨過，卻立視雲背。", "白日照其上，風雷走於內。滉漾雪海翻，槎牙玉山碎。", "蛟龍露鬐鬣，神鬼含變態。萬狀互生滅，百音以繁會。", "俯觀群動靜，始覺天宇大。山頂自晶明，人間已滂沛。", "豁然重昏斂，渙若春冰潰。反照入松門，瀑流飛縞帶。", "遙光泛物色，餘韻吟天籟。洞府撞仙鐘，村墟起夕靄。", "卻見山下侶，已如迷世代。問我何處來，我來雲雨外。"]'),
('yuding-11','秋江早發','劉禹錫','唐','御定全唐诗','yuding','','[]','輕陰迎曉日，霞霽秋江明。草樹含遠思，襟杯有餘清。',96,'御定全唐詩/json/355.json','["輕陰迎曉日，霞霽秋江明。草樹含遠思，襟杯有餘清。", "凝睇萬象起，朗吟孤憤平。渚鴻未矯翼，而我已遐征。", "因思市朝人，方聽晨雞鳴。昏昏戀衾枕，安見元氣英。", "納爽耳目變，玩奇筋骨輕。滄洲有奇趣，浩然吾將行。"]'),
('yuding-12','有僧言羅浮事，因為詩以寫之','劉禹錫','唐','御定全唐诗','yuding','','[]','君言羅浮上，容易見九垠。漸高元氣壯，洶湧來翼身。',216,'御定全唐詩/json/355.json','["君言羅浮上，容易見九垠。漸高元氣壯，洶湧來翼身。", "夜宿最高峰，瞻望浩無鄰。海黑天宇曠，星辰來逼人。", "是時當朏魄，陰物恣騰振。日光吐鯨背，劍影開龍鱗。", "倏若萬馬馳，旌旗聳奫淪。又如廣樂奏，金石含悲辛。", "疑其有巨靈，怪物盡來賓。陰陽迭用事，乃俾夜作晨。", "咿喔天雞鳴，扶桑色昕昕。赤波千萬里，湧出黃金輪。", "下視生物息，霏如隙中塵。醯雞仰甕口，亦謂雲漢津。", "世人信耳目，方寸度大鈞。安知視聽外，怪愕不可陳。", "悠悠想大方，此乃杯水濱。知小天地大，安能識其真。"]'),
('yuding-13','裴祭酒尚書見示春歸城南青松塢別墅寄王左丞高侍郎之什命同作','劉禹錫','唐','御定全唐诗','yuding','','[]','早宦閱人事，晚懷生道機。時從學省出，獨望郊園歸。',168,'御定全唐詩/json/355.json','["早宦閱人事，晚懷生道機。時從學省出，獨望郊園歸。", "野彴度春水，山花映岩扉。石頭解金章，林下步綠薇。", "青松郁成塢，修竹盈尺圍。吟風起天籟，蔽日無炎威。", "危徑盤羊腸，連甍聳翬飛。幽谷響樵斧，澄潭環釣磯。", "因高見帝城，冠蓋揚光輝。白雲難持寄，清韻投所希。", "二公如長離，比翼翔太微。含情謝林壑，酬贈駢珠璣。", "顧予久郎潛，愁寂對芳菲。一聞丘中趣，再撫黃金徽。"]'),
('yuding-14','和河南裴尹侍郎宿齋天平寺詣九龍祠祈雨二十韻','劉禹錫','唐','御定全唐诗','yuding','','[]','有事九龍廟，潔齋梵王祠。玉簫何時絕，碧樹空涼颸。',240,'御定全唐詩/json/355.json','["有事九龍廟，潔齋梵王祠。玉簫何時絕，碧樹空涼颸。", "吏散埃壒息，月高庭宇宜。重城肅穆閉，澗水潺湲時。", "人稀夜複閑，慮靜境亦隨。緬懷斷鼇足，凝想乘鸞姿。", "朱明盛農節，膏澤方愆期。瞻言五靈瑞，能救百穀萎。", "咿喔晨雞鳴，闌幹斗柄垂。修容謁神像，注意陳正詞。", "驚飆起泓泉，若調雷雨師。黑煙聳鱗甲，灑液如棼絲。", "豐隆震天衢，列缺揮火旗。炎空忽淒緊，高溜懸綆縻。", "生物已滂沛，濕雲稍離披。丹霞啟南陸，白水含東菑。", "熙熙飛走適，藹藹草樹滋。浮光動宮觀，遠思盈川坻。", "吳公敏于政，謝守工為詩。商山有病客，言賀舒龐眉。"]'),
('yuding-15','冬夜宴河中李相公中堂命箏歌送酒','劉禹錫','唐','御定全唐诗','yuding','','[]','朗朗鶤雞弦，華堂夜多思。簾外雪已深，座中人半醉。',48,'御定全唐詩/json/355.json','["朗朗鶤雞弦，華堂夜多思。簾外雪已深，座中人半醉。", "翠蛾發清響，曲盡有餘意。酌我莫憂狂，老來無逸氣。"]'),
('yuding-16','重至衡陽傷柳儀曹','劉禹錫','唐','御定全唐诗','yuding','','[]','憶昨與故人，湘江岸頭別。我馬映林嘶，君帆轉山滅。',48,'御定全唐詩/json/355.json','["憶昨與故人，湘江岸頭別。我馬映林嘶，君帆轉山滅。", "馬嘶循古道，帆滅如流電。千里江蘺春，故人今不見。"]'),
('yuding-17','謫居悼往二首','劉禹錫','唐','御定全唐诗','yuding','','[]','邑邑何邑邑，長沙地卑濕。樓上見春多，花前恨風急。',96,'御定全唐詩/json/355.json','["邑邑何邑邑，長沙地卑濕。樓上見春多，花前恨風急。", "猿愁腸斷叫，鶴病翹趾立。牛衣獨自眠，誰哀仲卿泣。", "鬱鬱何鬱鬱，長安遠如日。終日念鄉關，燕來鴻複還。", "潘嶽歲寒思，屈平憔悴顏。殷勤望歸路，無雨即登山。"]'),
('yuding-18','有獺吟','劉禹錫','唐','御定全唐诗','yuding','','[]','有獺得嘉魚，自謂天見憐。先祭不敢食，捧鱗望青玄。',156,'御定全唐詩/json/355.json','["有獺得嘉魚，自謂天見憐。先祭不敢食，捧鱗望青玄。", "人立寒沙上，心專眼悁悁。漁翁以為妖，舉塊投其咽。", "呼兒貫魚歸，與獺同烹煎。關關黃金鶚，大翅搖江煙。", "下見盈尋魚，投身擘洪連。攫拏隱鱗去，哺雛林嶽巔。", "鴟烏欲伺隙，遙噪莫敢前。長居青雲路，彈射無由緣。", "何地無江湖，何水無鮪鱣。天意不宰割，菲祭徒虔虔。", "空餘知禮重，載在淹中篇。"]'),
('yuding-19','白太守行','劉禹錫','唐','御定全唐诗','yuding','','[]','聞有白太守，拋官歸舊溪。蘇州十萬戶，盡作嬰兒啼。',96,'御定全唐詩/json/355.json','["聞有白太守，拋官歸舊溪。蘇州十萬戶，盡作嬰兒啼。", "太守駐行舟，閶門草萋萋。揮袂謝啼者，依然兩眉低。", "朱戶非不崇，我心如重狴。華池非不清，意在寥廓棲。", "誇者竊所怪，賢者默思齊。我為太守行，題在隱起珪。"]'),
('yuding-20','樂天寄洛下新詩，兼喜微之欲到，因以抒懷也','劉禹錫','唐','御定全唐诗','yuding','','[]','松間風未起，萬葉不自吟。池上月未來，清輝同夕陰。',96,'御定全唐詩/json/355.json','["松間風未起，萬葉不自吟。池上月未來，清輝同夕陰。", "宮征不獨運，塤篪自相尋。一從別樂天，詩思日已沉。", "吟君洛中作，精絕百煉金。乃知孤鶴情，月露為知音。", "微之從東來，威鳳鳴歸林。羨君先相見，一豁平生心。"]'),
('yuding-21','月夜憶樂天兼寄微之','劉禹錫','唐','御定全唐诗','yuding','','[]','今宵帝城月，一望雪相似。遙想洛陽城，清光正如此。',48,'御定全唐詩/json/355.json','["今宵帝城月，一望雪相似。遙想洛陽城，清光正如此。", "知君當此夕，亦望鏡湖水。輾轉相憶心，月明千萬里。"]'),
('yuding-22','早夏郡中書事','劉禹錫','唐','御定全唐诗','yuding','','[]','水禽渡殘月，飛雨灑高城。華堂對嘉樹，簾廡含曉清。',96,'御定全唐詩/json/355.json','["水禽渡殘月，飛雨灑高城。華堂對嘉樹，簾廡含曉清。", "拂鏡整危冠，振衣步前楹。將吏儼成列，簿書紛來縈。", "言下辨曲直，筆端破交爭。虛懷詢病苦，懷律操剽輕。", "閽吏告無事，歸來解簪纓。高簾覆朱閣，忽爾聞調笙。"]'),
('yuding-23','酬樂天七月一日夜即事見寄','劉禹錫','唐','御定全唐诗','yuding','','[]','夜樹風韻清，天河雲彩輕。故苑多露草，隔城聞鶴鳴。',72,'御定全唐詩/json/355.json','["夜樹風韻清，天河雲彩輕。故苑多露草，隔城聞鶴鳴。", "搖落從此始，別離含遠情。聞君當是夕，倚瑟吟商聲。", "外物豈不足，中懷向誰傾。秋來念歸去，同聽嵩陽笙。"]'),
('yuding-24','令狐相公見示贈竹二十韻仍命繼和','劉禹錫','唐','御定全唐诗','yuding','','[]','高人必愛竹，寄興良有以。峻節可臨戎，虛心宜待士。',240,'御定全唐詩/json/355.json','["高人必愛竹，寄興良有以。峻節可臨戎，虛心宜待士。", "眾芳信妍媚，威鳳難棲止。遂於鼙鼓間，移植東南美。", "封以梁國土，澆之浚泉水。得地色不移，淩空勢方起。", "新青排故葉，餘紛籠疏理。猶複隔牆藩，何因出塵滓。", "茲辰去前蔽，永日勞瞪視。槭槭林已成，熒熒玉相似。", "規摹起心匠，洗滌在頤指。曲直既了然，孤高何卓爾。", "垂梢覆內屏，迸筍侵前戺。妓席拂雲鬢，賓階蔭珠履。", "抱琴恣閑玩，執卷堪斜倚。露下懸明璫，風來韻清征。", "堅貞貫四候，標格殊百卉。歲晚當自知，繁華豈雲比。", "古詩無贈竹，高唱從此始。一聽清瑤音，崢然長在耳。"]'),
('yuding-25','和令狐相公晚泛漢江書懷寄洋州崔侍郎閬州高舍人二曹長','劉禹錫','唐','御定全唐诗','yuding','','[]','雨過遠山出，江澄暮霞生。因浮濟川舟，遂作適野行。',120,'御定全唐詩/json/355.json','["雨過遠山出，江澄暮霞生。因浮濟川舟，遂作適野行。", "郊樹映緹騎，水禽避紅旌。田夫捐畚鍤，織婦窺柴荊。", "古岸夏花發，遙林晚蟬清。沿洄方玩境，鼓角已登城。", "部內有良牧，望中寄深情。臨觴念佳期，泛瑟動離聲。", "寂寞一病士，夙昔接群英。多謝謫仙侶，幾時還玉京。"]'),
('yuding-26','和樂天洛城春齊梁體八韻','劉禹錫','唐','御定全唐诗','yuding','','[]','帝城宜春入，遊人喜意長。草生季倫穀，花出莫愁坊。',96,'御定全唐詩/json/355.json','["帝城宜春入，遊人喜意長。草生季倫穀，花出莫愁坊。", "斷雲發山色，輕風漾水光。樓前戲馬地，樹下鬥雞場。", "白頭自為侶，綠酒亦滿觴。潘園觀種植，謝墅閱池塘。", "至閑似隱逸，過老不悲傷。相問焉功德，銀黃遊故鄉。"]'),
('yuding-27','洛中早春贈樂天','劉禹錫','唐','御定全唐诗','yuding','','[]','漠漠複靄靄，半晴將半陰。春來自何處，無跡日以深。',84,'御定全唐詩/json/355.json','["漠漠複靄靄，半晴將半陰。春來自何處，無跡日以深。", "韶嫩冰後木，輕盈煙際林。藤生欲有托，柳弱不自任。", "花意已含蓄，鳥言尚沉吟。期君當此時，與我恣追尋。", "翻愁爛熳後，春暮卻傷心。"]'),
('yuding-28','和樂天宴李周美中丞宅池上賞櫻桃花','劉禹錫','唐','御定全唐诗','yuding','','[]','櫻桃千萬枝，照耀如雪天。王孫宴其下，隔水疑神仙。',72,'御定全唐詩/json/355.json','["櫻桃千萬枝，照耀如雪天。王孫宴其下，隔水疑神仙。", "宿露發清香，初陽動暄妍。妖姬滿髻插，酒客折枝傳。", "同此賞芳月，幾人有華筵。杯行勿遽辭，好醉逸三年。"]'),
('yuding-29','酬樂天聞新蟬見贈','劉禹錫','唐','御定全唐诗','yuding','','[]','碧樹鳴蟬後，煙雲改容光。瑟然引秋氣，芳草日夜黃。',84,'御定全唐詩/json/355.json','["碧樹鳴蟬後，煙雲改容光。瑟然引秋氣，芳草日夜黃。", "夾道喧古槐，臨池思垂楊。離人下憶淚，志士激剛腸。", "昔聞阻山川，今聽同匡床。人情便所遇，音韻豈殊常。", "因之比笙竽，送我遊醉鄉。"]'),
('yuding-30','和樂天秋涼閑臥','劉禹錫','唐','御定全唐诗','yuding','','[]','暑退人體輕，雨餘天色改。荷珠貫索斷，竹粉殘妝在。',48,'御定全唐詩/json/355.json','["暑退人體輕，雨餘天色改。荷珠貫索斷，竹粉殘妝在。", "高僧掃室請，逸客登樓待。槐柳漸蕭疏，閑門少光彩。"]'),
('yuding-31','酬樂天詠老見示','劉禹錫','唐','御定全唐诗','yuding','','[]','人誰不願老，老去有誰憐。身瘦帶頻減，發稀冠自偏。',72,'御定全唐詩/json/355.json','["人誰不願老，老去有誰憐。身瘦帶頻減，發稀冠自偏。", "廢書緣惜眼，多炙為隨年。經事還諳事，閱人如閱川。", "細思皆幸矣，下此便翛然。莫道桑榆晚，微霞尚滿天。"]'),
('yuding-32','歲夜詠懷','劉禹錫','唐','御定全唐诗','yuding','','[]','彌年不得意，新歲又如何。念昔同遊者，而今有幾多。',48,'御定全唐詩/json/355.json','["彌年不得意，新歲又如何。念昔同遊者，而今有幾多。", "以閑為自在，將壽補蹉跎。春色無情故，幽居亦見過。"]'),
('yuding-33','酬牛相公獨飲偶醉寓言見示','劉禹錫','唐','御定全唐诗','yuding','','[]','宮漏夜丁丁，千門閉霜月。華堂列紅燭，絲管靜中發。',72,'御定全唐詩/json/355.json','["宮漏夜丁丁，千門閉霜月。華堂列紅燭，絲管靜中發。", "歌眉低有思，舞體輕無骨。主人啟酡顏，酣暢浹肌發。", "猶思城外客，阡陌不可越。春意日夕深，此歡無斷絕。"]'),
('yuding-34','萋兮吟','劉禹錫','唐','御定全唐诗','yuding','','[]','天涯浮雲生，爭蔽日月光。窮巷秋風起，先摧蘭蕙芳。',72,'御定全唐詩/json/355.json','["天涯浮雲生，爭蔽日月光。窮巷秋風起，先摧蘭蕙芳。", "萬貨列旗亭，恣心注明璫。名高毀所集，言巧智難防。", "勿謂行大道，斯須成太行。莫吟萋兮什，徒使君子傷。"]'),
('yuding-35','韓十八侍御見示岳陽樓別竇司直詩因令屬和重以自述故足成六十二韻','劉禹錫','唐','御定全唐诗','yuding','','[]','楚望何蒼然，曾瀾七百里。孤城寄遠目，一寫無窮已。',576,'御定全唐詩/json/355.json','["楚望何蒼然，曾瀾七百里。孤城寄遠目，一寫無窮已。", "蕩漾浮天蓋，四環宣地理。積漲在三秋，混成非一水。", "冬遊見清淺，春望多洲沚。雲錦遠沙明，風煙青草靡。", "火星忽南見，月硤方東迤。雪波西山來，隱若長城起。", "獨專朝宗路，駛悍不可止。支川讓其威，蓄縮至南委。", "熊武走蠻落，瀟湘來奧鄙。炎蒸動泉源，積潦搜山趾。", "歸往無旦夕，包含通遠邇。行當白露時，眇視秋光裏。", "曙色未昭晰，露華遙斐舋。浩爾神骨清，如觀混元始。", "北風忽震盪，驚浪迷津涘。怒激鼓鏗訇，蹙成山巋硊。", "鶤鵬疑變化，罔象何恢詭。噓吸寫樓臺，騰驤露鬐尾。", "景移群動息，波靜繁音弭。明月出中央，青天絕纖滓。", "素光淡無際，綠靜平如砥。空影渡鵷鴻，秋聲思蘆葦。", "鮫人弄機杼，貝闕駢紅紫。珠蛤吐玲瓏，文鰩翔旖旎。", "水鄉吳蜀限，地勢東南庳。翼軫粲垂精，衡巫屹環峙。", "名雄七澤藪，國辨三苗氏。唐羿斷修蛇，荊王憚青兕。", "秦狩跡猶在，虞巡路從此。軒後奏宮商，騷人詠蘭芷。", "茅嶺潛相應，橘洲傍可指。郭璞驗幽經，羅含著前紀。", "觀津戚裏族，按道侯家子。連袂登高樓，臨軒笑相視。", "假守亦高臥，墨曹正垂耳。契闊話涼溫，壺觴慰遷徙。", "地偏山水秀，客重杯盤侈。紅袖花欲然，銀燈晝相似。", "興酣更抵掌，樂極同啟齒。筆鋒不能休，藻思一何綺。", "伊余負微尚，夙昔慚知己。出入金馬門，交結青雲士。", "襲芳踐蘭室，學古遊槐市。策慕宋前軍，文師漢中壘。", "陋容昧俯仰，孤志無依倚。衛足不如葵，漏川空歎蟻。"]'),
('yuding-36','和郴州楊侍郎玩郡齋紫薇花十四韻','劉禹錫','唐','御定全唐诗','yuding','','[]','幾年丹霄上，出入金華省。暫別萬年枝，看花桂陽嶺。',168,'御定全唐詩/json/355.json','["幾年丹霄上，出入金華省。暫別萬年枝，看花桂陽嶺。", "南方足奇樹，公府成佳境。綠陰交廣除，明豔透蕭屏。", "雨餘人吏散，燕語簾櫳靜。懿此含曉芳，翛然忘簿領。", "紫茸垂組縷，金縷攢鋒穎。露溽暗傳香，風輕徐就影。", "苒弱多意思，從容占光景。得地在侯家，移根近仙井。", "開尊好凝睇，倚瑟仍回頸。遊蜂駐彩冠，舞鶴迷煙頂。", "興生紅藥後，愛與甘棠並。不學夭桃姿，浮榮在俄頃。"]'),
('yuding-37','春日寄楊八唐州二首','劉禹錫','唐','御定全唐诗','yuding','','[]','淮西春草長，淮水逶迤光。燕入新村落，人耕舊戰場。',72,'御定全唐詩/json/355.json','["淮西春草長，淮水逶迤光。燕入新村落，人耕舊戰場。", "可憐行春守，立馬看斜桑。", "漠漠淮上春，莠苗生故壘。梨花方城路，荻筍蕭陂水。", "高齋有謫仙，坐嘯清風起。"]'),
('yuding-38','酬馮十七舍人宿衛贈別五韻','劉禹錫','唐','御定全唐诗','yuding','','[]','少年為別日，隋宮楊柳陰。白首相逢處，巴江煙浪深。',60,'御定全唐詩/json/355.json','["少年為別日，隋宮楊柳陰。白首相逢處，巴江煙浪深。", "使星上三蜀，春雨沾衣襟。王程促速意，夜語殷勤心。", "卻歸天上去，遺我雲間音。"]'),
('yuding-39','酬湖州崔郎中見寄','劉禹錫','唐','御定全唐诗','yuding','','[]','風箏吟秋空，不肖指爪聲。高人靈府間，律呂伴咸英。',96,'御定全唐詩/json/355.json','["風箏吟秋空，不肖指爪聲。高人靈府間，律呂伴咸英。", "昔年與兄游，文似馬長卿。今來寄新詩，乃類陶淵明。", "磨礱老益智，吟詠閑彌精。豈非山水鄉，蕩漾神機清。", "渚煙蕙蘭動，溪雨虹蜺生。馮君虛上舍，待餘乘興行。"]'),
('yuding-40','秋日書懷寄河南王尹','劉禹錫','唐','御定全唐诗','yuding','','[]','公府想無事，西池秋水清。去年為狎客，永日奉高情。',48,'御定全唐詩/json/355.json','["公府想無事，西池秋水清。去年為狎客，永日奉高情。", "況有臺上月，如聞雲外笙。不知桑落酒，今歲與誰傾。"]'),
('yuding-41','酬留守牛相公宮城早秋寓言見寄','劉禹錫','唐','御定全唐诗','yuding','','[]','曉月映宮樹，秋光起天津。涼風稍動葉，宿露未生塵。',72,'御定全唐詩/json/355.json','["曉月映宮樹，秋光起天津。涼風稍動葉，宿露未生塵。", "星氣尚芳麗，曠望感心神。揮毫成逸韻，開合遲來賓。", "擺去將相印，漸為逍遙身。如招後房宴，卻要白頭人。"]'),
('yuding-42','海陽十詠：吏隱亭','劉禹錫','唐','御定全唐诗','yuding','','[]','結構得奇勢，朱門交碧潯。外來始一望，寫盡平生心。',48,'御定全唐詩/json/355.json','["結構得奇勢，朱門交碧潯。外來始一望，寫盡平生心。", "日軒漾波影，月砌鏤松陰。幾度欲歸去，回眸情更深。"]'),
('yuding-43','海陽十詠：切雲亭','劉禹錫','唐','御定全唐诗','yuding','','[]','迥破林煙出，俯窺石潭空。波搖杏梁日，松韻碧窗風。',48,'御定全唐詩/json/355.json','["迥破林煙出，俯窺石潭空。波搖杏梁日，松韻碧窗風。", "隔水生別島，帶橋如斷虹。九疑南面事，盡入寸眸中。"]'),
('yuding-44','海陽十詠：雲英潭','劉禹錫','唐','御定全唐诗','yuding','','[]','芳幄覆雲屏，石奩開碧鏡。支流日飛灑，深處自疑瑩。',48,'御定全唐詩/json/355.json','["芳幄覆雲屏，石奩開碧鏡。支流日飛灑，深處自疑瑩。", "潛去不見跡，清音常滿聽。有時病朝酲，來此心神醒。"]'),
('yuding-45','海陽十詠：玄覽亭','劉禹錫','唐','御定全唐诗','yuding','','[]','瀟灑青林際，夤緣碧潭隈。淙流冒石下，輕波觸砌回。',48,'御定全唐詩/json/355.json','["瀟灑青林際，夤緣碧潭隈。淙流冒石下，輕波觸砌回。", "香風逼人度，幽花覆水開。故令無四壁，晴夜月光來。"]'),
('yuding-46','海陽十詠：裴溪','劉禹錫','唐','御定全唐诗','yuding','','[]','楚客憶關中，疏溪想汾水。縈紆非一曲，意態如千里。',48,'御定全唐詩/json/355.json','["楚客憶關中，疏溪想汾水。縈紆非一曲，意態如千里。", "倒影羅文動，微波笑顏起。君今賜環歸，何人承玉趾。"]'),
('yuding-47','海陽十詠：飛練瀑','劉禹錫','唐','御定全唐诗','yuding','','[]','晶晶擲岩端，潔光如可把。瓊枝曲不折，雲片晴猶下。',48,'御定全唐詩/json/355.json','["晶晶擲岩端，潔光如可把。瓊枝曲不折，雲片晴猶下。", "石堅激清響，葉動承餘灑。前時明月中，見是銀河瀉。"]'),
('yuding-48','海陽十詠：蒙池','劉禹錫','唐','御定全唐诗','yuding','','[]','瀠渟幽壁下，深淨如無力。風起不成文，月來同一色。',48,'御定全唐詩/json/355.json','["瀠渟幽壁下，深淨如無力。風起不成文，月來同一色。", "地靈草木瘦，人遠煙霞逼。往往疑列仙，圍棋在岩側。"]'),
('yuding-49','海陽十詠：棼絲瀑','劉禹錫','唐','御定全唐诗','yuding','','[]','飛流透嵌隙，噴灑如絲棼。含暈迎初旭，翻光破夕曛。',48,'御定全唐詩/json/355.json','["飛流透嵌隙，噴灑如絲棼。含暈迎初旭，翻光破夕曛。", "餘波繞石去，碎響隔溪聞。卻望瓊沙際，逶迤見脈分。"]'),
('yuding-50','海陽十詠：雙溪','劉禹錫','唐','御定全唐诗','yuding','','[]','流水繞雙島，碧溪相並深。浮花擁曲處，遠影落中心。',48,'御定全唐詩/json/355.json','["流水繞雙島，碧溪相並深。浮花擁曲處，遠影落中心。", "閑鷺久獨立，曝龜驚複沉。蘋風有時起，滿穀簫韶音。"]'),
('yuding-51','海陽十詠：月窟','劉禹錫','唐','御定全唐诗','yuding','','[]','濺濺漱幽石，注入團圓處。有如常滿杯，承彼清夜露。',48,'御定全唐詩/json/355.json','["濺濺漱幽石，注入團圓處。有如常滿杯，承彼清夜露。", "岩曲月斜照，林寒春晚煦。遊人不敢觸，恐有蛟龍護。"]'),
('yuding-52','武夫詞','劉禹錫','唐','御定全唐诗','yuding','','[]','武夫何洸洸，衣紫襲絳裳。借問胡為爾，列校在鷹揚。',108,'御定全唐詩/json/355.json','["武夫何洸洸，衣紫襲絳裳。借問胡為爾，列校在鷹揚。", "依倚將軍勢，交結少年場。探丸害公吏，抽刃妒名倡。", "家產既不事，顧盼自生光。酣歌高樓上，袒裼大道傍。", "昔為編戶人，秉耒甘哺糠。今來從軍樂，躍馬飫膏粱。", "猶思風塵起，無種取侯王。"]'),
('yuding-53','虎丘寺路宴','劉禹錫','唐','御定全唐诗','yuding','','[]','青林虎丘寺，林際翠微路。立見山僧來，遙從鳥飛處。',144,'御定全唐詩/json/355.json','["青林虎丘寺，林際翠微路。立見山僧來，遙從鳥飛處。", "茲峰淪寶玉，千載惟丘墓。埋劍人空傳，鑿山龍已去。", "捫蘿披翳薈，路轉夕陰遽。虎嘯崖谷寒，猿鳴松杉暮。", "徘徊北樓上，海江窮一顧。日映千里帆，鴉歸萬家樹。", "暫因愜所適，果得捐外慮。庭暗棲還雲，簷香滴甘露。", "久迷空寂理，多為聲華故。永欲投此山，餘生豈能誤。"]'),
('yuding-54','缺題','劉禹錫','唐','御定全唐诗','yuding','','[]','故人日已遠，窗下塵滿琴。坐對一樽酒，恨多無力斟。',48,'御定全唐詩/json/355.json','["故人日已遠，窗下塵滿琴。坐對一樽酒，恨多無力斟。", "幕疏螢色迥，露重月華深。萬境與群籟，此時情豈任。"]'),
('yuding-55','晚步揚子游南塘望沙尾','劉禹錫','唐','御定全唐诗','yuding','','[]','淮海多夏雨，曉來天始晴。蕭條長風至，千里孤雲生。',108,'御定全唐詩/json/355.json','["淮海多夏雨，曉來天始晴。蕭條長風至，千里孤雲生。", "卑濕久喧濁，搴開偶虛清。客遊廣陵郡，晚出臨江城。", "郊外綠楊陰，江中沙嶼明。歸帆翳盡日，去棹聞遺聲。", "鄉國殊渺漫，羈心目懸旌。悠然京華意，悵望懷遠程。", "薄暮大山上，翩翩雙鳥征。"]'),
('yuding-56','和浙西李大夫晚下北固山喜徑松成陰悵然懷古偶題臨江亭并浙東元相公所和依本韻','劉禹錫','唐','御定全唐诗','yuding','','[]','一辭溫室樹，幾見武昌柳。荀謝年何少，韋平望已久。',240,'御定全唐詩/json/355.json','["一辭溫室樹，幾見武昌柳。荀謝年何少，韋平望已久。", "種松夾石道，紆組臨沙阜。目覽帝王州，心存股肱守。", "葉動驚彩翰，波澄見赬首。晉宋齊梁都，千山萬江口。", "煙散隋宮出，濤來海門吼。風俗太伯餘，衣冠永嘉後。", "江長天作限，山固壤無朽。自古稱佳麗，非賢誰奄有。", "八元邦族盛，萬石門風厚。天柱揭東溟，文星照北斗。", "高亭一騁望，舉酒共為壽。因賦詠懷詩，遠寄同心友。", "禁中晨夜直，江左東西偶。將手握兵符，儒腰盤貴綬。", "頒條風有自，立事言無苟。農野聞讓耕，軍人不使酒。", "用材當構廈，知道寧窺牖。誰謂青雲高，鵬飛終背負。"]'),
('yuding-57','始至雲安寄兵部韓侍郎中書白舍人二公近曾遠守故有屬焉','劉禹錫','唐','御定全唐诗','yuding','','[]','天外巴子國，山頭白帝城。波清蜀栜盡，雲散楚台傾。',144,'御定全唐詩/json/355.json','["天外巴子國，山頭白帝城。波清蜀栜盡，雲散楚台傾。", "迅瀨下哮吼，兩岸勢爭衡。陰風鬼神過，暴雨蛟龍生。", "硤斷見孤邑，江流照飛甍。蠻軍擊嚴鼓，笮馬引雙旌。", "望闕遙拜舞，分庭備將迎。銅符一以合，文墨紛來縈。", "暮色四山起，愁猿數處聲。重關群吏散，靜室寒燈明。", "故人青霞意，飛舞集蓬瀛。昔曾在池籞，應知魚鳥情。"]'),
('yuding-0','更衣曲','劉禹錫','唐','御定全唐诗','yuding','','[]','博山炯炯吐香霧，紅燭引至更衣處。夜如何其夜漫漫，',40,'御定全唐詩/json/356.json','["博山炯炯吐香霧，紅燭引至更衣處。夜如何其夜漫漫，", "滿堂醉客爭笑語，嘈囋琵琶青幕中。"]'),
('yuding-1','桃源行','劉禹錫','唐','御定全唐诗','yuding','','[]','漁舟何招招，浮在武陵水。拖綸擲餌信流去，',108,'御定全唐詩/json/356.json','["漁舟何招招，浮在武陵水。拖綸擲餌信流去，", "洞門蒼黑煙霧生，暗行數步逢虛明。俗人毛骨驚仙子，", "因嗟隱身來種玉，不知人世如風燭。筵羞石髓勸客餐，", "漁人振衣起出戶，滿庭無路花紛紛。翻然恐失鄉縣處，", "仙家一出尋無蹤，至今流水山重重。"]'),
('yuding-2','洞庭秋月行','劉禹錫','唐','御定全唐诗','yuding','','[]','洞庭秋月生湖心，層波萬頃如熔金。孤輪徐轉光不定，',88,'御定全唐詩/json/356.json','["洞庭秋月生湖心，層波萬頃如熔金。孤輪徐轉光不定，", "岳陽樓頭暮角絕，蕩漾已過君山東。山城蒼蒼夜寂寂，", "勢高夜久陰力全，金氣肅肅開星躔。浮雲野馬歸四裔，", "日出喧喧人不閑，夜來清景非人間。"]'),
('yuding-3','九華山歌','劉禹錫','唐','御定全唐诗','yuding','','[]','奇峰一見驚魂魄，意想洪爐始開闢。疑是九龍夭矯欲攀天，',93,'御定全唐詩/json/356.json','["奇峰一見驚魂魄，意想洪爐始開闢。疑是九龍夭矯欲攀天，", "結根不得要路津，迥秀長在無人境。軒皇封禪登雲亭，", "君不見敬亭之山黃索漠，兀如斷岸無棱角。", "宣城謝守一首詩，遂使聲名齊五嶽。九華山，九華山，"]'),
('yuding-4','泰娘歌','劉禹錫','唐','御定全唐诗','yuding','','[]','泰娘家本閶門西，門前綠水環金堤。有時妝成好天氣，',160,'御定全唐詩/json/356.json','["泰娘家本閶門西，門前綠水環金堤。有時妝成好天氣，", "鬥量明珠鳥傳意，紺幰迎入專城居。長鬟如雲衣似霧，", "從郎西入帝城中，貴遊簪組香簾櫳。低鬟緩視抱明月，", "洛陽舊宅生草萊，杜陵蕭蕭松柏哀。妝奩蟲網厚如繭，", "自言買笑擲黃金，月墮雲中從此始。安知鵩鳥座隅飛，", "山城少人江水碧，斷雁哀猿風雨夕。朱弦已絕為知音，", "如何將此千行淚，更灑湘江斑竹枝。"]'),
('yuding-5','龍陽縣歌','劉禹錫','唐','御定全唐诗','yuding','','[]','縣門白日無塵土，百姓縣前挽魚罟。主人引客登大堤，',40,'御定全唐詩/json/356.json','["縣門白日無塵土，百姓縣前挽魚罟。主人引客登大堤，", "沙平草綠見吏稀，寂曆斜陽照縣鼓。"]'),
('yuding-6','牆陰歌','劉禹錫','唐','御定全唐诗','yuding','','[]','白日左右浮天潢，朝晡影入東西牆。昔為兒童在陰戲，',64,'御定全唐詩/json/356.json','["白日左右浮天潢，朝晡影入東西牆。昔為兒童在陰戲，", "西鄰田舍乏糟糠，就影汲汲舂黃粱。因思九州四海外，", "君看眼前光陰促，中心莫學太行山。"]'),
('yuding-7','踏潮歌','劉禹錫','唐','御定全唐诗','yuding','','[]','屯門積日無回飆，滄波不歸成踏潮。轟如鞭石矻且搖，',72,'御定全唐詩/json/356.json','["屯門積日無回飆，滄波不歸成踏潮。轟如鞭石矻且搖，", "四邊無阻音響調，背負元氣掀重霄。介鯨得性方逍遙，", "征南將軍登麗譙，赤旗指麾不敢囂。翌日風回沴氣消，"]'),
('yuding-8','白鷺兒','劉禹錫','唐','御定全唐诗','yuding','','[]','白鷺兒，最高格。毛衣新成雪不敵，眾禽喧呼獨凝寂。',48,'御定全唐詩/json/356.json','["白鷺兒，最高格。毛衣新成雪不敵，眾禽喧呼獨凝寂。", "孤眠芊芊草，久立潺潺石。前山正無雲，飛去入遙碧。"]'),
('yuding-9','平齊行二首','劉禹錫','唐','御定全唐诗','yuding','','[]','胡塵昔起薊北門，河南地屬平盧軍。貂裘代馬繞東嶽，',168,'御定全唐詩/json/356.json','["胡塵昔起薊北門，河南地屬平盧軍。貂裘代馬繞東嶽，", "魯人皆解帶弓箭，齊人不復聞簫韶。今朝天子聖神武，", "去秋詔下誅東平，官軍四合猶嬰城。春來群烏噪且驚，", "帳中虜血流滿地，門外三軍舞連臂。驛騎函首過黃河，", "泰山沉寇六十年，旅祭不享生愁煙。今逢聖君欲封禪，", "開元皇帝東封時，百神受職爭賓士。千鈞猛簴順流下，", "當今睿孫承聖祖，嶽神望幸河宗舞。青門大道屬車塵，"]'),
('yuding-10','送裴處士應制舉詩','劉禹錫','唐','御定全唐诗','yuding','','[]','裴生久在風塵裏，氣勁言高少知己。注書曾學鄭司農，',120,'御定全唐詩/json/356.json','["裴生久在風塵裏，氣勁言高少知己。注書曾學鄭司農，", "登山雨中試蠟屐，入洞夏裏披貂裘。白帝城邊又相遇，", "人言策中說何事，掉頭不答看飛鴻。彤庭翠松迎曉日，", "古稱射策如彎弧，一發偶中何時無。由來草澤無忌諱，", "垂鉤釣得王餘魚，踏芳共登蘇小墓。此事今同夢想間，"]'),
('yuding-11','三鄉驛樓伏睹玄宗望女幾山詩，小臣斐然有感','劉禹錫','唐','御定全唐诗','yuding','','[]','開元天子萬事足，唯惜當時光景促。三鄉陌上望仙山，',40,'御定全唐詩/json/356.json','["開元天子萬事足，唯惜當時光景促。三鄉陌上望仙山，", "天上忽乘白雲去，世間空有秋風詞。"]'),
('yuding-12','城西行','劉禹錫','唐','御定全唐诗','yuding','','[]','城西簇簇三叛族，叛者為誰蔡吳蜀。中使提刀出禁來，',48,'御定全唐詩/json/356.json','["城西簇簇三叛族，叛者為誰蔡吳蜀。中使提刀出禁來，", "守吏能然董卓臍，饑烏來覘桓玄目。城西人散泰階平，"]'),
('yuding-13','武昌老人說笛歌','劉禹錫','唐','御定全唐诗','yuding','','[]','武昌老人七十餘，手把庾令相問書。自言少小學吹笛，',72,'御定全唐詩/json/356.json','["武昌老人七十餘，手把庾令相問書。自言少小學吹笛，", "當時買材恣搜索，典卻身上烏貂裘。古苔蒼蒼封老節，", "曾將黃鶴樓上吹，一聲占盡秋江月。如今老去語尤遲，"]'),
('yuding-14','西山蘭若試茶歌','劉禹錫','唐','御定全唐诗','yuding','','[]','山僧後簷茶數叢，春來映竹抽新茸。宛然為客振衣起，',112,'御定全唐詩/json/356.json','["山僧後簷茶數叢，春來映竹抽新茸。宛然為客振衣起，", "驟雨松聲入鼎來，白雲滿碗花徘徊。悠揚噴鼻宿酲散，", "炎帝雖嘗未解煎，桐君有籙那知味。新芽連拳半未舒，", "僧言靈味宜幽寂，采采翹英為嘉客。不辭緘封寄郡齋，", "欲知花乳清泠味，須是眠雲跂石人。"]'),
('yuding-15','聚蚊謠','劉禹錫','唐','御定全唐诗','yuding','','[]','沉沉夏夜蘭堂開，飛蚊伺暗聲如雷。嘈然欻起初駭聽，',64,'御定全唐詩/json/356.json','["沉沉夏夜蘭堂開，飛蚊伺暗聲如雷。嘈然欻起初駭聽，", "露花滴瀝月上天，利觜迎人著不得。我軀七尺爾如芒，", "清商一來秋日曉，羞爾微形飼丹鳥。"]'),
('yuding-16','百舌吟','劉禹錫','唐','御定全唐诗','yuding','','[]','曉星寥落春雲低，初聞百舌間關啼。花樹滿空迷處所，',96,'御定全唐詩/json/356.json','["曉星寥落春雲低，初聞百舌間關啼。花樹滿空迷處所，", "東方朝日遲遲升，迎風弄景如自矜。數聲不盡又飛去，", "酡顏俠少停歌聽，墜珥妖姬和睡聞。可憐光景何時盡，", "天生羽族爾何微，舌端萬變乘春暉。南方朱鳥一朝見，"]'),
('yuding-17','飛鳶操','劉禹錫','唐','御定全唐诗','yuding','','[]','鳶飛杳杳青雲裏，鳶鳴蕭蕭風四起。旗尾飄揚勢漸高，',96,'御定全唐詩/json/356.json','["鳶飛杳杳青雲裏，鳶鳴蕭蕭風四起。旗尾飄揚勢漸高，", "遊鶤翔雁出其下，慶雲清景相迴旋。忽聞饑烏一噪聚，", "畏人避犬投高處，俯啄無聲猶屢顧。青鳥自愛玉山禾，", "游童挾彈一麾肘，臆碎羽分人不悲。天生眾禽各有類，"]'),
('yuding-18','秋螢引','劉禹錫','唐','御定全唐诗','yuding','','[]','漢陵秦苑遙蒼蒼，陳根腐葉秋螢光。夜空寥寂金氣淨，',96,'御定全唐詩/json/356.json','["漢陵秦苑遙蒼蒼，陳根腐葉秋螢光。夜空寥寂金氣淨，", "露華洗濯清風吹，低昂不定招搖垂。高麗罘罳照珠網，", "槐市諸生夜讀書，北窗分明辨魯魚。行子東山起征思，", "誰言向晦常自明，兒童走步嬌女爭。天生有光非自衒，"]'),
('yuding-19','傷秦姝行','劉禹錫','唐','御定全唐诗','yuding','','[]','長安二月花滿城，插花女兒彈銀箏。南宮仙郎下朝晚，',144,'御定全唐詩/json/356.json','["長安二月花滿城，插花女兒彈銀箏。南宮仙郎下朝晚，", "此時意重千金輕，鳥傳消息紺輪迎。芳筵銀燭一相見，", "青牛文梓赤金簧，玫瑰寶柱秋雁行。斂蛾收袂凝清光，", "曲終韻盡意不足，餘思悄絕愁空堂。從郎鎮南別城闕，", "北池含煙瑤草短。萬松亭下清風滿。秦聲一曲此時聞，", "侍兒掩泣收銀甲，鸚鵡不言愁玉籠。博山爐中香自滅，"]'),
('yuding-20','競渡曲','劉禹錫','唐','御定全唐诗','yuding','','[]','沅江五月平堤流，邑人相將浮彩舟。靈均何年歌已矣，',88,'御定全唐詩/json/356.json','["沅江五月平堤流，邑人相將浮彩舟。靈均何年歌已矣，", "蛟龍得雨鬐鬣動，螮蝀飲河形影聯。刺史臨流褰翠幃，", "百勝本自有前期，一飛由來無定所。風俗如狂重此時，", "曲終人散空愁暮，招屈亭前水東注。"]'),
('yuding-21','翰林白二十二學士見寄詩一百篇，因以答貺','劉禹錫','唐','御定全唐诗','yuding','','[]','吟君遺我百篇詩，使我獨坐形神馳。玉琴清夜人不語，',40,'御定全唐詩/json/356.json','["吟君遺我百篇詩，使我獨坐形神馳。玉琴清夜人不語，", "世人方內欲相尋，行盡四維無處覓。"]'),
('yuding-22','憶春草','劉禹錫','唐','御定全唐诗','yuding','','[]','憶春草，處處多情洛陽道。金谷園中見日遲，',44,'御定全唐詩/json/356.json','["憶春草，處處多情洛陽道。金谷園中見日遲，", "府門閉後滿街月，幾處遊人草頭歇。館娃宮外姑蘇台，"]'),
('yuding-23','樂天寄憶舊遊，因作報白君以答','劉禹錫','唐','御定全唐诗','yuding','','[]','報白君，別來已渡江南春。江南春色何處好，',88,'御定全唐詩/json/356.json','["報白君，別來已渡江南春。江南春色何處好，", "丫頭小兒蕩畫槳，長袂女郎簪翠翹。郡齋北軒卷羅幕，", "吳娃足情言語黠，越客有酒巾冠斜。坐中皆言白太守，", "報白君，相思空望嵩丘雲。其奈錢塘蘇小小，"]'),
('yuding-24','兩如何詩謝裴令公贈別二首','劉禹錫','唐','御定全唐诗','yuding','','[]','一言一顧重，重何如。今日陪游清洛苑，昔年別入承明廬。',52,'御定全唐詩/json/356.json','["一言一顧重，重何如。今日陪游清洛苑，昔年別入承明廬。", "一東一西別，別何如。終期大冶再熔煉，願托扶搖翔碧虛。"]'),
('yuding-25','唐侍禦寄游道林嶽麓二寺詩並沈中丞姚員外所和見征繼作','劉禹錫','唐','御定全唐诗','yuding','','[]','湘西古刹雙蹲蹲，群峰朝拱如駿奔。青松步障深五裏，',112,'御定全唐詩/json/356.json','["湘西古刹雙蹲蹲，群峰朝拱如駿奔。青松步障深五裏，", "橘洲泛浮金實動，水郭繚繞朱樓鶱。語餘百響入天籟，", "回廊架險高且曲，新徑穿林明複昏。淺流忽濁山獸過，", "紫髯翼從紅袖舞，竹風松雪香溫黁。遠持清瑣照巫峽，", "恨無黃金千萬餅，布地買取為丘園。"]'),
('yuding-26','將赴汝州，途出浚下，留辭李相公','劉禹錫','唐','御定全唐诗','yuding','','[]','長安舊遊四十載，鄂渚一別十四年。後來富貴已零落，',88,'御定全唐詩/json/356.json','["長安舊遊四十載，鄂渚一別十四年。後來富貴已零落，", "相看卻數六朝臣，屈指如今無四五。夷門天下之咽喉，", "久別凡經幾多事，何由說得平生意。千思萬慮盡如空，", "功成名遂會歸老，請向東山為近鄰。"]'),
('yuding-27','平蔡州三首','劉禹錫','唐','御定全唐诗','yuding','','[]','蔡州城中眾心死，妖星夜落照壕水。漢家飛將下天來，',136,'御定全唐詩/json/356.json','["蔡州城中眾心死，妖星夜落照壕水。漢家飛將下天來，", "狂童面縛登檻車，太白夭矯垂捷書。相公從容來鎮撫，", "汝南晨雞喔喔鳴，城頭鼓角音和平。路傍老人憶舊事，", "忽驚元和十二載，重見天寶承平時。", "九衢車馬渾渾流，使臣來獻淮西囚。四夷聞風失匕箸，", "南峰無火楚澤間，夜行不鎖穆陵關。策勳禮畢天下泰，"]'),
('yuding-28','送僧仲剬東遊兼寄呈靈澈上人','劉禹錫','唐','御定全唐诗','yuding','','[]','釋子道成神氣閑，住持曾上清涼山。晴空禮拜見真像，',112,'御定全唐詩/json/356.json','["釋子道成神氣閑，住持曾上清涼山。晴空禮拜見真像，", "松間白月照寶書，竹下香泉灑瑤席。前時學得經論成，", "舊聞南方多長老，次第來入荊門道。荊州本自重彌天，", "忽憶遺民社中客，為我衡陽駐飛錫。講罷同尋相鶴經，", "憑將雜擬三十首，寄與江南湯慧休。"]'),
('yuding-29','觀棋歌送儇師西游','劉禹錫','唐','御定全唐诗','yuding','','[]','長沙男子東林師，閑讀藝經工弈棋。有時凝思如入定，',120,'御定全唐詩/json/356.json','["長沙男子東林師，閑讀藝經工弈棋。有時凝思如入定，", "山人無事秋日長，白晝懵懵眠匡床。因君臨局看鬥智，", "前身後身付餘習，百變千化無窮已。初疑磊落曙天星，", "行盡三湘不逢敵，終日饒人損機格。自言台閣有知音，", "忽思爭道畫平沙，獨笑無言心有適。藹藹京城在九天，"]'),
('yuding-30','吐綬鳥詞','劉禹錫','唐','御定全唐诗','yuding','','[]','越山有鳥翔寥廓，嗉中天綬光若若。越人偶見而奇之，',120,'御定全唐詩/json/356.json','["越山有鳥翔寥廓，嗉中天綬光若若。越人偶見而奇之，", "赤玉雕成彪炳毛，紅綃翦出玲瓏翅。湖煙始開山日高，", "花紅草綠人間事，未若靈禽自然貴。鶴吐明珠暫報恩，", "翠幕雕籠非所慕，珠丸柘彈莫相猜。棲月啼煙淩縹緲，", "不學碧雞依井絡，願隨青鳥向層城。太液池中有黃鵠，"]'),
('yuding-31','八月十五日夜桃源玩月','劉禹錫','唐','御定全唐诗','yuding','','[]','塵中見月心亦閑，況是清秋仙府間。凝光悠悠寒露墜，',72,'御定全唐詩/json/356.json','["塵中見月心亦閑，況是清秋仙府間。凝光悠悠寒露墜，", "群動翛然一顧中，天高地平千萬里。少君引我升玉壇，", "金霞昕昕漸東上，輪欹影促猶頻望。絕景良時難再並，"]'),
('yuding-32','送鴻舉游江西','劉禹錫','唐','御定全唐诗','yuding','','[]','禪客學禪兼學文，出山初似無心雲。從風卷舒來何處，',88,'御定全唐詩/json/356.json','["禪客學禪兼學文，出山初似無心雲。從風卷舒來何處，", "使君灘頭揀石硯，白帝城邊尋野蔬。忽然登高心瞥起，", "荊門峽斷無盤渦，湘平漢闊清光多。廬山霧開見瀑布，", "與師相見便談空，想得高齋獅子吼。"]'),
('yuding-33','采菱行','劉禹錫','唐','御定全唐诗','yuding','','[]','白馬湖平秋日光，紫菱如錦彩鴛翔。蕩舟游女滿中央，',88,'御定全唐詩/json/356.json','["白馬湖平秋日光，紫菱如錦彩鴛翔。蕩舟游女滿中央，", "長鬟弱袂動參差，釵影釧文浮蕩漾。笑語哇咬顧晚暉，", "家家竹樓臨廣陌，下有連檣多估客。攜觴薦芰夜經過，", "一曲南音此地聞，長安北望三千里。"]'),
('yuding-34','和牛相公南溪醉歌見寄','劉禹錫','唐','御定全唐诗','yuding','','[]','脫屣將相守沖謙，唯於山水獨不廉。枕伊背洛得勝地，',144,'御定全唐詩/json/356.json','["脫屣將相守沖謙，唯於山水獨不廉。枕伊背洛得勝地，", "清池曲榭人所致，野趣幽芳天與添。有時轉入潭島間，", "怪石釣出太湖底，珠樹移自天臺尖。崇蘭迎風綠泛豔，", "渚蒲抽芽劍脊動，岸荻迸筍錐頭銛。攜觴命侶極永日。", "此會雖數心無厭。人皆置莊身不到，富貴難與逍遙兼。", "唯公出處得自在，決就放曠辭炎炎。座賓盡歡恣談謔，"]'),
('yuding-35','和浙西李大夫霜夜對月，聽小童吹觱篥歌，依本韻','劉禹錫','唐','御定全唐诗','yuding','','[]','海門雙青暮煙歇，萬頃金波湧明月。侯家小兒能觱篥，',96,'御定全唐詩/json/356.json','["海門雙青暮煙歇，萬頃金波湧明月。侯家小兒能觱篥，", "涵胡畫角怨邊草，蕭瑟清蟬吟野叢。沖融頓挫心使指，", "郡人寂聽衣滿霜，江城月斜樓影長。才驚指下繁韻息，", "一奏荊人白雪歌，如聞雒客扶風鄔。吳門水驛按山陰，"]'),
('yuding-36','歎水別白二十二','劉禹錫','唐','御定全唐诗','yuding','','[]','水。至清，盡美。從一勺，至千里。利人利物，',21,'御定全唐詩/json/356.json','["水。至清，盡美。從一勺，至千里。利人利物，"]'),
('yuding-37','同留守王僕射各賦春中一物，從一韻至七','劉禹錫','唐','御定全唐诗','yuding','','[]','鶯。能語，多情。春將半，天欲明。始逢南陌，',21,'御定全唐詩/json/356.json','["鶯。能語，多情。春將半，天欲明。始逢南陌，"]'),
('yuding-38','傷我馬詞','劉禹錫','唐','御定全唐诗','yuding','','[]','生於磧礪善馳走，萬里南來困丘阜。青菰寒菽非適口，',24,'御定全唐詩/json/356.json','["生於磧礪善馳走，萬里南來困丘阜。青菰寒菽非適口，"]'),
('yuding-39','清湘詞二首','劉禹錫','唐','御定全唐诗','yuding','','[]','湘水流，湘水流，九疑雲物至今愁。君問二妃何處所，',48,'御定全唐詩/json/356.json','["湘水流，湘水流，九疑雲物至今愁。君問二妃何處所，", "斑竹枝，斑竹枝，淚痕點點寄相思。楚客欲聞瑤瑟怨，"]'),
('yuding-40','和樂天春詞，依憶江南曲拍為句','劉禹錫','唐','御定全唐诗','yuding','','[]','春去也，多謝洛城人。弱柳從風疑舉袂，',36,'御定全唐詩/json/356.json','["春去也，多謝洛城人。弱柳從風疑舉袂，", "春過也，笑惜豔陽年。猶有桃花流水上，"]'),
('yuding-41','澤宮詩','劉禹錫','唐','御定全唐诗','yuding','','[]','秩秩澤宮，有的維鵠。祁祁庶士，於以幹祿。',80,'御定全唐詩/json/356.json','["秩秩澤宮，有的維鵠。祁祁庶士，於以幹祿。", "彼鵠斯微，若止若翔。千里之差，起於毫芒。", "我矢既直，我弓既良，依于高墉，因我不臧。", "高墉伊何，維器與時。視之以心，誰謂鵠微。"]'),
('yuding-42','酬令狐相公六言見寄','劉禹錫','唐','御定全唐诗','yuding','','[]','已嗟別離太遠，更被光陰苦催。吳苑燕辭人去，',35,'御定全唐詩/json/356.json','["已嗟別離太遠，更被光陰苦催。吳苑燕辭人去，", "今日便令歌者，唱兄詩送一杯。"]'),
('yuding-43','答樂天臨都驛見贈','劉禹錫','唐','御定全唐诗','yuding','','[]','北固山邊波浪，東都城裏風塵。',28,'御定全唐詩/json/356.json','["北固山邊波浪，東都城裏風塵。", "世事不同心事，新人何似故人。"]'),
('yuding-44','再贈樂天','劉禹錫','唐','御定全唐诗','yuding','','[]','一政政官軋軋，一年年老駸駸。',28,'御定全唐詩/json/356.json','["一政政官軋軋，一年年老駸駸。", "身外名何足算，別來詩且同吟。"]'),
('yuding-45','酬楊侍郎憑見寄','劉禹錫','唐','御定全唐诗','yuding','','[]','十年毛羽摧頹，一旦天書召回。',28,'御定全唐詩/json/356.json','["十年毛羽摧頹，一旦天書召回。", "看看瓜時欲到，故侯也好歸來。"]'),
('yuding-0','春有情篇','劉禹錫','唐','御定全唐诗','yuding','','[]','為問遊春侶，春情何處尋。花含欲語意，草有鬥生心。',48,'御定全唐詩/json/357.json','["為問遊春侶，春情何處尋。花含欲語意，草有鬥生心。", "雨頻催發色，雲輕不作陰。縱令無月夜，芳興暗中深。"]'),
('yuding-1','七夕二首','劉禹錫','唐','御定全唐诗','yuding','','[]','河鼓靈旗動，嫦娥破鏡斜。滿空天是幕，徐轉鬥為車。',96,'御定全唐詩/json/357.json','["河鼓靈旗動，嫦娥破鏡斜。滿空天是幕，徐轉鬥為車。", "機罷猶安石，橋成不礙槎。誰知觀津女，竟夕望雲涯。", "天衢啟雲帳，神馭上星橋。初喜渡河漢，頻驚轉鬥杓。", "餘霞張錦幛，輕電閃紅綃。非是人間世，還悲後會遙。"]'),
('yuding-2','邊風行','劉禹錫','唐','御定全唐诗','yuding','','[]','邊馬蕭蕭鳴，邊風滿磧生。暗添弓箭力，鬥上鼓鼙聲。',48,'御定全唐詩/json/357.json','["邊馬蕭蕭鳴，邊風滿磧生。暗添弓箭力，鬥上鼓鼙聲。", "襲月寒暈起，吹雲陰陣成。將軍占氣候，出號夜翻營。"]'),
('yuding-3','送工部蕭郎中刑部李郎中並以本官兼中丞分命充京西京北覆糧使','劉禹錫','唐','御定全唐诗','yuding','','[]','霜簡映金章，相輝同舍郎。天威巡虎落，星使出鴛行。',48,'御定全唐詩/json/357.json','["霜簡映金章，相輝同舍郎。天威巡虎落，星使出鴛行。", "尊俎成全策，京坻閱見糧。歸來虜塵滅，畫地奏明光。"]'),
('yuding-4','送太常蕭博士棄官歸養赴東都','劉禹錫','唐','御定全唐诗','yuding','','[]','兄弟盡鴛鸞，歸心切問安。貪榮五彩服，遂掛兩梁冠。',48,'御定全唐詩/json/357.json','["兄弟盡鴛鸞，歸心切問安。貪榮五彩服，遂掛兩梁冠。", "侍膳曾調鼎，循陔更握蘭。從今別君後，長憶德星看。"]'),
('yuding-5','送河南皇甫少尹赴絳州','劉禹錫','唐','御定全唐诗','yuding','','[]','祖帳臨周道，前旌指晉城。午橋群吏散，亥字老人迎。',48,'御定全唐詩/json/357.json','["祖帳臨周道，前旌指晉城。午橋群吏散，亥字老人迎。", "詩酒同行樂，別離方見情。從此洛陽社，吟詠屬書生。"]'),
('yuding-6','發華州留別張侍禦','劉禹錫','唐','御定全唐诗','yuding','','[]','束簡下延閣，買符驅短轅。同人惜分袂，結念醉芳樽。',48,'御定全唐詩/json/357.json','["束簡下延閣，買符驅短轅。同人惜分袂，結念醉芳樽。", "切切別弦急，蕭蕭征騎煩。臨岐無限意，相視卻忘言。"]'),
('yuding-7','奉送家兄歸王屋山隱居二首','劉禹錫','唐','御定全唐诗','yuding','','[]','洛陽天壇上，依稀似玉京。夜分先見日，月靜遠聞笙。',96,'御定全唐詩/json/357.json','["洛陽天壇上，依稀似玉京。夜分先見日，月靜遠聞笙。", "雲路將雞犬，丹台有姓名。古來成道者，兄弟亦同行。", "春來山事好，歸去亦逍遙。水淨苔莎色，露香芝朮苗。", "登臺吸瑞景，飛步翼神飆。願薦塤篪曲，相將學玉簫。"]'),
('yuding-8','送王師魯協律赴湖南使幕','劉禹錫','唐','御定全唐诗','yuding','','[]','翩翩馬上郎，驅傳渡三湘。橘樹沙洲暗，松醪酒肆香。',48,'御定全唐詩/json/357.json','["翩翩馬上郎，驅傳渡三湘。橘樹沙洲暗，松醪酒肆香。", "素風傳竹帛，高價聘琳琅。楚水多蘭芷，何人事搴芳。"]'),
('yuding-9','送趙中丞自司金郎轉官參山南令狐僕射幕府','劉禹錫','唐','御定全唐诗','yuding','','[]','綠樹滿褒斜，西南蜀路賒。驛門臨白草，縣道入黃花。',48,'御定全唐詩/json/357.json','["綠樹滿褒斜，西南蜀路賒。驛門臨白草，縣道入黃花。", "相府開油幕，門生逐絳紗。行看布政後，還從入京華。"]'),
('yuding-10','送盧處士歸嵩山別業','劉禹錫','唐','御定全唐诗','yuding','','[]','世業嵩山隱，雲深無四鄰。藥爐燒姹女，酒甕貯賢人。',48,'御定全唐詩/json/357.json','["世業嵩山隱，雲深無四鄰。藥爐燒姹女，酒甕貯賢人。", "晚日華陰霧，秋風函穀塵。送君從此去，鈴閣少談賓。"]'),
('yuding-11','洛中送崔司業使君扶侍赴唐州','劉禹錫','唐','御定全唐诗','yuding','','[]','綠野芳城路，殘春柳絮飛。風鳴驌驦馬，日照老萊衣。',48,'御定全唐詩/json/357.json','["綠野芳城路，殘春柳絮飛。風鳴驌驦馬，日照老萊衣。", "洛苑魚書至，江村雁戶歸。相思望淮水，雙鯉不應稀。"]'),
('yuding-12','送李友路秀才赴舉','劉禹錫','唐','御定全唐诗','yuding','','[]','誰憐相門子，不語望秋山。生長綺紈內，辛勤筆硯間。',48,'御定全唐詩/json/357.json','["誰憐相門子，不語望秋山。生長綺紈內，辛勤筆硯間。", "榮親在名字，好學棄官班。佇俟明年桂，高堂開笑顏。"]'),
('yuding-13','送從弟郎中赴浙西','劉禹錫','唐','御定全唐诗','yuding','','[]','銜命出尚書，新恩換使車。漢庭無右者，梁苑重歸歟。',48,'御定全唐詩/json/357.json','["銜命出尚書，新恩換使車。漢庭無右者，梁苑重歸歟。", "又食建業水，曾依京口居。共經何限事，賓主兩如初。"]'),
('yuding-14','送元上人歸稽亭','劉禹錫','唐','御定全唐诗','yuding','','[]','重疊稽亭路，山僧歸獨行。遠峰斜日影，本寺舊鐘聲。',48,'御定全唐詩/json/357.json','["重疊稽亭路，山僧歸獨行。遠峰斜日影，本寺舊鐘聲。", "徒侶問新事，煙雲愴別情。應誇乞食處，踏遍鳳凰城。"]'),
('yuding-15','贈別君素上人詩','劉禹錫','唐','御定全唐诗','yuding','','[]','窮巷唯秋草，高僧獨扣門。相歡如舊識，問法到無言。',48,'御定全唐詩/json/357.json','["窮巷唯秋草，高僧獨扣門。相歡如舊識，問法到無言。", "水為風生浪，珠非塵可昏。悟來皆是道，此別不銷魂。"]'),
('yuding-16','送深法師游南嶽','劉禹錫','唐','御定全唐诗','yuding','','[]','師在白雲鄉，名登善法堂。十方傳句偈，八部會壇場。',48,'御定全唐詩/json/357.json','["師在白雲鄉，名登善法堂。十方傳句偈，八部會壇場。", "飛錫無定所，寶書留舊房。唯應銜果雁，相送至衡陽。"]'),
('yuding-17','贈別約師','劉禹錫','唐','御定全唐诗','yuding','','[]','師逢吳興守，相伴住禪扃。春雨同栽樹，秋燈對講經。',48,'御定全唐詩/json/357.json','["師逢吳興守，相伴住禪扃。春雨同栽樹，秋燈對講經。", "廬山曾結社，桂水遠揚舲。話舊還惆悵，天南望柳星。"]'),
('yuding-18','秋日過鴻舉法師寺院，便送歸江陵','劉禹錫','唐','御定全唐诗','yuding','','[]','看畫長廊遍，尋僧一徑幽。小池兼鶴淨，古木帶蟬秋。',48,'御定全唐詩/json/357.json','["看畫長廊遍，尋僧一徑幽。小池兼鶴淨，古木帶蟬秋。", "客至茶煙起，禽歸講席收。浮杯明日去，相望水悠悠。"]'),
('yuding-19','春日退朝','劉禹錫','唐','御定全唐诗','yuding','','[]','紫陌夜來雨，南山朝下看。戟枝迎日動，閣影助松寒。',48,'御定全唐詩/json/357.json','["紫陌夜來雨，南山朝下看。戟枝迎日動，閣影助松寒。", "瑞氣轉綃縠，遊光泛波瀾。禦溝新柳色，處處拂歸鞍。"]'),
('yuding-20','蜀先主廟','劉禹錫','唐','御定全唐诗','yuding','','[]','天地英雄氣，千秋尚凜然。勢分三足鼎，業複五銖錢。',48,'御定全唐詩/json/357.json','["天地英雄氣，千秋尚凜然。勢分三足鼎，業複五銖錢。", "得相能開國，生兒不象賢。淒涼蜀故妓，來舞魏宮前。"]'),
('yuding-21','經東都安國觀九仙公主舊院作','劉禹錫','唐','御定全唐诗','yuding','','[]','仙院禦溝東，今來事不同。門開青草日，樓閉綠楊風。',48,'御定全唐詩/json/357.json','["仙院禦溝東，今來事不同。門開青草日，樓閉綠楊風。", "將犬升天路，披雲赴月宮。武皇曾駐蹕，親問主人翁。"]'),
('yuding-22','觀八陣圖','劉禹錫','唐','御定全唐诗','yuding','','[]','軒皇傳上略，蜀相運神機。水落龍蛇出，沙平鵝鸛飛。',48,'御定全唐詩/json/357.json','["軒皇傳上略，蜀相運神機。水落龍蛇出，沙平鵝鸛飛。", "波濤無動勢，鱗介避餘威。會有知兵者，臨流指是非。"]'),
('yuding-23','八月十五日夜玩月','劉禹錫','唐','御定全唐诗','yuding','','[]','天將今夜月，一遍洗寰瀛。暑退九霄淨，秋澄萬景清。',48,'御定全唐詩/json/357.json','["天將今夜月，一遍洗寰瀛。暑退九霄淨，秋澄萬景清。", "星辰讓光彩，風露發晶英。能變人間世，翛然是玉京。"]'),
('yuding-24','太和戊申歲大有年詔賜百僚出城觀秋稼謹書盛事以俟釆詩者','劉禹錫','唐','御定全唐诗','yuding','','[]','長安銅雀鳴，秋稼與雲平。玉燭調寒暑，金風報順成。',48,'御定全唐詩/json/357.json','["長安銅雀鳴，秋稼與雲平。玉燭調寒暑，金風報順成。", "川原呈上瑞，恩澤賜閑行。欲反重城掩，猶聞歌吹聲。"]'),
('yuding-25','金陵懷古','劉禹錫','唐','御定全唐诗','yuding','','[]','潮滿冶城渚，日斜征虜亭。蔡洲新草綠，幕府舊煙青。',48,'御定全唐詩/json/357.json','["潮滿冶城渚，日斜征虜亭。蔡洲新草綠，幕府舊煙青。", "興廢由人事，山川空地形。後庭花一曲，幽怨不堪聽。"]'),
('yuding-26','晝居池上亭獨吟','劉禹錫','唐','御定全唐诗','yuding','','[]','日午樹陰正，獨吟池上亭。靜看蜂教誨，閑想鶴儀形。',48,'御定全唐詩/json/357.json','["日午樹陰正，獨吟池上亭。靜看蜂教誨，閑想鶴儀形。", "法酒調神氣，清琴入性靈。浩然機已息，几杖複何銘。"]'),
('yuding-27','分司東都蒙襄陽李司徒相公書問因以奉寄','劉禹錫','唐','御定全唐诗','yuding','','[]','早忝金馬客，晚為商洛翁。知名四海內，多病一生中。',48,'御定全唐詩/json/357.json','["早忝金馬客，晚為商洛翁。知名四海內，多病一生中。", "舉世往還盡，何人心事同。幾時登峴首，恃舊揖三公。"]'),
('yuding-28','門下相公榮加冊命，天下同歡忝沐眷私，輒感申賀','劉禹錫','唐','御定全唐诗','yuding','','[]','冊命出宸衷，官儀自古崇。特膺平土拜，光贊格天功。',48,'御定全唐詩/json/357.json','["冊命出宸衷，官儀自古崇。特膺平土拜，光贊格天功。", "再佩扶陽印，常乘鮑氏驄。七賢遺老在，猶得詠清風。"]'),
('yuding-29','病中一二禪客見問，因以謝之','劉禹錫','唐','御定全唐诗','yuding','','[]','勞動諸賢者，同來問病夫。添爐烹雀舌，灑水淨龍須。',48,'御定全唐詩/json/357.json','["勞動諸賢者，同來問病夫。添爐烹雀舌，灑水淨龍須。", "身是芭蕉喻，行須筇竹扶。醫王有妙藥，能乞一丸無。"]'),
('yuding-30','秋江晚泊','劉禹錫','唐','御定全唐诗','yuding','','[]','長泊起秋色，空江涵霽暉。暮霞千萬狀，賓鴻次第飛。',48,'御定全唐詩/json/357.json','["長泊起秋色，空江涵霽暉。暮霞千萬狀，賓鴻次第飛。", "古戍見旗迥，荒村聞犬稀。軻峨艑上客，勸酒夜相依。"]'),
('yuding-31','步出武陵東亭臨江寓望','劉禹錫','唐','御定全唐诗','yuding','','[]','鷹至感風候，霜餘變林麓。孤帆帶日來，寒江轉沙曲。',48,'御定全唐詩/json/357.json','["鷹至感風候，霜餘變林麓。孤帆帶日來，寒江轉沙曲。", "戍搖旗影動，津晚櫓聲促。月上彩霞收，漁歌遠相續。"]'),
('yuding-32','秋日送客至潛水驛','劉禹錫','唐','御定全唐诗','yuding','','[]','候吏立沙際，田家連竹溪。楓林社日鼓，茅屋午時雞。',48,'御定全唐詩/json/357.json','["候吏立沙際，田家連竹溪。楓林社日鼓，茅屋午時雞。", "鵲噪晚禾地，蝶飛秋草畦。驛樓宮樹近，疲馬再三嘶。"]'),
('yuding-33','湖州崔郎中曹長寄三癖詩自言癖在詩與琴酒其詞逸而高吟詠不足昔柳吳興亭皋隴首之句王融書之白團扇故為四韻以謝之','劉禹錫','唐','御定全唐诗','yuding','','[]','視事畫屏中，自稱三癖翁。管弦泛春渚，旌旆拂晴虹。',48,'御定全唐詩/json/357.json','["視事畫屏中，自稱三癖翁。管弦泛春渚，旌旆拂晴虹。", "酒對青山月，琴韻白蘋風。會書團扇上，知君文字工。"]'),
('yuding-34','為郎分司寄上都同舍','劉禹錫','唐','御定全唐诗','yuding','','[]','籍通金馬門，家在銅駝陌。省闥晝無塵，宮樹朝凝碧。',48,'御定全唐詩/json/357.json','["籍通金馬門，家在銅駝陌。省闥晝無塵，宮樹朝凝碧。", "荒街淺深轍，古渡潺湲石。唯有嵩丘雲，堪誇早朝客。"]'),
('yuding-35','登陝州北樓卻憶京師親友','劉禹錫','唐','御定全唐诗','yuding','','[]','獨上百尺樓，目窮思亦愁。初日遍露草，野田荒悠悠。',48,'御定全唐詩/json/357.json','["獨上百尺樓，目窮思亦愁。初日遍露草，野田荒悠悠。", "塵息長道白，林清宿煙收。回首雲深處，永懷鄉舊遊。"]'),
('yuding-36','途中早發','劉禹錫','唐','御定全唐诗','yuding','','[]','中庭望啟明，促促事晨征。寒樹鳥初動，霜橋人未行。',48,'御定全唐詩/json/357.json','["中庭望啟明，促促事晨征。寒樹鳥初動，霜橋人未行。", "水流白煙起，日上彩霞生。隱士應高枕，無人問姓名。"]'),
('yuding-37','陝州河亭陪韋五大夫雪後眺望因以留別與韋有布衣之舊一別二紀經遷貶而歸','劉禹錫','唐','御定全唐诗','yuding','','[]','雪霽太陽津，城池表裏春。河流添馬頰，原色動龍鱗。',48,'御定全唐詩/json/357.json','["雪霽太陽津，城池表裏春。河流添馬頰，原色動龍鱗。", "萬里獨歸客，一杯逢故人。登高向西望，關路正飛塵。"]'),
('yuding-38','城東閒遊','劉禹錫','唐','御定全唐诗','yuding','','[]','借問池台主，多居要路津。千金買絕境，永日屬閒人。',48,'御定全唐詩/json/357.json','["借問池台主，多居要路津。千金買絕境，永日屬閒人。", "竹徑縈紆入，花林委曲巡。斜陽眾客散，空鎖一園春。"]'),
('yuding-39','罷郡歸洛陽閒居','劉禹錫','唐','御定全唐诗','yuding','','[]','十年江海守，旦夕有歸心。及此西還日，空成東武吟。',48,'御定全唐詩/json/357.json','["十年江海守，旦夕有歸心。及此西還日，空成東武吟。", "花間數杯酒，月下一張琴。聞說功名事，依前惜寸陰。"]'),
('yuding-40','晚泊牛渚','劉禹錫','唐','御定全唐诗','yuding','','[]','蘆葦晚風起，秋江鱗甲生。殘霞忽變色，遊雁有餘聲。',48,'御定全唐詩/json/357.json','["蘆葦晚風起，秋江鱗甲生。殘霞忽變色，遊雁有餘聲。", "戍鼓音響絕，漁家燈火明。無人能詠史，獨自月中行。"]'),
('yuding-41','宿誠禪師山房題贈二首','劉禹錫','唐','御定全唐诗','yuding','','[]','宴坐白雲端，清江直下看。來人望金刹，講席繞香壇。',96,'御定全唐詩/json/357.json','["宴坐白雲端，清江直下看。來人望金刹，講席繞香壇。", "虎嘯夜林動，鼉鳴秋澗寒。眾音徒起滅，心在淨中觀。", "不出孤峰上，人間四十秋。視身如傳舍，閱世似東流。", "法為因緣立，心從次第修。中宵問真偈，有住是吾憂。"]'),
('yuding-42','贈澧州高大夫司馬霞寓','劉禹錫','唐','御定全唐诗','yuding','','[]','前年牧錦城，馬蹋血泥行。千里追戎首，三軍許勇名。',48,'御定全唐詩/json/357.json','["前年牧錦城，馬蹋血泥行。千里追戎首，三軍許勇名。", "殘兵疑鶴唳，空壘辯烏聲。一誤雲中級，南游湘水清。"]'),
('yuding-43','聞董評事疾因以書贈','劉禹錫','唐','御定全唐诗','yuding','','[]','繁露傳家學，青蓮譯梵書。火風乖四大，文字廢三餘。',48,'御定全唐詩/json/357.json','["繁露傳家學，青蓮譯梵書。火風乖四大，文字廢三餘。", "欹枕晝眠靜，折巾秋鬢疏。武皇思視草，誰許茂陵居。"]'),
('yuding-44','詠庭梅寄人','劉禹錫','唐','御定全唐诗','yuding','','[]','早花常犯寒，繁實常苦酸。何事上春日，坐令芳意闌。',48,'御定全唐詩/json/357.json','["早花常犯寒，繁實常苦酸。何事上春日，坐令芳意闌。", "夭桃定相笑，遊妓肯回看。君問調金鼎，方知正味難。"]'),
('yuding-45','德宗神武孝文皇帝挽歌二首','劉禹錫','唐','御定全唐诗','yuding','','[]','出震清多難，乘時播大鈞。操弦調六氣，揮翰動三辰。',96,'御定全唐詩/json/357.json','["出震清多難，乘時播大鈞。操弦調六氣，揮翰動三辰。", "運偶升天日，哀深率土人。瑤池無轍跡，誰見屬車塵。", "鳳翣擁銘旌，威遲異吉行。漢儀陳秘器，楚挽咽繁聲。", "駐綍辭清廟，凝笳背直城。唯應留內傳，知是向蓬瀛。"]'),
('yuding-46','敬宗睿武昭湣孝皇帝挽歌三首','劉禹錫','唐','御定全唐诗','yuding','','[]','寶曆方無限，仙期忽有涯。事親崇漢禮，傳聖法殷家。',144,'御定全唐詩/json/357.json','["寶曆方無限，仙期忽有涯。事親崇漢禮，傳聖法殷家。", "晚出芙蓉闕，春歸棠棣華。玉輪今日動，不是畫雲車。", "任賢勞夢寐，登位富春秋。欲遂東人幸，甯虞杞國憂。", "長楊收羽騎，太液泊龍舟。惟有衣冠在，年年愴月遊。", "講學金華殿，親耕鉤盾田。侍臣容諫獵，方士信求仙。", "虹影俄侵日，龍髯不上天。空餘水銀海，長照夜燈前。"]'),
('yuding-47','文宗元聖昭獻孝皇帝挽歌三首','劉禹錫','唐','御定全唐诗','yuding','','[]','繼體三才理，承顏九族親。禹功留海內，殷曆付天倫。',144,'御定全唐詩/json/357.json','["繼體三才理，承顏九族親。禹功留海內，殷曆付天倫。", "調露曲常在，秋風詞尚新。本支方百代，先讓棣華春。", "月落宮車動，風淒儀仗閑。路唯瞻鳳翣，人尚想龍顏。", "禦宇方無事，乘雲遂不還。聖情悲望處，沉日下西山。", "享國十五載，升天千萬年。龍鑣仙路遠，騎吹禮容全。", "日下初陵外，人悲舊劍前。周南有遺老，掩淚望秦川。"]'),
('yuding-48','故相國燕國公于司空挽歌二首','劉禹錫','唐','御定全唐诗','yuding','','[]','雕弓封舊國，黑弰繼前功。十年鎮南雍，九命作司空。',96,'御定全唐詩/json/357.json','["雕弓封舊國，黑弰繼前功。十年鎮南雍，九命作司空。", "池台樂事盡，簫鼓葬儀雄。一代英豪氣，曉散白楊風。", "陰山貴公子，來葬五陵西。前馬悲無主，猶帶朔風嘶。", "漢水晉山郭，襄陽白銅鞮。至今有遺愛，日暮人淒淒。"]'),
('yuding-49','傷丘中丞','劉禹錫','唐','御定全唐诗','yuding','','[]','鄴下殺才子，蒼茫冤氣凝。枯楊映漳水，野火上西陵。',48,'御定全唐詩/json/357.json','["鄴下殺才子，蒼茫冤氣凝。枯楊映漳水，野火上西陵。", "馬鬣今無所，龍門昔共登。何人為吊客，唯是有青蠅。"]'),
('yuding-50','河南觀察使故相國袁公挽歌三首','劉禹錫','唐','御定全唐诗','yuding','','[]','五驅龍虎節，一入鳳凰池。令尹自無喜，羊公人不疑。',144,'御定全唐詩/json/357.json','["五驅龍虎節，一入鳳凰池。令尹自無喜，羊公人不疑。", "天歸京兆日，葉下洞庭時。湘水秋風至，淒涼吹素旗。", "丹旐發江皋，人悲雁亦號。湘南罷亥市，漢上改詞曹。", "表墓雙碑立，尊名一字褒。嘗聞平楚獄，為報裏門高。", "返葬三千里，荊衡達帝畿。逢人即故吏，拜奠盡沾衣。", "地得青烏相，賓驚白鶴飛。五公碑尚在，今日亦同歸。"]'),
('yuding-51','哭王僕射相公','劉禹錫','唐','御定全唐诗','yuding','','[]','子侯一日病，滕公千載歸。門庭愴已變，風物澹無輝。',48,'御定全唐詩/json/357.json','["子侯一日病，滕公千載歸。門庭愴已變，風物澹無輝。", "群吏謁新府，舊賓沾素衣。歌堂忽暮哭，賀雀盡驚飛。"]'),
('yuding-52','傷韋賓客','劉禹錫','唐','御定全唐诗','yuding','','[]','韋公八十餘，位至六尚書。五福唯無富，一生誰得如。',48,'御定全唐詩/json/357.json','["韋公八十餘，位至六尚書。五福唯無富，一生誰得如。", "桂枝攀最久，蘭省出仍初。海內時流盡，何人動素車。"]'),
('yuding-53','再經故元九相公宅池上作','劉禹錫','唐','御定全唐诗','yuding','','[]','故池春又至，一到一傷情。雁鶩群猶下，蛙螟衣已生。',48,'御定全唐詩/json/357.json','["故池春又至，一到一傷情。雁鶩群猶下，蛙螟衣已生。", "竹叢身後長，台勢雨來傾。六尺孤安在，人間未有名。"]'),
('yuding-54','請告東歸發灞橋卻寄諸僚友','劉禹錫','唐','御定全唐诗','yuding','','[]','征徒出灞涘，回首傷如何。故人雲雨散，滿目山川多。',48,'御定全唐詩/json/357.json','["征徒出灞涘，回首傷如何。故人雲雨散，滿目山川多。", "行車無停軌，流景同迅波。前歡漸成昔，感歎益勞歌。"]'),
('yuding-55','初至長安','劉禹錫','唐','御定全唐诗','yuding','','[]','左遷凡二紀，重見帝城春。老大歸朝客，平安出嶺人。',48,'御定全唐詩/json/357.json','["左遷凡二紀，重見帝城春。老大歸朝客，平安出嶺人。", "每行經舊處，卻想似前身。不改南山色，其餘事事新。"]'),
('yuding-56','歲杪將發楚州呈樂天','劉禹錫','唐','御定全唐诗','yuding','','[]','楚澤雪初霽，楚城春欲歸。清淮變寒色，遠樹含清暉。',48,'御定全唐詩/json/357.json','["楚澤雪初霽，楚城春欲歸。清淮變寒色，遠樹含清暉。", "原野已多思，風霜潛減威。與君同旅雁，北向刷毛衣。"]'),
('yuding-57','鶴歎二首','劉禹錫','唐','御定全唐诗','yuding','','[]','寂寞一雙鶴，主人在西京。故巢吳苑樹，深院洛陽城。',96,'御定全唐詩/json/357.json','["寂寞一雙鶴，主人在西京。故巢吳苑樹，深院洛陽城。", "徐引竹間步，遠含雲外情。誰憐好風月，鄰舍夜吹笙。", "丹頂宜承日，霜翎不染泥。愛池能久立，看月未成棲。", "一院春草長，三山歸路迷。主人朝謁早，貪養汝南雞。"]'),
('yuding-58','答白刑部聞新蟬','劉禹錫','唐','御定全唐诗','yuding','','[]','蟬聲未發前，已自感流年。一入淒涼耳，如聞斷續弦。',48,'御定全唐詩/json/357.json','["蟬聲未發前，已自感流年。一入淒涼耳，如聞斷續弦。", "晴清依露葉，晚急畏霞天。何事秋卿詠，逢時亦悄然。"]'),
('yuding-59','和裴相公寄白侍郎求雙鶴','劉禹錫','唐','御定全唐诗','yuding','','[]','皎皎華亭鶴，來隨太守船。青雲意長在，滄海別經年。',48,'御定全唐詩/json/357.json','["皎皎華亭鶴，來隨太守船。青雲意長在，滄海別經年。", "留滯清洛苑，裴回明月天。何如鳳池上，雙舞入祥煙。"]'),
('yuding-60','終南秋雪','劉禹錫','唐','御定全唐诗','yuding','','[]','南嶺見秋雪，千門生早寒。閒時駐馬望，高處捲簾看。',48,'御定全唐詩/json/357.json','["南嶺見秋雪，千門生早寒。閒時駐馬望，高處捲簾看。", "霧散瓊枝出，日斜鉛粉殘。偏宜曲江上，倒影入清瀾。"]'),
('yuding-61','和樂天早寒','劉禹錫','唐','御定全唐诗','yuding','','[]','雨引苔侵壁，風驅葉擁階。久留閑客話，宿請老僧齋。',48,'御定全唐詩/json/357.json','["雨引苔侵壁，風驅葉擁階。久留閑客話，宿請老僧齋。", "酒甕新陳接，書簽次第排。翛然自有處，搖落不傷懷。"]'),
('yuding-62','曲江春望','劉禹錫','唐','御定全唐诗','yuding','','[]','鳳城煙雨歇，萬象含佳氣。酒後人倒狂，花時天似醉。',48,'御定全唐詩/json/357.json','["鳳城煙雨歇，萬象含佳氣。酒後人倒狂，花時天似醉。", "三春車馬客，一代繁華地。何事獨傷懷，少年曾得意。"]'),
('yuding-63','同樂天和微之深春二十首','劉禹錫','唐','御定全唐诗','yuding','','[]','何處深春好，春深萬乘家。宮門皆映柳，輦路盡穿花。',576,'御定全唐詩/json/357.json','["何處深春好，春深萬乘家。宮門皆映柳，輦路盡穿花。", "池色連天漢，城形象帝車。旌旗暖風裏，獵獵向西斜。", "何處深春好，春深阿母家。瑤池長不夜，珠樹正開花。", "橋峻通星渚，樓暄近日車。層城十二闕，相對日西斜。", "何處深春好，春深執政家。恩光貪捧日，貴重不看花。", "玉饌堂交印，沙堤柱礙車。多門一已閉，直道更無斜。", "何處深春好，春深大鎮家。前旌光照日，後騎蹙成花。", "節院收衙隊，球場簇看車。廣筵歌舞散，書號夕陽斜。", "何處深春多，春深貴戚家。櫪嘶無價馬，庭發有名花。", "欲進宮人食，先熏命婦車。晚歸長帶酒，冠蓋任傾斜。", "何處深春好，春深恩澤家。爐添龍腦炷，綬結虎頭花。", "賓客珠成履，嬰孩錦縛車。畫堂簾幕外，來去燕飛斜。", "何處深春好，春深京兆家。人眉新柳葉，馬色醉桃花。", "盜息無鳴鼓，朝回自走車。能令帝城外，不敢徑由斜。", "何處深春好，春深刺史家。夜闌猶命樂，雨甚亦尋花。", "傲客多憑酒，新姬苦上車。公門吏散後，風擺戟衣斜。", "何處深春好，春深羽客家。芝田繞舍色，杏樹滿山花。", "雲是淮王宅，風為列子車。古壇操簡處，一徑入林斜。", "何處深春好，春深小隱家。芟庭留野菜，撼樹去狂花。", "醉酒一千日，貯書三十車。雉衣從露體，不敢有餘斜。", "何處深春好，春深富室家。唯多貯金帛，不擬負鶯花。", "國樂呼聯轡，行廚載滿車。歸來看理曲，燈下寶釵斜。", "何處深春好，春深豪士家。多沽味濃酒，貴買色深花。", "已臂鷹隨馬，連催妓上車。城南踏青處，村落逐原斜。"]'),
('yuding-64','贈眼醫婆羅門僧','劉禹錫','唐','御定全唐诗','yuding','','[]','三秋傷望眼，終日哭途窮。兩目今先暗，中年似老翁。',48,'御定全唐詩/json/357.json','["三秋傷望眼，終日哭途窮。兩目今先暗，中年似老翁。", "看朱漸成碧，羞日不禁風。師有金篦術，如何為發蒙。"]'),
('yuding-65','海門潮別浩初師','劉禹錫','唐','御定全唐诗','yuding','','[]','前日過蕭寺，看師上講筵。都上禮白足，施者散金錢。',48,'御定全唐詩/json/357.json','["前日過蕭寺，看師上講筵。都上禮白足，施者散金錢。", "方便無非教，經行不廢禪。還知習居士，發論侍彌天。"]'),
('yuding-0','始聞蟬有懷白賓客去歲白有聞蟬見寄詩云祗應催我老兼遣報君知之句','劉禹錫','唐','御定全唐诗','yuding','','[]','蟬韻極清切，始聞何處悲。人含不平意，景值欲秋時。',48,'御定全唐詩/json/358.json','["蟬韻極清切，始聞何處悲。人含不平意，景值欲秋時。", "此歲方晼晚，誰家無別離。君言催我老，已是去年詩。"]'),
('yuding-1','贈樂天','劉禹錫','唐','御定全唐诗','yuding','','[]','一別舊遊盡，相逢俱涕零。在人雖晚達，于樹似冬青。',48,'御定全唐詩/json/358.json','["一別舊遊盡，相逢俱涕零。在人雖晚達，于樹似冬青。", "痛飲連宵醉，狂吟滿坐聽。終期拋印綬，共占少微星。"]'),
('yuding-2','到郡未浹日登西樓見樂天題詩因即事以寄','劉禹錫','唐','御定全唐诗','yuding','','[]','湖上收宿雨，城中無晝塵。樓依新柳貴，池帶亂苔青。',48,'御定全唐詩/json/358.json','["湖上收宿雨，城中無晝塵。樓依新柳貴，池帶亂苔青。", "雲水正一望，簿書來繞身。煙波洞庭路，愧彼扁舟人。"]'),
('yuding-3','秋夕不寐寄樂天','劉禹錫','唐','御定全唐诗','yuding','','[]','洞戶夜簾卷，華堂秋簟清。螢飛過池影，蛩思繞階聲。',48,'御定全唐詩/json/358.json','["洞戶夜簾卷，華堂秋簟清。螢飛過池影，蛩思繞階聲。", "老枕知將雨，高窗報欲明。何人諳此景，遠問白先生。"]'),
('yuding-4','冬日晨興寄樂天','劉禹錫','唐','御定全唐诗','yuding','','[]','庭樹曉禽動，郡樓殘點聲。燈挑紅燼落，酒暖白光生。',48,'御定全唐詩/json/358.json','["庭樹曉禽動，郡樓殘點聲。燈挑紅燼落，酒暖白光生。", "發少嫌梳利，顏衰恨鏡明。獨吟誰應和，須寄洛陽城。"]'),
('yuding-5','答樂天見憶','劉禹錫','唐','御定全唐诗','yuding','','[]','與老無期約，到來如等閒。偏傷朋友盡，移興子孫間。',48,'御定全唐詩/json/358.json','["與老無期約，到來如等閒。偏傷朋友盡，移興子孫間。", "筆底心無毒，杯前膽不豩。唯餘憶君夢，飛過武牢關。"]'),
('yuding-6','和樂天誚失婢榜者','劉禹錫','唐','御定全唐诗','yuding','','[]','把鏡朝猶在，添香夜不歸。鴛鴦拂瓦去，鸚鵡透籠飛。',48,'御定全唐詩/json/358.json','["把鏡朝猶在，添香夜不歸。鴛鴦拂瓦去，鸚鵡透籠飛。", "不逐張公子，即隨劉武威。新知正相樂，從此脫青衣。"]'),
('yuding-7','八月十五日夜半雲開然後玩月因書一時之景寄呈樂天','劉禹錫','唐','御定全唐诗','yuding','','[]','半夜碧雲收，中天素月流。開城邀好客，置酒賞清秋。',48,'御定全唐詩/json/358.json','["半夜碧雲收，中天素月流。開城邀好客，置酒賞清秋。", "影透衣香潤，光凝歌黛愁。斜輝猶可玩，移宴上西樓。"]'),
('yuding-8','秋日書懷寄白賓客','劉禹錫','唐','御定全唐诗','yuding','','[]','州遠雄無益，年高健亦衰。興情逢酒在，筋力上樓知。',48,'御定全唐詩/json/358.json','["州遠雄無益，年高健亦衰。興情逢酒在，筋力上樓知。", "蟬噪芳意盡，雁來愁望時。商山紫芝客，應不向秋悲。"]'),
('yuding-9','酬樂天初冬早寒見寄','劉禹錫','唐','御定全唐诗','yuding','','[]','乍起衣猶冷，微吟帽半欹。霜凝南屋瓦，雞唱後園枝。',48,'御定全唐詩/json/358.json','["乍起衣猶冷，微吟帽半欹。霜凝南屋瓦，雞唱後園枝。", "洛水碧雲曉，吳宮黃葉時。兩傳千里意，書劄不如詩。"]'),
('yuding-10','和令狐相公郡齋對紫薇花','劉禹錫','唐','御定全唐诗','yuding','','[]','明麗碧天霞，豐茸紫綬花。香聞荀令宅，豔入孝王家。',48,'御定全唐詩/json/358.json','["明麗碧天霞，豐茸紫綬花。香聞荀令宅，豔入孝王家。", "幾歲自榮樂，高情方歎嗟。有人移上苑，猶足占年華。"]'),
('yuding-11','令狐相公俯贈篇章斐然仰謝','劉禹錫','唐','御定全唐诗','yuding','','[]','鄂渚臨流別，梁園沖雪來。旅愁隨凍釋，歡意待花開。',48,'御定全唐詩/json/358.json','["鄂渚臨流別，梁園沖雪來。旅愁隨凍釋，歡意待花開。", "城曉烏頻起，池春雁欲回。飲和心自醉，何必管弦催。"]'),
('yuding-12','酬令狐相公早秋見寄','劉禹錫','唐','御定全唐诗','yuding','','[]','公來第四秋，樂國號無愁。軍士游書肆，商人占酒樓。',48,'御定全唐詩/json/358.json','["公來第四秋，樂國號無愁。軍士游書肆，商人占酒樓。", "熊羆交黑槊，賓客滿青油。今日文章主，梁王不姓劉。"]'),
('yuding-13','和令狐相公入潼關','劉禹錫','唐','御定全唐诗','yuding','','[]','寒光照旌節，關路曉無塵。吏謁前丞相，山迎舊主人。',48,'御定全唐詩/json/358.json','["寒光照旌節，關路曉無塵。吏謁前丞相，山迎舊主人。", "東瞻軍府靜，西望敕書頻。心共黃河水，同升天漢津。"]'),
('yuding-14','和令狐相公尋白閣老見留小飲因贈','劉禹錫','唐','御定全唐诗','yuding','','[]','傲士更逢酒，樂天仍對花。文章管星曆，情興占年華。',48,'御定全唐詩/json/358.json','["傲士更逢酒，樂天仍對花。文章管星曆，情興占年華。", "宦達翻思退，名高卻不誇。惟存浩然氣，相共賞煙霞。"]'),
('yuding-15','酬令狐相公雪中游玄都見憶','劉禹錫','唐','御定全唐诗','yuding','','[]','好雪動高情，心期在玉京。人披鶴氅出，馬踏象筵行。',48,'御定全唐詩/json/358.json','["好雪動高情，心期在玉京。人披鶴氅出，馬踏象筵行。", "照耀樓臺變，淋漓松桂清。玄都留五字，使入步虛聲。"]'),
('yuding-16','和令狐相公以司空裴相見招南亭看雪四韻','劉禹錫','唐','御定全唐诗','yuding','','[]','重門不下關，樞務有餘閑。上客同看雪，高亭盡見山。',48,'御定全唐詩/json/358.json','["重門不下關，樞務有餘閑。上客同看雪，高亭盡見山。", "瑞呈霄漢外，興入笑言間。知是平陽會，人人帶酒還。"]'),
('yuding-17','和鄆州令狐相公春晚對花','劉禹錫','唐','御定全唐诗','yuding','','[]','朱門退公後，高興對花枝。望闕無窮思，看書欲盡時。',48,'御定全唐詩/json/358.json','["朱門退公後，高興對花枝。望闕無窮思，看書欲盡時。", "含芳朝競發，凝豔晚相宜。人意殷勤惜，狂風豈得知。"]'),
('yuding-18','酬令狐相公春日言懷見寄','劉禹錫','唐','御定全唐诗','yuding','','[]','前陪看花處，鄰里近王昌。今想臨戎地，旌旗出汶陽。',48,'御定全唐詩/json/358.json','["前陪看花處，鄰里近王昌。今想臨戎地，旌旗出汶陽。", "營飛柳絮雪，門耀戟枝霜。東望清河水，心隨艑上郎。"]'),
('yuding-19','途次大梁雪中奉天平令狐相公書問兼示新什因思曩歲從此拜辭形於短篇以申仰謝','劉禹錫','唐','御定全唐诗','yuding','','[]','遠守宦情薄，故人書信來。共曾花下別，今獨雪中回。',48,'御定全唐詩/json/358.json','["遠守宦情薄，故人書信來。共曾花下別，今獨雪中回。", "紙尾得新什，眉頭還暫開。此時同雁鶩，池上一徘徊。"]'),
('yuding-20','酬令狐相公秋懷見寄','劉禹錫','唐','御定全唐诗','yuding','','[]','寂寞蟬聲靜，差池燕羽回。秋風憐越絕，朔氣想台駘。',48,'御定全唐詩/json/358.json','["寂寞蟬聲靜，差池燕羽回。秋風憐越絕，朔氣想台駘。", "相去數千里，無因同一杯。殷勤望飛雁，新自塞垣來。"]'),
('yuding-21','酬太原令狐相公見寄','劉禹錫','唐','御定全唐诗','yuding','','[]','書信來天外，瓊瑤滿匣中。衣冠南渡遠，旌節北門雄。',48,'御定全唐詩/json/358.json','["書信來天外，瓊瑤滿匣中。衣冠南渡遠，旌節北門雄。", "鶴唳華亭月，馬嘶榆塞風。山川幾千里，惟有兩心同。"]'),
('yuding-22','酬令狐相公歲暮遠懷見寄','劉禹錫','唐','御定全唐诗','yuding','','[]','別侶孤鶴怨，沖天威鳳歸。容光一以間，夢想是耶非。',48,'御定全唐詩/json/358.json','["別侶孤鶴怨，沖天威鳳歸。容光一以間，夢想是耶非。", "芳訊遠彌重，知音老更稀。不如湖上雁，北向整毛衣。"]'),
('yuding-23','酬令狐相公親仁郭家花下即事見寄','劉禹錫','唐','御定全唐诗','yuding','','[]','荀令園林好，山公遊賞頻。豈無花下侶，遠望眼中人。',48,'御定全唐詩/json/358.json','["荀令園林好，山公遊賞頻。豈無花下侶，遠望眼中人。", "斜日漸移影，落英紛委塵。一吟相思曲，惆悵江南春。"]'),
('yuding-24','酬令狐相公首夏閒居書懷見寄','劉禹錫','唐','御定全唐诗','yuding','','[]','蕙草芳未歇，綠槐陰已成。金罍唯獨酌，瑤瑟有離聲。',48,'御定全唐詩/json/358.json','["蕙草芳未歇，綠槐陰已成。金罍唯獨酌，瑤瑟有離聲。", "翔泳各殊勢，篇章空寄情。應憐三十載，未變使君名。"]'),
('yuding-25','酬令狐相公庭前白菊花謝偶書所懷見寄','劉禹錫','唐','御定全唐诗','yuding','','[]','數叢如雪色，一旦冒霜開。寒蕊差池落，清香斷續來。',48,'御定全唐詩/json/358.json','["數叢如雪色，一旦冒霜開。寒蕊差池落，清香斷續來。", "思深含別怨，芳謝惜年催。千里難同賞，看看又早梅。"]'),
('yuding-26','酬令狐相公季冬南郊宿齋見寄','劉禹錫','唐','御定全唐诗','yuding','','[]','壇下雪初霽，南城凍欲生。齋心祠上帝，高步領名卿。',48,'御定全唐詩/json/358.json','["壇下雪初霽，南城凍欲生。齋心祠上帝，高步領名卿。", "沐浴含芳澤，周旋聽佩聲。猶憐廣平守，寂寞竟何成。"]'),
('yuding-27','貞元中侍郎舅氏牧華州時余再忝科第前後由華覲謁陪登伏毒寺屢焉亦曾賦詩題於梁棟今典馮翊暇日登樓南望三峰浩然生思追想昔年之事因成篇題舊寺','劉禹錫','唐','御定全唐诗','yuding','','[]','曾作關中客，頻經伏毒岩。晴煙沙苑樹，晚日渭川帆。',48,'御定全唐詩/json/358.json','["曾作關中客，頻經伏毒岩。晴煙沙苑樹，晚日渭川帆。", "昔是青春貌，今悲白雪髯。郡樓空一望，含意卷高簾。"]'),
('yuding-28','酬令狐相公杏園花下飲有懷見寄','劉禹錫','唐','御定全唐诗','yuding','','[]','年年曲江望，花發即經過。未飲心先醉，臨風思倍多。',48,'御定全唐詩/json/358.json','["年年曲江望，花發即經過。未飲心先醉，臨風思倍多。", "三春看又盡，兩地欲如何。日望長安道，空成勞者歌。"]'),
('yuding-29','令狐相公見示題洋州崔侍郎宅雙木瓜花頃接侍郎同舍陪宴樹下吟玩來什輒成和章','劉禹錫','唐','御定全唐诗','yuding','','[]','金牛蜀路遠，玉樹帝城春。榮耀生華館，逢迎欠主人。',48,'御定全唐詩/json/358.json','["金牛蜀路遠，玉樹帝城春。榮耀生華館，逢迎欠主人。", "簾前疑小雪，牆外麗行塵。來去皆回首，情深是德鄰。"]'),
('yuding-30','和令狐相公春早朝回鹽鐵使院中作','劉禹錫','唐','御定全唐诗','yuding','','[]','柳動禦溝清，威遲堤上行。城隅日未過，山色雨初晴。',48,'御定全唐詩/json/358.json','["柳動禦溝清，威遲堤上行。城隅日未過，山色雨初晴。", "鶯避傳呼起，花臨府署明。簿書盈幾案，要自有高情。"]'),
('yuding-31','和令狐僕射相公題龍回寺','劉禹錫','唐','御定全唐诗','yuding','','[]','茲地回鑾日，皇家禪聖時。路無胡馬跡，人識漢官儀。',48,'御定全唐詩/json/358.json','["茲地回鑾日，皇家禪聖時。路無胡馬跡，人識漢官儀。", "天子旌旗度，法王龍象隨。知懷去家歎，經此益遲遲。"]'),
('yuding-32','令狐相公頻示新什早春南望遐想漢中因抒短章以寄情愫','劉禹錫','唐','御定全唐诗','yuding','','[]','軍城臨漢水，旌旆起春風。遠思見江草，歸心看塞鴻。',48,'御定全唐詩/json/358.json','["軍城臨漢水，旌旆起春風。遠思見江草，歸心看塞鴻。", "野花沿古道，新葉映行宮。惟有詩兼酒，朝朝兩不同。"]'),
('yuding-33','和令狐相公詠梔子花','劉禹錫','唐','御定全唐诗','yuding','','[]','蜀國花已盡，越桃今已開。色疑瓊樹倚，香似玉京來。',48,'御定全唐詩/json/358.json','["蜀國花已盡，越桃今已開。色疑瓊樹倚，香似玉京來。", "且賞同心處，那憂別葉催。佳人如擬詠，何必待寒梅。"]'),
('yuding-34','酬令狐相公新蟬見寄','劉禹錫','唐','御定全唐诗','yuding','','[]','相去三千里，聞蟬同此時。清吟曉露葉，愁噪夕陽枝。',48,'御定全唐詩/json/358.json','["相去三千里，聞蟬同此時。清吟曉露葉，愁噪夕陽枝。", "忽爾弦斷絕，俄聞管參差。洛橋碧雲晚，西望佳人期。"]'),
('yuding-35','酬樂天閑臥見寄','劉禹錫','唐','御定全唐诗','yuding','','[]','散誕向陽眠，將閑敵地仙。詩情茶助爽，藥力酒能宣。',48,'御定全唐詩/json/358.json','["散誕向陽眠，將閑敵地仙。詩情茶助爽，藥力酒能宣。", "風碎竹間日，露明池底天。同年未同隱，緣欠買山錢。"]'),
('yuding-36','酬樂天小亭寒夜有懷','劉禹錫','唐','御定全唐诗','yuding','','[]','寒夜陰雲起，疏林宿鳥驚。斜風閃燈影，迸雪打窗聲。',48,'御定全唐詩/json/358.json','["寒夜陰雲起，疏林宿鳥驚。斜風閃燈影，迸雪打窗聲。", "竟夕不能寐，同年知此情。漢皇無奈老，何況本書生。"]'),
('yuding-37','將之官留辭裴令公留守','劉禹錫','唐','御定全唐诗','yuding','','[]','祖帳臨伊水，前旌指渭河。風煙裏數少，雲雨別情多。',48,'御定全唐詩/json/358.json','["祖帳臨伊水，前旌指渭河。風煙裏數少，雲雨別情多。", "重疊受恩久，邅回如命何。東山與東閣，終異再經過。"]'),
('yuding-38','酬喜相遇同州與樂天替代','劉禹錫','唐','御定全唐诗','yuding','','[]','舊托松心契，新交竹使符。行年同甲子，筋力羨丁夫。',48,'御定全唐詩/json/358.json','["舊托松心契，新交竹使符。行年同甲子，筋力羨丁夫。", "別後詩成帙，攜來酒滿壺。今朝停五馬，不獨為羅敷。"]'),
('yuding-39','閑坐憶樂天以詩問酒熟未','劉禹錫','唐','御定全唐诗','yuding','','[]','案頭開縹帙，肘後檢青囊。唯有達生理，應無治老方。',48,'御定全唐詩/json/358.json','["案頭開縹帙，肘後檢青囊。唯有達生理，應無治老方。", "減書存眼力，省事養心王。君酒何時熟，相攜入醉鄉。"]'),
('yuding-40','秋中暑退贈樂天','劉禹錫','唐','御定全唐诗','yuding','','[]','暑服宜秋著，清琴入夜彈。人情皆向菊，風意欲摧蘭。',48,'御定全唐詩/json/358.json','["暑服宜秋著，清琴入夜彈。人情皆向菊，風意欲摧蘭。", "歲稔貧心泰，天涼病體安。相逢取次第，卻甚少年歡。"]'),
('yuding-41','樂天池館夏景方妍白蓮初開彩舟空泊唯邀緇侶因以戲之','劉禹錫','唐','御定全唐诗','yuding','','[]','池館今正好，主人何寂然。白蓮方出水，碧樹未鳴蟬。',48,'御定全唐詩/json/358.json','["池館今正好，主人何寂然。白蓮方出水，碧樹未鳴蟬。", "靜室宵聞磬，齋廚晚絕煙。蕃僧如共載，應不是神仙。"]'),
('yuding-42','酬樂天感秋涼見寄','劉禹錫','唐','御定全唐诗','yuding','','[]','庭晚初辨色，林秋微有聲。槿衰猶強笑，蓮迥卻多情。',48,'御定全唐詩/json/358.json','["庭晚初辨色，林秋微有聲。槿衰猶強笑，蓮迥卻多情。", "簷燕歸心動，鞲鷹俊氣生。閒人占閑景，酒熟且同傾。"]'),
('yuding-43','秋晚新晴夜月如練有懷樂天','劉禹錫','唐','御定全唐诗','yuding','','[]','雨歇晚霞明，風調夜景清。月高微暈散，雲薄細鱗生。',48,'御定全唐詩/json/358.json','["雨歇晚霞明，風調夜景清。月高微暈散，雲薄細鱗生。", "露草百蟲思，秋林千葉聲。相望一步地，脈脈萬重情。"]'),
('yuding-44','新秋對月寄樂天','劉禹錫','唐','御定全唐诗','yuding','','[]','月露發光彩，此時方見秋。夜涼金氣應，天靜火星流。',48,'御定全唐詩/json/358.json','["月露發光彩，此時方見秋。夜涼金氣應，天靜火星流。", "蛩響偏依井，螢飛直過樓。相知盡白首，清景複追遊。"]'),
('yuding-45','酬樂天小台晚坐見憶','劉禹錫','唐','御定全唐诗','yuding','','[]','小台堪遠望，獨上清秋時。有酒無人勸，看山只自知。',48,'御定全唐詩/json/358.json','["小台堪遠望，獨上清秋時。有酒無人勸，看山只自知。", "幽禽囀新竹，孤蓮落靜池。高門勿遽掩，好客無前期。"]'),
('yuding-46','早秋雨後寄樂天','劉禹錫','唐','御定全唐诗','yuding','','[]','夜雲起河漢，朝雨灑高林。梧葉先風落，草蟲迎濕吟。',48,'御定全唐詩/json/358.json','["夜雲起河漢，朝雨灑高林。梧葉先風落，草蟲迎濕吟。", "簟涼扇恩薄，室靜琴思深。且喜炎前別，安能懷寸陰。"]'),
('yuding-47','秋晚病中樂天以詩見問力疾奉酬','劉禹錫','唐','御定全唐诗','yuding','','[]','耳虛多聽遠，輾轉晨雞鳴。一室背燈臥，中宵掃葉聲。',48,'御定全唐詩/json/358.json','["耳虛多聽遠，輾轉晨雞鳴。一室背燈臥，中宵掃葉聲。", "蘭芳經雨敗，鶴病得秋輕。肯踏衡門草，唯應是友生。"]'),
('yuding-48','和樂天燒藥不成命酒獨醉','劉禹錫','唐','御定全唐诗','yuding','','[]','九轉欲成就，百神應主持。嬰啼鼎上去，老貌鏡前悲。',48,'御定全唐詩/json/358.json','["九轉欲成就，百神應主持。嬰啼鼎上去，老貌鏡前悲。", "卻顧空丹灶，回心向酒卮。醺然耳熱後，暫似少年時。"]'),
('yuding-49','元日樂天見過因舉酒為賀','劉禹錫','唐','御定全唐诗','yuding','','[]','漸入有年數，喜逢新歲來。震方天籟動，寅位帝車回。',48,'御定全唐詩/json/358.json','["漸入有年數，喜逢新歲來。震方天籟動，寅位帝車回。", "門巷掃殘雪，林園驚早梅。與君同甲子，壽酒讓先杯。"]'),
('yuding-50','酬馬大夫以愚獻通草茇葜酒感通拔二字因而寄別之作','劉禹錫','唐','御定全唐诗','yuding','','[]','泥沙難振拔，誰複問窮通。莫訝提壺贈，家傳枕曲風。',48,'御定全唐詩/json/358.json','["泥沙難振拔，誰複問窮通。莫訝提壺贈，家傳枕曲風。", "成謠獨酌後，深意片言中。不進終無已，應須荀令公。"]'),
('yuding-51','奉和司空裴相公中書即事通簡舊僚之作','劉禹錫','唐','御定全唐诗','yuding','','[]','譚笑在岩廊，人人盡所長。儀形見山立，文字動星光。',48,'御定全唐詩/json/358.json','["譚笑在岩廊，人人盡所長。儀形見山立，文字動星光。", "日運丹青筆，時看赤白囊。佇聞戎馬息，入賀領鴛行。"]'),
('yuding-52','微之鎮武昌中路見寄藍橋懷舊之作淒然繼和兼寄安平','劉禹錫','唐','御定全唐诗','yuding','','[]','今日油幢引，他年黃紙追。同為三楚客，獨有九霄期。',48,'御定全唐詩/json/358.json','["今日油幢引，他年黃紙追。同為三楚客，獨有九霄期。", "宿草恨長在，傷禽飛尚遲。武昌應已到，新柳映紅旗。"]'),
('yuding-53','將赴蘇州途出洛陽留守李相公累申宴餞寵行話舊形於篇章謹抒下情以申仰謝','劉禹錫','唐','御定全唐诗','yuding','','[]','歲杪風物動，雪餘宮苑晴。兔園賓客至，金穀管弦聲。',48,'御定全唐詩/json/358.json','["歲杪風物動，雪餘宮苑晴。兔園賓客至，金穀管弦聲。", "洛水故人別，吳宮新燕迎。越郎憂不淺，懷袖有瓊英。"]'),
('yuding-54','牛相公留守見示城外新墅有溪竹秋月親情多往宿遊恨不得去因成四韻兼簡洛中親故之什兼命同作','劉禹錫','唐','御定全唐诗','yuding','','[]','別墅洛城外，月明村野通。光輝滿地上，絲管發舟中。',48,'御定全唐詩/json/358.json','["別墅洛城外，月明村野通。光輝滿地上，絲管發舟中。", "堤豔菊花露，島涼松葉風。高情限清禁，寒漏滴深宮。"]'),
('yuding-55','牛相公林亭雨後偶成','劉禹錫','唐','御定全唐诗','yuding','','[]','飛雨過池閣，浮光生草樹。新竹開粉奩，初蓮爇香注。',48,'御定全唐詩/json/358.json','["飛雨過池閣，浮光生草樹。新竹開粉奩，初蓮爇香注。", "野花無時節，水鳥自來去。若問知境人，人間第一處。"]'),
('yuding-56','酬滑州李尚書秋日見寄','劉禹錫','唐','御定全唐诗','yuding','','[]','一入石渠署，三聞宮樹蟬。丹霄未得路，白髮又添年。',48,'御定全唐詩/json/358.json','["一入石渠署，三聞宮樹蟬。丹霄未得路，白髮又添年。", "雙節外台貴，孤簫中禁傳。征黃在旦夕，早晚發南燕。"]'),
('yuding-57','和西川李尚書漢州微月游房太尉西湖','劉禹錫','唐','御定全唐诗','yuding','','[]','木落漢川夜，西湖懸玉鉤。旌旗環水次，舟楫泛中流。',48,'御定全唐詩/json/358.json','["木落漢川夜，西湖懸玉鉤。旌旗環水次，舟楫泛中流。", "目極想前事，神交如共遊。瑤琴久已絕，松韻自悲秋。"]'),
('yuding-58','和重題','劉禹錫','唐','御定全唐诗','yuding','','[]','林端落照盡，湖上遠嵐清。水榭芝蘭室，仙舟魚鳥情。',48,'御定全唐詩/json/358.json','["林端落照盡，湖上遠嵐清。水榭芝蘭室，仙舟魚鳥情。", "人琴久寂寞，煙月若平生。一泛釣璜處，再吟鏘玉聲。"]'),
('yuding-59','酬李相公喜歸鄉國自鞏縣夜泛洛水見寄','劉禹錫','唐','御定全唐诗','yuding','','[]','鞏樹煙月上，清光含碧流。且無三已色，猶泛五湖舟。',48,'御定全唐詩/json/358.json','["鞏樹煙月上，清光含碧流。且無三已色，猶泛五湖舟。", "鵬息風還起，鳳歸林正秋。雖攀小山桂，此地不淹留。"]'),
('yuding-60','和李相公平泉潭上喜見初月','劉禹錫','唐','御定全唐诗','yuding','','[]','家山見初月，林壑悄無塵。幽境此何夕，清光如為人。',48,'御定全唐詩/json/358.json','["家山見初月，林壑悄無塵。幽境此何夕，清光如為人。", "潭空破鏡入，風動翠蛾嚬。會向瑣窗望，追思伊洛濱。"]'),
('yuding-61','和李相公初歸平泉過龍門南嶺遙望山居即事','劉禹錫','唐','御定全唐诗','yuding','','[]','暫別明庭去，初隨優詔還。曾為鵬鳥賦，喜過鑿龍山。',48,'御定全唐詩/json/358.json','["暫別明庭去，初隨優詔還。曾為鵬鳥賦，喜過鑿龍山。", "新墅煙火起，野程泉石間。岩廊人望在，只得片時閑。"]'),
('yuding-62','和李相公以平泉新墅獲方外之名因為詩以報洛中士君子兼見寄之什','劉禹錫','唐','御定全唐诗','yuding','','[]','業繼韋平後，家依昆閬間。恩華辭北第，瀟灑愛東山。',48,'御定全唐詩/json/358.json','["業繼韋平後，家依昆閬間。恩華辭北第，瀟灑愛東山。", "滿室圖書在，入門松菊閑。垂天雖暫息，一舉出人寰。"]'),
('yuding-63','發蘇州後登武丘寺望海樓','劉禹錫','唐','御定全唐诗','yuding','','[]','獨宿望海樓，夜深珍木冷。僧房已閉戶，山月方出嶺。',48,'御定全唐詩/json/358.json','["獨宿望海樓，夜深珍木冷。僧房已閉戶，山月方出嶺。", "碧池涵劍彩，寶刹搖星影。卻憶郡齋中，虛眠此時景。"]'),
('yuding-64','松江送處州奚使君','劉禹錫','唐','御定全唐诗','yuding','','[]','吳越古今路，滄波朝夕流。從來別離地，能使管弦愁。',48,'御定全唐詩/json/358.json','["吳越古今路，滄波朝夕流。從來別離地，能使管弦愁。", "江草帶煙暮，海雲含雨秋。知君五陵客，不樂石門遊。"]'),
('yuding-65','題報恩寺','劉禹錫','唐','御定全唐诗','yuding','','[]','雲外支硎寺，名聲敵虎丘。石文留馬跡，峰勢聳牛頭。',48,'御定全唐詩/json/358.json','["雲外支硎寺，名聲敵虎丘。石文留馬跡，峰勢聳牛頭。", "泉眼潛通海，松門預帶秋。遲回好風景，王謝昔曾遊。"]'),
('yuding-66','罷郡姑蘇北歸渡揚子津','劉禹錫','唐','御定全唐诗','yuding','','[]','幾歲悲南國，今朝賦北征。歸心渡江勇，病體得秋輕。',96,'御定全唐詩/json/358.json','["幾歲悲南國，今朝賦北征。歸心渡江勇，病體得秋輕。", "海闊石門小，城高粉堞明。金山舊遊寺，過岸聽鐘聲。", "故國荒台在，前臨震澤波。綺羅隨世盡，麋鹿古時多。", "築用金錘力，摧因石鼠窠。昔年雕輦路，唯有采樵歌。"]'),
('yuding-67','尋汪道士不遇','劉禹錫','唐','御定全唐诗','yuding','','[]','仙子東南秀，泠然善馭風。笙歌五雲裏，天地一壺中。',48,'御定全唐詩/json/358.json','["仙子東南秀，泠然善馭風。笙歌五雲裏，天地一壺中。", "受籙金華洞，焚香玉帝宮。我來君閉戶，應是向崆峒。"]'),
('yuding-68','謝柳子厚寄疊石硯','劉禹錫','唐','御定全唐诗','yuding','','[]','常時同硯席，寄硯感離群。清越敲寒玉，參差疊碧雲。',48,'御定全唐詩/json/358.json','["常時同硯席，寄硯感離群。清越敲寒玉，參差疊碧雲。", "煙嵐餘斐亹，水墨兩氛氳。好與陶貞白，松窗寫紫文。"]'),
('yuding-69','元日感懷','劉禹錫','唐','御定全唐诗','yuding','','[]','振蟄春潛至，湘南人未歸。身加一日長，心覺去年非。',48,'御定全唐詩/json/358.json','["振蟄春潛至，湘南人未歸。身加一日長，心覺去年非。", "燎火委虛燼，兒童衒彩衣。異鄉無舊識，車馬到門稀。"]'),
('yuding-70','謝宣州崔相公賜馬','劉禹錫','唐','御定全唐诗','yuding','','[]','浮雲金絡膝，昨日別朱輪。銜草如懷戀，嘶風尚意頻。',48,'御定全唐詩/json/358.json','["浮雲金絡膝，昨日別朱輪。銜草如懷戀，嘶風尚意頻。", "曾將比君子，不是換佳人。從此西歸路，應容躡後塵。"]'),
('yuding-71','南中書來','劉禹錫','唐','御定全唐诗','yuding','','[]','君書問風俗，此地接炎州。淫祀多青鬼，居人少白頭。',48,'御定全唐詩/json/358.json','["君書問風俗，此地接炎州。淫祀多青鬼，居人少白頭。", "旅情偏在夜，鄉思豈唯秋。每羨朝宗水，門前盡日流。"]'),
('yuding-72','題招隱寺','劉禹錫','唐','御定全唐诗','yuding','','[]','隱士遺塵在，高僧精舍開。地形臨渚斷，江勢觸山回。',48,'御定全唐詩/json/358.json','["隱士遺塵在，高僧精舍開。地形臨渚斷，江勢觸山回。", "楚野花多思，南禽聲例哀。殷勤最高頂，閑即望鄉來。"]'),
('yuding-73','思歸寄山中友人','劉禹錫','唐','御定全唐诗','yuding','','[]','蕭條對秋色，相憶在雲泉。木落病身死，潮平歸思懸。',48,'御定全唐詩/json/358.json','["蕭條對秋色，相憶在雲泉。木落病身死，潮平歸思懸。", "涼鐘山頂寺，暝火渡頭船。此地非吾士，閑留又一年。"]'),
('yuding-74','有感','劉禹錫','唐','御定全唐诗','yuding','','[]','死且不自覺，其餘安可論。昨宵鳳池客，今日雀羅門。',48,'御定全唐詩/json/358.json','["死且不自覺，其餘安可論。昨宵鳳池客，今日雀羅門。", "騎吏塵未息，銘旌風已翻。平生紅粉愛，惟解哭黃昏。"]'),
('yuding-75','途次敷水驛伏睹華州舅氏昔日行縣題詩處潸然有感','劉禹錫','唐','御定全唐诗','yuding','','[]','昔日股肱守，朱輪茲地遊。繁華日已謝，章句此空留。',48,'御定全唐詩/json/358.json','["昔日股肱守，朱輪茲地遊。繁華日已謝，章句此空留。", "蔓草佳城閉，故林棠樹秋。今來重垂淚，不忍過西州。"]'),
('yuding-76','奉和鄭相公以考功十弟山姜花俯賜篇詠','劉禹錫','唐','御定全唐诗','yuding','','[]','採擷黃姜蕊，封題青瑣闈。共聞調膳日，正是退朝歸。',48,'御定全唐詩/json/358.json','["採擷黃姜蕊，封題青瑣闈。共聞調膳日，正是退朝歸。", "響為纖筵發，情隨彩翰飛。故將天下寶，萬里與光輝。"]'),
('yuding-77','題淳於髡墓','劉禹錫','唐','御定全唐诗','yuding','','[]','生為齊贅婿，死作楚先賢。應以客卿葬，故臨官道邊。',48,'御定全唐詩/json/358.json','["生為齊贅婿，死作楚先賢。應以客卿葬，故臨官道邊。", "寓言本多興，放意能合權。我有一石酒，置君墳樹前。"]'),
('yuding-0','送春詞','劉禹錫','唐','御定全唐诗','yuding','','[]','昨來樓上迎春處，今日登樓又送歸。蘭蕊殘妝含露泣，',40,'御定全唐詩/json/359.json','["昨來樓上迎春處，今日登樓又送歸。蘭蕊殘妝含露泣，", "萬古至今同此恨，無如一醉盡忘機。"]'),
('yuding-1','送李尚書鎮滑州','劉禹錫','唐','御定全唐诗','yuding','','[]','南徐報政入文昌，東郡須才別建章。視草名高同蜀客，',40,'御定全唐詩/json/359.json','["南徐報政入文昌，東郡須才別建章。視草名高同蜀客，", "自古相門還出相，如今人望在岩廊。"]'),
('yuding-2','送渾大夫赴豐州','劉禹錫','唐','御定全唐诗','yuding','','[]','鳳銜新詔降恩華，又見旌旗出渾家。故吏來辭辛屬國，',40,'御定全唐詩/json/359.json','["鳳銜新詔降恩華，又見旌旗出渾家。故吏來辭辛屬國，", "其奈明年好春日，無人喚看牡丹花。"]'),
('yuding-3','送源中丞充新羅冊立使','劉禹錫','唐','御定全唐诗','yuding','','[]','相門才子稱華簪，持節東行捧德音。身帶霜威辭鳳闕，',40,'御定全唐詩/json/359.json','["相門才子稱華簪，持節東行捧德音。身帶霜威辭鳳闕，", "想見扶桑受恩處，一時西拜盡傾心。"]'),
('yuding-4','送王司馬之陝州','劉禹錫','唐','御定全唐诗','yuding','','[]','暫輟清齋出太常，空攜詩卷赴甘棠。府公既有朝中舊，',40,'御定全唐詩/json/359.json','["暫輟清齋出太常，空攜詩卷赴甘棠。府公既有朝中舊，", "兩京大道多遊客，每遇詞人戰一場。"]'),
('yuding-5','洛中送楊處厚入關便游蜀','劉禹錫','唐','御定全唐诗','yuding','','[]','洛陽秋日正淒淒，君去西秦更向西。舊學三冬今轉富，',40,'御定全唐詩/json/359.json','["洛陽秋日正淒淒，君去西秦更向西。舊學三冬今轉富，", "早識臥龍應有分，不妨從此躡丹梯。"]'),
('yuding-6','送周使君罷渝州歸郢州別墅','劉禹錫','唐','御定全唐诗','yuding','','[]','君思郢上吟歸去，故自渝南擲郡章。野戍岸邊留畫舸，',40,'御定全唐詩/json/359.json','["君思郢上吟歸去，故自渝南擲郡章。野戍岸邊留畫舸，", "只恐鳴騶催上道，不容待得晚菘嘗。"]'),
('yuding-7','奉送浙西李僕射相公赴鎮','劉禹錫','唐','御定全唐诗','yuding','','[]','建節東行是舊遊，歡聲喜氣滿吳州。郡人重得黃丞相，',40,'御定全唐詩/json/359.json','["建節東行是舊遊，歡聲喜氣滿吳州。郡人重得黃丞相，", "自憐不識平津閣，遙望旌旗汝水頭。"]'),
('yuding-8','重送浙西李相公頃廉問江南已經七載後歷滑臺劍南兩鎮遂入相今復領舊地新加旌旄','劉禹錫','唐','御定全唐诗','yuding','','[]','江北萬人看玉節，江南千騎引金鐃。鳳從池上游滄海，',40,'御定全唐詩/json/359.json','["江北萬人看玉節，江南千騎引金鐃。鳳從池上游滄海，", "碧雞白馬回翔久，卻憶朱方是樂郊。"]'),
('yuding-9','送前進士蔡京赴學究科','劉禹錫','唐','御定全唐诗','yuding','','[]','耳聞戰鼓帶經鋤，振發聲名自裏閭。已是世間能賦客，',40,'御定全唐詩/json/359.json','["耳聞戰鼓帶經鋤，振發聲名自裏閭。已是世間能賦客，", "幸遇天官舊丞相，知君無翼上空虛。"]'),
('yuding-10','送唐舍人出鎮閩中','劉禹錫','唐','御定全唐诗','yuding','','[]','暫辭鴛鷺出蓬瀛，忽擁貔貅鎮粵城。閩嶺夏雲迎皂蓋，',40,'御定全唐詩/json/359.json','["暫辭鴛鷺出蓬瀛，忽擁貔貅鎮粵城。閩嶺夏雲迎皂蓋，", "了卻人間婚嫁事，複歸朝右作公卿。"]'),
('yuding-11','送李中丞赴楚州','劉禹錫','唐','御定全唐诗','yuding','','[]','緹騎朱旗入楚城，士林皆賀振家聲。兒童但喜迎賓守，',40,'御定全唐詩/json/359.json','["緹騎朱旗入楚城，士林皆賀振家聲。兒童但喜迎賓守，", "憶君初得昆山玉，同向揚州攜手行。"]'),
('yuding-12','奉送李戶部侍郎自河南尹再除本官歸闕','劉禹錫','唐','御定全唐诗','yuding','','[]','昔年內署振雄詞，今日東都結去思。宮女猶傳洞簫賦，',40,'御定全唐詩/json/359.json','["昔年內署振雄詞，今日東都結去思。宮女猶傳洞簫賦，", "想到金閨待通籍，一時驚喜見風儀。"]'),
('yuding-13','送蘄州李郎中赴任','劉禹錫','唐','御定全唐诗','yuding','','[]','楚關蘄水路非賒，東望雲山日夕佳。薤葉照人呈夏簟，',40,'御定全唐詩/json/359.json','["楚關蘄水路非賒，東望雲山日夕佳。薤葉照人呈夏簟，", "北地交親長引領，早將玄鬢到京華。"]'),
('yuding-14','送國子令狐博士赴興元覲省','劉禹錫','唐','御定全唐诗','yuding','','[]','相門才子高陽族，學省清資五品官。諫院過時榮棣萼，',40,'御定全唐詩/json/359.json','["相門才子高陽族，學省清資五品官。諫院過時榮棣萼，", "伯仲到家人盡賀，柳營蓮府遞相歡。"]'),
('yuding-15','送李二十九兄員外赴邠甯使幕','劉禹錫','唐','御定全唐诗','yuding','','[]','家襲韋平身業文，素風清白至今貧。南宮通籍新郎吏，',40,'御定全唐詩/json/359.json','["家襲韋平身業文，素風清白至今貧。南宮通籍新郎吏，", "鼎門為別霜天曉，剩把離觴三五巡。"]'),
('yuding-16','送分司陳郎中只召直史館重修三聖實錄','劉禹錫','唐','御定全唐诗','yuding','','[]','蟬鳴官樹引行車，言自成周赴玉除。遠取南朝貴公子，',40,'御定全唐詩/json/359.json','["蟬鳴官樹引行車，言自成周赴玉除。遠取南朝貴公子，", "若問舊人劉子政，如今白首在南徐。"]'),
('yuding-17','送慧則法師歸上都因呈廣宣上人','劉禹錫','唐','御定全唐诗','yuding','','[]','昨日東林看講時，都人象馬蹋琉璃。雪山童子應前世，',40,'御定全唐詩/json/359.json','["昨日東林看講時，都人象馬蹋琉璃。雪山童子應前世，", "休公久別如相問，楚客逢秋心更悲。"]'),
('yuding-18','送義舟師卻還黔南','劉禹錫','唐','御定全唐诗','yuding','','[]','黔江秋水浸雲霓，獨泛慈航路不迷。猿狖窺齋林葉動，',40,'御定全唐詩/json/359.json','["黔江秋水浸雲霓，獨泛慈航路不迷。猿狖窺齋林葉動，", "常說摩圍似靈鷲，卻將山屐上丹梯。"]'),
('yuding-19','送景玄師東歸','劉禹錫','唐','御定全唐诗','yuding','','[]','東林寺裏一沙彌，心愛當時才子詩。山下偶隨流水出，',40,'御定全唐詩/json/359.json','["東林寺裏一沙彌，心愛當時才子詩。山下偶隨流水出，", "想到舊房拋錫杖，小松應有過簷枝。"]'),
('yuding-20','漢壽城春望','劉禹錫','唐','御定全唐诗','yuding','','[]','漢壽城邊野草春，荒祠古墓對荊榛。田中牧豎燒芻狗，',40,'御定全唐詩/json/359.json','["漢壽城邊野草春，荒祠古墓對荊榛。田中牧豎燒芻狗，", "不知何日東瀛變，此地還成要路津。"]'),
('yuding-21','荊門道懷古','劉禹錫','唐','御定全唐诗','yuding','','[]','南國山川舊帝畿，宋台梁館尚依稀。馬嘶古道行人歇，',40,'御定全唐詩/json/359.json','["南國山川舊帝畿，宋台梁館尚依稀。馬嘶古道行人歇，", "徒使詞臣庾開府，咸陽終日苦思歸。"]'),
('yuding-22','朗州竇員外見示與澧州元郎中郡齋贈答長句二篇因以繼和','劉禹錫','唐','御定全唐诗','yuding','','[]','鴛鷺差池出建章，彩旗朱戶蔚相望。新恩共理犬牙地，',40,'御定全唐詩/json/359.json','["鴛鷺差池出建章，彩旗朱戶蔚相望。新恩共理犬牙地，", "應憐一罷金閨籍，枉渚逢春十度傷。"]'),
('yuding-23','早春對雪奉寄澧州元郎中','劉禹錫','唐','御定全唐诗','yuding','','[]','新賜魚書墨未幹，賢人暫出遠人安。朝驅旌旆行時令，',40,'御定全唐詩/json/359.json','["新賜魚書墨未幹，賢人暫出遠人安。朝驅旌旆行時令，", "甯知楚客思公子，北望長吟澧有蘭。"]'),
('yuding-24','竇朗州見示與澧州元郎中早秋贈答命同作','劉禹錫','唐','御定全唐诗','yuding','','[]','鄰境諸侯同舍郎，芷江蘭浦恨無梁。秋風門外旌旗動，',24,'御定全唐詩/json/359.json','["鄰境諸侯同舍郎，芷江蘭浦恨無梁。秋風門外旌旗動，"]'),
('yuding-25','松滋渡望峽中','劉禹錫','唐','御定全唐诗','yuding','','[]','渡頭輕雨灑寒梅，雲際溶溶雪水來。夢渚草長迷楚望，',40,'御定全唐詩/json/359.json','["渡頭輕雨灑寒梅，雲際溶溶雪水來。夢渚草長迷楚望，", "十二碧峰何處所，永安宮外是荒台。"]'),
('yuding-26','衢州徐員外使君遺以縞紵兼竹書箱因成一篇用答佳貺','劉禹錫','唐','御定全唐诗','yuding','','[]','爛柯山下舊仙郎，列宿來添婺女光。遠放歌聲分白紵，',40,'御定全唐詩/json/359.json','["爛柯山下舊仙郎，列宿來添婺女光。遠放歌聲分白紵，", "聞說天臺有遺愛，人將琪樹比甘棠。"]'),
('yuding-27','唐秀才贈端州紫石硯，以詩答之','劉禹錫','唐','御定全唐诗','yuding','','[]','端州石硯人間重，贈我因知正草玄。闕裏廟堂空舊物，',40,'御定全唐詩/json/359.json','["端州石硯人間重，贈我因知正草玄。闕裏廟堂空舊物，", "此日傭工記名姓，因君數到墨池前。"]'),
('yuding-28','覽董評事思歸之什因以詩贈','劉禹錫','唐','御定全唐诗','yuding','','[]','幾年油幕佐征東，卻泛滄浪狎釣童。欹枕醉眠成戲蝶，',40,'御定全唐詩/json/359.json','["幾年油幕佐征東，卻泛滄浪狎釣童。欹枕醉眠成戲蝶，", "更說扁舟動鄉思，青菰已熟奈秋風。"]'),
('yuding-29','謝寺雙檜','劉禹錫','唐','御定全唐诗','yuding','','[]','雙檜蒼然古貌奇，含煙吐霧鬱參差。晚依禪客當金殿，',40,'御定全唐詩/json/359.json','["雙檜蒼然古貌奇，含煙吐霧鬱參差。晚依禪客當金殿，", "長明燈是前朝焰，曾照青青年少時。"]'),
('yuding-30','寄楊八壽州','劉禹錫','唐','御定全唐诗','yuding','','[]','風獵紅旗入壽春，滿城歌舞向朱輪。八公山下清淮水，',40,'御定全唐詩/json/359.json','["風獵紅旗入壽春，滿城歌舞向朱輪。八公山下清淮水，", "聖朝方用敢言者，次第應須舊諫臣。"]'),
('yuding-31','洛中寺北樓見賀監草書題詩','劉禹錫','唐','御定全唐诗','yuding','','[]','高樓賀監昔曾登，壁上筆蹤龍虎騰。中國書流尚皇象，',40,'御定全唐詩/json/359.json','["高樓賀監昔曾登，壁上筆蹤龍虎騰。中國書流尚皇象，", "唯恐塵埃轉磨滅，再三珍重囑山僧。"]'),
('yuding-32','聞韓賓擢第歸覲以詩美之兼賀韓十五曹長時韓牧永州','劉禹錫','唐','御定全唐诗','yuding','','[]','零陵香草滿郊坰，丹穴雛飛入翠屏。孝若歸來成畫贊，',40,'御定全唐詩/json/359.json','["零陵香草滿郊坰，丹穴雛飛入翠屏。孝若歸來成畫贊，", "為報儒林丈人道，如今從此鬢星星。"]'),
('yuding-33','宣上人遠寄和禮部王侍郎放榜後詩，因而繼和','劉禹錫','唐','御定全唐诗','yuding','','[]','禮闈新榜動長安，九陌人人走馬看。一日聲名遍天下，',40,'御定全唐詩/json/359.json','["禮闈新榜動長安，九陌人人走馬看。一日聲名遍天下，", "借問至公誰印可，支郎天眼定中觀。"]'),
('yuding-34','贈東嶽張煉師','劉禹錫','唐','御定全唐诗','yuding','','[]','東嶽真人張煉師，高情雅淡世間稀。堪為列女書青簡，',40,'御定全唐詩/json/359.json','["東嶽真人張煉師，高情雅淡世間稀。堪為列女書青簡，", "雲衢不要吹簫伴，只擬乘鸞獨自飛。"]'),
('yuding-35','秘書崔少監見示墜馬長句，因而和之','劉禹錫','唐','御定全唐诗','yuding','','[]','麟台少監舊仙郎，洛水橋邊墜馬傷。塵汙腰間青襞綬，',40,'御定全唐詩/json/359.json','["麟台少監舊仙郎，洛水橋邊墜馬傷。塵汙腰間青襞綬，", "猶賴德全如醉者，不妨吟詠入篇章。"]'),
('yuding-36','寄楊虢州與之舊姻','劉禹錫','唐','御定全唐诗','yuding','','[]','避地江湖知幾春，今來本郡擁朱輪。阮郎無複裏中舊，',40,'御定全唐詩/json/359.json','["避地江湖知幾春，今來本郡擁朱輪。阮郎無複裏中舊，", "玉城山裏多靈藥，擺落功名且養神。"]'),
('yuding-37','秋日題竇員外崇德里新居','劉禹錫','唐','御定全唐诗','yuding','','[]','長愛街西風景閑，到君居處暫開顏。清光門外一渠水，',40,'御定全唐詩/json/359.json','["長愛街西風景閑，到君居處暫開顏。清光門外一渠水，", "莫言堆案無餘地，認得詩人在此間。"]'),
('yuding-38','蒙恩轉儀曹郎依前充集賢學士舉韓潮州自代因寄七言','劉禹錫','唐','御定全唐诗','yuding','','[]','翔鸞闕下謝恩初，通籍由來在石渠。暫入南宮判祥瑞，',40,'御定全唐詩/json/359.json','["翔鸞闕下謝恩初，通籍由來在石渠。暫入南宮判祥瑞，", "今日薦君嗟久滯，不惟文體似相如。"]'),
('yuding-39','途次華州陪錢大夫登城北樓春望因睹李崔令狐三相國唱和之什翰林舊侶繼踵華城山水清高鸞鳳翔集皆忝宿眷遂題此詩','劉禹錫','唐','御定全唐诗','yuding','','[]','城樓四望出風塵，見盡關西渭北春。百二山河雄上國，',40,'御定全唐詩/json/359.json','["城樓四望出風塵，見盡關西渭北春。百二山河雄上國，", "莫怪老郎呈濫吹，宦途雖別舊情親。"]'),
('yuding-40','始聞秋風','劉禹錫','唐','御定全唐诗','yuding','','[]','昔看黃菊與君別，今聽玄蟬我卻回。五夜颼飀枕前覺，',40,'御定全唐詩/json/359.json','["昔看黃菊與君別，今聽玄蟬我卻回。五夜颼飀枕前覺，", "天地肅清堪四望，為君扶病上高臺。"]'),
('yuding-41','洛中初冬拜表有懷上京故人','劉禹錫','唐','御定全唐诗','yuding','','[]','鳳樓南面控三條，拜表郎官早渡橋。清洛曉光鋪碧簟，',40,'御定全唐詩/json/359.json','["鳳樓南面控三條，拜表郎官早渡橋。清洛曉光鋪碧簟，", "寄謝殷勤九天侶，搶榆水擊各逍遙。"]'),
('yuding-42','尉遲郎中見示自南遷牽複卻至洛城東舊居之作因以和之','劉禹錫','唐','御定全唐诗','yuding','','[]','曾遭飛語十年謫，新受恩光萬里還。朝服不妨遊洛浦，',40,'御定全唐詩/json/359.json','["曾遭飛語十年謫，新受恩光萬里還。朝服不妨遊洛浦，", "留作功成退身地，如今只是暫時閑。"]'),
('yuding-43','洛中酬福建陳判官見贈','劉禹錫','唐','御定全唐诗','yuding','','[]','潦倒聲名擁腫材，一生多故苦邅回。南宮舊籍遙相管，',40,'御定全唐詩/json/359.json','["潦倒聲名擁腫材，一生多故苦邅回。南宮舊籍遙相管，", "怪君近日文鋒利，新向延平看劍來。"]'),
('yuding-44','和蘇十郎中謝病閒居時嚴常侍蕭給事同過訪歎初有二毛之作','劉禹錫','唐','御定全唐诗','yuding','','[]','清羸隱幾望雲空，左掖鴛鸞到室中。一卷素書消永日，',40,'御定全唐詩/json/359.json','["清羸隱幾望雲空，左掖鴛鸞到室中。一卷素書消永日，", "莫怪人人驚早白，緣君尚是黑頭翁。"]'),
('yuding-45','酬淮南廖參謀秋夕見過之作','劉禹錫','唐','御定全唐诗','yuding','','[]','揚州從事夜相尋，無限新詩月下吟。初服已驚玄發長，',40,'御定全唐詩/json/359.json','["揚州從事夜相尋，無限新詩月下吟。初服已驚玄發長，", "不逐繁華訪閒散，知君擺落俗人心。"]'),
('yuding-46','題王郎中宣義裏新居','劉禹錫','唐','御定全唐诗','yuding','','[]','愛君新買街西宅，客到如游鄠杜間。雨後退朝貪種樹，',40,'御定全唐詩/json/359.json','["愛君新買街西宅，客到如游鄠杜間。雨後退朝貪種樹，", "見擬移居作鄰里，不論時節請開關。"]'),
('yuding-47','酬朗州崔員外與任十四兄侍御同過鄙人舊居見懷之什時守吳郡','劉禹錫','唐','御定全唐诗','yuding','','[]','昔日居鄰招屈亭，楓林橘樹鷓鴣聲。一辭御苑青門去，',40,'御定全唐詩/json/359.json','["昔日居鄰招屈亭，楓林橘樹鷓鴣聲。一辭御苑青門去，", "何人萬里能相憶，同舍仙郎與外兄。"]'),
('yuding-48','劉駙馬水亭避暑','劉禹錫','唐','御定全唐诗','yuding','','[]','千竿竹翠數蓮紅，水閣虛涼玉簟空。琥珀盞紅疑漏酒，',40,'御定全唐詩/json/359.json','["千竿竹翠數蓮紅，水閣虛涼玉簟空。琥珀盞紅疑漏酒，", "盡日逍遙避煩暑，再三珍重主人翁。"]'),
('yuding-49','述舊賀遷寄陝虢孫常侍','劉禹錫','唐','御定全唐诗','yuding','','[]','南宮幸襲芝蘭後，左輔曾交印綬來。多病未離清洛苑，',40,'御定全唐詩/json/359.json','["南宮幸襲芝蘭後，左輔曾交印綬來。多病未離清洛苑，", "聞說隨車有零雨，此時偏動子荊才。"]'),
('yuding-50','江陵嚴司空見示與成都武相公唱和，因命同作','劉禹錫','唐','御定全唐诗','yuding','','[]','南荊西蜀大行台，幕府旌門相對開。名重三司平水土，',40,'御定全唐詩/json/359.json','["南荊西蜀大行台，幕府旌門相對開。名重三司平水土，", "不是郢中清唱發，誰當丞相掞天才。"]'),
('yuding-51','廟庭偃松詩','劉禹錫','唐','御定全唐诗','yuding','','[]','勢軋枝偏根已危，高情一見與扶持。忽從憔悴有生意，',40,'御定全唐詩/json/359.json','["勢軋枝偏根已危，高情一見與扶持。忽從憔悴有生意，", "謝公莫道東山去，待取陰成滿鳳池。"]'),
('yuding-52','贈致仕滕庶子先輩','劉禹錫','唐','御定全唐诗','yuding','','[]','朝服歸來晝錦榮，登科記上更無兄。壽觴每使曾孫獻，',40,'御定全唐詩/json/359.json','["朝服歸來晝錦榮，登科記上更無兄。壽觴每使曾孫獻，", "淩寒卻向山陰去，衣繡郎君雪裏行。"]'),
('yuding-53','哭呂衡州，時予方謫居','劉禹錫','唐','御定全唐诗','yuding','','[]','一夜霜風凋玉芝，蒼生望絕士林悲。空懷濟世安人略，',40,'御定全唐詩/json/359.json','["一夜霜風凋玉芝，蒼生望絕士林悲。空懷濟世安人略，", "朔方徙歲行當滿，欲為君刊第二碑。"]'),
('yuding-54','夔州竇員外使君見示悼妓詩顧餘嘗識之因命同作','劉禹錫','唐','御定全唐诗','yuding','','[]','前年曾見兩鬟時，今日驚吟悼妓詩。鳳管學成知有籍，',40,'御定全唐詩/json/359.json','["前年曾見兩鬟時，今日驚吟悼妓詩。鳳管學成知有籍，", "寂寞魚山青草裏，何人更立智瓊祠。"]'),
('yuding-55','竇夔州見寄寒食日憶故姬小紅吹笙，因和之','劉禹錫','唐','御定全唐诗','yuding','','[]','鸞聲窈眇管參差，清韻初調眾樂隨。幽院妝成花下弄，',40,'御定全唐詩/json/359.json','["鸞聲窈眇管參差，清韻初調眾樂隨。幽院妝成花下弄，", "聞道今年寒食日，東山舊路獨行遲。"]'),
('yuding-56','哭龐京兆','劉禹錫','唐','御定全唐诗','yuding','','[]','俊骨英才氣褎然，策名飛步冠群賢。逢時已自致高位。',64,'御定全唐詩/json/359.json','["俊骨英才氣褎然，策名飛步冠群賢。逢時已自致高位。", "得疾還因倚少年。天上別歸京兆府，人間空數茂陵阡。", "今朝繐帳哭君處，前日見鋪歌舞筵。"]'),
('yuding-57','送李庚先輩赴選','劉禹錫','唐','御定全唐诗','yuding','','[]','一家何啻十朱輪，諸父雙飛秉大鈞。曾脫素衣參幕客，',40,'御定全唐詩/json/359.json','["一家何啻十朱輪，諸父雙飛秉大鈞。曾脫素衣參幕客，", "今日山公舊賓主，知君不負帝城春。"]'),
('yuding-58','陽山廟觀賽神','劉禹錫','唐','御定全唐诗','yuding','','[]','漢家都尉舊征蠻，血食如今配此山，曲蓋幽深蒼檜下，',40,'御定全唐詩/json/359.json','["漢家都尉舊征蠻，血食如今配此山，曲蓋幽深蒼檜下，", "日落風生廟門外，幾人連蹋竹歌還。"]'),
('yuding-59','送僧元暠東游','劉禹錫','唐','御定全唐诗','yuding','','[]','寶書翻譯學初成，振錫如飛白足輕。彭澤因家凡幾世，',40,'御定全唐詩/json/359.json','["寶書翻譯學初成，振錫如飛白足輕。彭澤因家凡幾世，", "從此多逢大居士，何人不願解珠瓔。"]'),
('yuding-60','贈日本僧智藏','劉禹錫','唐','御定全唐诗','yuding','','[]','浮杯萬里過滄溟，遍禮名山適性靈。深夜降龍潭水黑，',40,'御定全唐詩/json/359.json','["浮杯萬里過滄溟，遍禮名山適性靈。深夜降龍潭水黑，", "為問中華學道者，幾人雄猛得寧馨。"]'),
('yuding-61','送元簡上人適越','劉禹錫','唐','御定全唐诗','yuding','','[]','孤雲出岫本無依，勝境名山即是歸。久向吳門遊好寺，',40,'御定全唐詩/json/359.json','["孤雲出岫本無依，勝境名山即是歸。久向吳門遊好寺，", "更入天臺石橋去，垂珠璀璨拂三衣。"]'),
('yuding-62','送宗密上人歸南山草堂寺，因謁河南尹白侍郎','劉禹錫','唐','御定全唐诗','yuding','','[]','宿習修來得慧根，多聞第一卻忘言。自從七祖傳心印，',40,'御定全唐詩/json/359.json','["宿習修來得慧根，多聞第一卻忘言。自從七祖傳心印，", "河南白尹大檀越，好把真經相對翻。"]'),
('yuding-63','西塞山懷古','劉禹錫','唐','御定全唐诗','yuding','','[]','西晉樓船下益州，金陵王氣黯然收。千尋鐵鎖沉江底，',40,'御定全唐詩/json/359.json','["西晉樓船下益州，金陵王氣黯然收。千尋鐵鎖沉江底，", "今逢四海為家日，故壘蕭蕭蘆荻秋。"]'),
('yuding-64','廣宣上人寄在蜀與韋令公唱和詩卷因以令公手扎答詩示之','劉禹錫','唐','御定全唐诗','yuding','','[]','碧雲佳句久傳芳，曾向成都住草堂。振錫常過長者宅，',40,'御定全唐詩/json/359.json','["碧雲佳句久傳芳，曾向成都住草堂。振錫常過長者宅，", "若許相期同結社，吾家本自有柴桑。"]'),
('yuding-0','白舍人自杭州寄新詩有柳色春藏蘇小家之句因而戲酬兼寄浙東元相公','劉禹錫','唐','御定全唐诗','yuding','','[]','錢塘山水有奇聲，暫謫仙官領百城。女妓還聞名小小，',40,'御定全唐詩/json/360.json','["錢塘山水有奇聲，暫謫仙官領百城。女妓還聞名小小，", "莫道騷人在三楚，文星今向鬥牛明。"]'),
('yuding-1','春日書懷，寄東洛白二十二楊八二庶子','劉禹錫','唐','御定全唐诗','yuding','','[]','曾向空門學坐禪，如今萬事盡忘筌。眼前名利同春夢，',40,'御定全唐詩/json/360.json','["曾向空門學坐禪，如今萬事盡忘筌。眼前名利同春夢，", "心知洛下閑才子，不作詩魔即酒顛。"]'),
('yuding-2','白舍人見酬拙詩，因以寄謝','劉禹錫','唐','御定全唐诗','yuding','','[]','雖陪三品散班中，資歷從來事不同。名姓也曾鐫石柱，',40,'御定全唐詩/json/360.json','["雖陪三品散班中，資歷從來事不同。名姓也曾鐫石柱，", "煙水五湖如有伴，猶應堪作釣魚翁。"]'),
('yuding-3','白舍人曹長寄新詩，有游宴之盛，因以戲酬','劉禹錫','唐','御定全唐诗','yuding','','[]','蘇州刺史例能詩，西掖今來替左司。二八城門開道路，',40,'御定全唐詩/json/360.json','["蘇州刺史例能詩，西掖今來替左司。二八城門開道路，", "若共吳王鬥百草，不如應是欠西施。"]'),
('yuding-4','蘇州白舍人寄新詩，有歎早白無兒之句，因以贈之','劉禹錫','唐','御定全唐诗','yuding','','[]','莫嗟華髮與無兒，卻是人間久遠期。雪裏高山頭白早，',40,'御定全唐詩/json/360.json','["莫嗟華髮與無兒，卻是人間久遠期。雪裏高山頭白早，", "倖免如新分非淺，祝君長詠夢熊詩。"]'),
('yuding-5','酬樂天揚州初逢席上見贈','劉禹錫','唐','御定全唐诗','yuding','','[]','巴山楚水淒涼地，二十三年棄置身。懷舊空吟聞笛賦，',40,'御定全唐詩/json/360.json','["巴山楚水淒涼地，二十三年棄置身。懷舊空吟聞笛賦，", "今日聽君歌一曲，暫憑杯酒長精神。"]'),
('yuding-6','罷郡歸洛途次山陽，留辭郭中丞使君','劉禹錫','唐','御定全唐诗','yuding','','[]','自到山陽不許辭，高齋日夜有佳期。管弦正合看書院，',40,'御定全唐詩/json/360.json','["自到山陽不許辭，高齋日夜有佳期。管弦正合看書院，", "洛陽歸客明朝去，容趁城東花發時。"]'),
('yuding-7','楚州開元寺北院枸杞臨井繁茂可觀群賢賦詩因以繼和','劉禹錫','唐','御定全唐诗','yuding','','[]','僧房藥樹依寒井，井有香泉樹有靈。翠黛葉生籠石甃，',40,'御定全唐詩/json/360.json','["僧房藥樹依寒井，井有香泉樹有靈。翠黛葉生籠石甃，", "上品功能甘露味，還知一勺可延齡。"]'),
('yuding-8','和樂天鸚鵡','劉禹錫','唐','御定全唐诗','yuding','','[]','養來鸚鵡觜初紅，宜在朱樓繡戶中。頻學喚人緣性慧，',40,'御定全唐詩/json/360.json','["養來鸚鵡觜初紅，宜在朱樓繡戶中。頻學喚人緣性慧，", "誰遣聰明好顏色，事須安置入深籠。"]'),
('yuding-9','洛中逢白監同話游梁之樂，因寄宣武令狐相公','劉禹錫','唐','御定全唐诗','yuding','','[]','曾經謝病各游梁，今日相逢憶孝王。少有一身兼將相，',40,'御定全唐詩/json/360.json','["曾經謝病各游梁，今日相逢憶孝王。少有一身兼將相，", "借問風前兼月下，不知何客對胡床。"]'),
('yuding-10','河南王少尹宅燕張常侍白舍人兼呈盧郎中李員外二副使','劉禹錫','唐','御定全唐诗','yuding','','[]','將星夜落使星來，三省清臣到外台。事重各銜天子詔，',40,'御定全唐詩/json/360.json','["將星夜落使星來，三省清臣到外台。事重各銜天子詔，", "第一林亭迎好客，殷勤莫惜玉山頹。"]'),
('yuding-11','和宣武令狐相公郡齋對新竹','劉禹錫','唐','御定全唐诗','yuding','','[]','新竹翛翛韻曉風，隔窗依砌尚蒙籠。數間素壁初開後，',40,'御定全唐詩/json/360.json','["新竹翛翛韻曉風，隔窗依砌尚蒙籠。數間素壁初開後，", "此君若欲長相見，政事堂東有舊叢。"]'),
('yuding-12','和樂天送鶴上裴相公別鶴之作','劉禹錫','唐','御定全唐诗','yuding','','[]','昨日看成送鶴詩，高籠提出白雲司。朱門乍入應迷路，',40,'御定全唐詩/json/360.json','["昨日看成送鶴詩，高籠提出白雲司。朱門乍入應迷路，", "三山碧海不歸去，且向人間呈羽儀。"]'),
('yuding-13','闕下待傳點呈諸同舍','劉禹錫','唐','御定全唐诗','yuding','','[]','禁漏晨鐘聲欲絕，旌旗組綬影相交。殿含佳氣當龍首，',40,'御定全唐詩/json/360.json','["禁漏晨鐘聲欲絕，旌旗組綬影相交。殿含佳氣當龍首，", "多慚再入金門籍，不敢為文學解嘲。"]'),
('yuding-14','和樂天以鏡換酒','劉禹錫','唐','御定全唐诗','yuding','','[]','把取菱花百煉鏡，換他竹葉十旬杯。嚬眉厭老終難去，',40,'御定全唐詩/json/360.json','["把取菱花百煉鏡，換他竹葉十旬杯。嚬眉厭老終難去，", "校量功力相千萬，好去從空白玉台。"]'),
('yuding-15','同樂天送河南馮尹學士','劉禹錫','唐','御定全唐诗','yuding','','[]','可憐五馬風流地，暫輟金貂侍從才。閣上掩書劉向去，',40,'御定全唐詩/json/360.json','["可憐五馬風流地，暫輟金貂侍從才。閣上掩書劉向去，", "共羨府中棠棣好，先於城外百花開。"]'),
('yuding-16','同白二十二贈王山人','劉禹錫','唐','御定全唐诗','yuding','','[]','愛名之世忘名客，多事之時無事身。古老相傳見來久，',40,'御定全唐詩/json/360.json','["愛名之世忘名客，多事之時無事身。古老相傳見來久，", "笑聽咚咚朝暮鼓，只能催得市朝人。"]'),
('yuding-17','題集賢閣','劉禹錫','唐','御定全唐诗','yuding','','[]','鳳池西畔圖書府，玉樹玲瓏景氣閑。長聽餘風送天樂，',40,'御定全唐詩/json/360.json','["鳳池西畔圖書府，玉樹玲瓏景氣閑。長聽餘風送天樂，", "曾是先賢翔集地，每看壁記一慚顏。"]'),
('yuding-18','和令狐相公初歸京國賦詩言懷','劉禹錫','唐','御定全唐诗','yuding','','[]','淩雲羽翮掞天才，揚曆中樞與外台。相印昔辭東閣去，',40,'御定全唐詩/json/360.json','["淩雲羽翮掞天才，揚曆中樞與外台。相印昔辭東閣去，", "口不言功心自適，吟詩釀酒待花開。"]'),
('yuding-19','和樂天南園試小樂','劉禹錫','唐','御定全唐诗','yuding','','[]','閒步南園煙雨晴，遙聞絲竹出牆聲。欲拋丹筆三川去，',40,'御定全唐詩/json/360.json','["閒步南園煙雨晴，遙聞絲竹出牆聲。欲拋丹筆三川去，", "多才遇景皆能詠，當日人傳滿鳳城。"]'),
('yuding-20','答樂天戲贈','劉禹錫','唐','御定全唐诗','yuding','','[]','才子聲名白侍郎，風流雖老尚難當。詩情逸似陶彭澤，',40,'御定全唐詩/json/360.json','["才子聲名白侍郎，風流雖老尚難當。詩情逸似陶彭澤，", "知君技癢思歡宴，欲倩天魔破道場。"]'),
('yuding-21','同樂天送令狐相公赴東都留守','劉禹錫','唐','御定全唐诗','yuding','','[]','尚書劍履出明光，居守旌旗赴洛陽。世上功名兼將相，',40,'御定全唐詩/json/360.json','["尚書劍履出明光，居守旌旗赴洛陽。世上功名兼將相，", "從發坡頭向東望，春風處處有甘棠。"]'),
('yuding-22','刑部白侍郎謝病長告，改賓客分司，以詩贈別','劉禹錫','唐','御定全唐诗','yuding','','[]','鼎食華軒到眼前，拂衣高謝豈徒然。九霄路上辭朝客，',40,'御定全唐詩/json/360.json','["鼎食華軒到眼前，拂衣高謝豈徒然。九霄路上辭朝客，", "洛陽舊有衡茆在，亦擬抽身伴地仙。"]'),
('yuding-23','和留守令狐相公答白賓客','劉禹錫','唐','御定全唐诗','yuding','','[]','麥隴和風吹樹枝，商山逸客出關時。身無拘束起長晚，',40,'御定全唐詩/json/360.json','["麥隴和風吹樹枝，商山逸客出關時。身無拘束起長晚，", "君來不用飛書報，萬戶先從紙貴知。"]'),
('yuding-24','酬鄆州令狐相公官舍言懷見寄兼呈樂天','劉禹錫','唐','御定全唐诗','yuding','','[]','詞人各在一涯居，聲味雖同跡自疏。佳句傳因多好事，',40,'御定全唐詩/json/360.json','["詞人各在一涯居，聲味雖同跡自疏。佳句傳因多好事，", "聞說朝天在來歲，霸陵春色待行車。"]'),
('yuding-25','吟白樂天哭崔兒二篇，愴然寄贈','劉禹錫','唐','御定全唐诗','yuding','','[]','吟君苦調我沾纓，能使無情盡有情。四望車中心未釋，',40,'御定全唐詩/json/360.json','["吟君苦調我沾纓，能使無情盡有情。四望車中心未釋，", "從此期君比瓊樹，一枝吹折一枝生。"]'),
('yuding-26','答樂天所寄詠懷，且釋其枯樹之歎','劉禹錫','唐','御定全唐诗','yuding','','[]','衙前有樂饌常精，宅內連池酒任傾。自是官高無狎客，',40,'御定全唐詩/json/360.json','["衙前有樂饌常精，宅內連池酒任傾。自是官高無狎客，", "莫羨三春桃與李，桂花成實向秋榮。"]'),
('yuding-27','赴蘇州酬別樂天','劉禹錫','唐','御定全唐诗','yuding','','[]','吳郡魚書下紫宸，長安廄吏送朱輪。二南風化承遺愛，',40,'御定全唐詩/json/360.json','["吳郡魚書下紫宸，長安廄吏送朱輪。二南風化承遺愛，", "江城春日追遊處，共憶東歸舊主人。"]'),
('yuding-28','福先寺雪中酬別樂天','劉禹錫','唐','御定全唐诗','yuding','','[]','龍門賓客會龍宮，東去旌旗駐上東。二八笙歌雲幕下，',40,'御定全唐詩/json/360.json','["龍門賓客會龍宮，東去旌旗駐上東。二八笙歌雲幕下，", "才子從今一分散，便將詩詠向吳儂。"]'),
('yuding-29','和樂天耳順吟兼寄敦詩','劉禹錫','唐','御定全唐诗','yuding','','[]','吟君新什慰蹉跎，屈指同登耳順科。鄧禹功成三紀事，',40,'御定全唐詩/json/360.json','["吟君新什慰蹉跎，屈指同登耳順科。鄧禹功成三紀事，", "獨恨長洲數千里，且隨魚鳥泛煙波。"]'),
('yuding-30','和白侍郎送令狐相公鎮太原','劉禹錫','唐','御定全唐诗','yuding','','[]','十萬天兵貂錦衣，晉城風日鬥生輝。行台僕射深恩重，',40,'御定全唐詩/json/360.json','["十萬天兵貂錦衣，晉城風日鬥生輝。行台僕射深恩重，", "邊庭自此無烽火，擁節還來坐紫微。"]'),
('yuding-31','酬樂天見寄','劉禹錫','唐','御定全唐诗','yuding','','[]','元君後輩先零落，崔相同年不少留。華屋坐來能幾日，',40,'御定全唐詩/json/360.json','["元君後輩先零落，崔相同年不少留。華屋坐來能幾日，", "若使吾徒還早達，亦應簫鼓入松楸。"]'),
('yuding-32','樂天寄重和晚達冬青一篇，因成再答','劉禹錫','唐','御定全唐诗','yuding','','[]','風雲變化饒年少，光景蹉跎屬老夫。秋隼得時淩汗漫，',40,'御定全唐詩/json/360.json','["風雲變化饒年少，光景蹉跎屬老夫。秋隼得時淩汗漫，", "振臂猶堪呼一擲，爭知掌下不成盧。"]'),
('yuding-33','河南白尹有喜崔賓客歸洛兼見懷長句，因而繼和','劉禹錫','唐','御定全唐诗','yuding','','[]','幾年侍從作名臣，卻向青雲索得身。朝士忽為方外士，',40,'御定全唐詩/json/360.json','["幾年侍從作名臣，卻向青雲索得身。朝士忽為方外士，", "遙羨光陰不虛擲，肯令絲竹暫生塵。"]'),
('yuding-34','和楊師皋給事傷小姬英英','劉禹錫','唐','御定全唐诗','yuding','','[]','見學胡琴見藝成，今朝追想幾傷情。撚弦花下呈新曲。',64,'御定全唐詩/json/360.json','["見學胡琴見藝成，今朝追想幾傷情。撚弦花下呈新曲。", "放撥燈前謝改名。但是好花皆易落，從來尤物不長生。", "鸞台夜直衣衾冷，雲雨無因入禁城。"]'),
('yuding-35','和樂天洛下醉吟，寄太原令狐相公，兼見懷長句','劉禹錫','唐','御定全唐诗','yuding','','[]','舊相臨戎非稱意，詞人作尹本多情。從容自使邊塵靜，',40,'御定全唐詩/json/360.json','["舊相臨戎非稱意，詞人作尹本多情。從容自使邊塵靜，", "昨來亦有吳趨詠，惟寄東都與北京。"]'),
('yuding-36','郡齋書懷寄江南白尹，兼簡分司崔賓客','劉禹錫','唐','御定全唐诗','yuding','','[]','謾讀圖書三十車，年年為郡老天涯。一生不得文章力，',40,'御定全唐詩/json/360.json','["謾讀圖書三十車，年年為郡老天涯。一生不得文章力，", "還思謝病吟歸去，同醉城東桃李花。"]'),
('yuding-37','題于家公主舊宅','劉禹錫','唐','御定全唐诗','yuding','','[]','樹繞荒台葉滿池，簫聲一絕草蟲悲。鄰家猶學宮人髻，',40,'御定全唐詩/json/360.json','["樹繞荒台葉滿池，簫聲一絕草蟲悲。鄰家猶學宮人髻，", "何郎獨在無恩澤，不似當初傅粉時。"]'),
('yuding-38','酬樂天見貽賀金紫之什','劉禹錫','唐','御定全唐诗','yuding','','[]','久學文章含白鳳，卻因政事賜金魚。郡人未識聞謠詠，',40,'御定全唐詩/json/360.json','["久學文章含白鳳，卻因政事賜金魚。郡人未識聞謠詠，", "舊來詞客多無位，金紫同遊誰得如。"]'),
('yuding-39','樂天見示傷微之敦詩晦叔三君子皆有深分因成是詩以寄','劉禹錫','唐','御定全唐诗','yuding','','[]','吟君歎逝雙絕句，使我傷懷奏短歌。世上空驚故人少，',40,'御定全唐詩/json/360.json','["吟君歎逝雙絕句，使我傷懷奏短歌。世上空驚故人少，", "萬古到今同此恨，聞琴淚盡欲如何。"]'),
('yuding-40','和樂天柘枝','劉禹錫','唐','御定全唐诗','yuding','','[]','柘枝本出楚王家，玉面添嬌舞態奢。松鬢改梳鸞鳳髻，',40,'御定全唐詩/json/360.json','["柘枝本出楚王家，玉面添嬌舞態奢。松鬢改梳鸞鳳髻，", "畫筵曲罷辭歸去，便隨王母上煙霞。"]'),
('yuding-41','和樂天題真娘墓','劉禹錫','唐','御定全唐诗','yuding','','[]','薝卜林中黃土堆，羅襦繡黛已成灰。芳魂雖死人不怕，',40,'御定全唐詩/json/360.json','["薝卜林中黃土堆，羅襦繡黛已成灰。芳魂雖死人不怕，", "吳王嬌女墳相近，一片行雲應往來。"]'),
('yuding-42','客有話汴州新政書事寄令狐相公','劉禹錫','唐','御定全唐诗','yuding','','[]','天下咽喉今大寧，軍城喜氣徹青冥。庭前劍戟朝迎日，',40,'御定全唐詩/json/360.json','["天下咽喉今大寧，軍城喜氣徹青冥。庭前劍戟朝迎日，", "汴州忽複承平事，正月看燈戶不扃。"]'),
('yuding-43','令狐相公見示河中楊少尹贈答，兼命繼之','劉禹錫','唐','御定全唐诗','yuding','','[]','兩首新詩百字餘，朱弦玉磬韻難如。漢家丞相重征後，',40,'御定全唐詩/json/360.json','["兩首新詩百字餘，朱弦玉磬韻難如。漢家丞相重征後，", "自從卻縠為元帥，大將歸來盡把書。"]'),
('yuding-44','和令狐相公送趙常盈鏈師與中貴人同拜嶽及天臺投龍畢卻赴京','劉禹錫','唐','御定全唐诗','yuding','','[]','銀璫謁者引蜺旌，霞帔仙官到赤城。白鶴迎來天樂動，',40,'御定全唐詩/json/360.json','["銀璫謁者引蜺旌，霞帔仙官到赤城。白鶴迎來天樂動，", "何事夷門請詩送，梁王文字上聲名。"]'),
('yuding-45','酬令狐相公贈別','劉禹錫','唐','御定全唐诗','yuding','','[]','越聲長苦有誰聞，老向湘山與楚雲。海嶠新辭永嘉守，',40,'御定全唐詩/json/360.json','["越聲長苦有誰聞，老向湘山與楚雲。海嶠新辭永嘉守，", "幸遇甘泉尚詞賦，不知何客薦雄文。"]'),
('yuding-46','酬令狐相公寄賀遷拜之什','劉禹錫','唐','御定全唐诗','yuding','','[]','邅回二紀重為郎，洛下遙分列宿光。不見當關呼早起，',40,'御定全唐詩/json/360.json','["邅回二紀重為郎，洛下遙分列宿光。不見當關呼早起，", "白髮青衫誰比數，相憐只是有梁王。"]'),
('yuding-47','夏日寄宣武令狐相公','劉禹錫','唐','御定全唐诗','yuding','','[]','長憶梁王逸興多，西園花盡興如何。近來溽暑侵亭館，',40,'御定全唐詩/json/360.json','["長憶梁王逸興多，西園花盡興如何。近來溽暑侵亭館，", "承明欲謁先相報，願拂朝衣逐曉珂。"]'),
('yuding-48','酬令狐留守巡內至集賢院見寄','劉禹錫','唐','御定全唐诗','yuding','','[]','仙院文房隔舊宮，當時盛事盡成空。墨池半在頹垣下，',40,'御定全唐詩/json/360.json','["仙院文房隔舊宮，當時盛事盡成空。墨池半在頹垣下，", "為兄手寫殷勤句，遍曆三台各一通。"]'),
('yuding-49','和令狐相公言懷寄河中楊少尹','劉禹錫','唐','御定全唐诗','yuding','','[]','章句慚非第一流，世間才子昔陪游。吳宮已歎芙蓉死，',40,'御定全唐詩/json/360.json','["章句慚非第一流，世間才子昔陪游。吳宮已歎芙蓉死，", "石渠甘對圖書老，關外楊公安穩不。"]'),
('yuding-50','令狐相公自天平移鎮太原以詩申賀','劉禹錫','唐','御定全唐诗','yuding','','[]','北都留守將天兵，出入香街宿禁扃。鼙鼓夜聞驚朔雁，',40,'御定全唐詩/json/360.json','["北都留守將天兵，出入香街宿禁扃。鼙鼓夜聞驚朔雁，", "夷落遙知真漢相，爭來屈膝看儀刑。"]'),
('yuding-51','重酬前寄','劉禹錫','唐','御定全唐诗','yuding','','[]','邊烽寂寂盡收兵，宮樹蒼蒼靜掩扃。戎羯歸心如內地，',40,'御定全唐詩/json/360.json','["邊烽寂寂盡收兵，宮樹蒼蒼靜掩扃。戎羯歸心如內地，", "吳苑晉祠遙望處，可憐南北太相形。"]'),
('yuding-52','令狐相公自太原累示新詩，因以酬寄','劉禹錫','唐','御定全唐诗','yuding','','[]','飛蓬卷盡塞雲寒，戰馬閑嘶漢地寬。萬里胡天無警急，',40,'御定全唐詩/json/360.json','["飛蓬卷盡塞雲寒，戰馬閑嘶漢地寬。萬里胡天無警急，", "珍重新詩遠相寄，風情不似四登壇。"]'),
('yuding-53','酬令狐相公使宅別齋初栽桂樹見懷之作','劉禹錫','唐','御定全唐诗','yuding','','[]','清淮南岸家山樹，黑水東邊第一栽。影近畫梁迎曉日，',40,'御定全唐詩/json/360.json','["清淮南岸家山樹，黑水東邊第一栽。影近畫梁迎曉日，", "早晚陰成比梧竹，九霄還放彩雛來。"]'),
('yuding-54','酬令狐相公見寄','劉禹錫','唐','御定全唐诗','yuding','','[]','才兼文武播雄名，遺愛芳塵滿洛城。身在行台為僕射，',40,'御定全唐詩/json/360.json','["才兼文武播雄名，遺愛芳塵滿洛城。身在行台為僕射，", "千里相思難命駕，七言詩裏寄深情。"]'),
('yuding-55','郡內書情獻裴侍中留守','劉禹錫','唐','御定全唐诗','yuding','','[]','功成頻獻乞身章，擺落襄陽鎮洛陽。萬乘旌旗分一半，',40,'御定全唐詩/json/360.json','["功成頻獻乞身章，擺落襄陽鎮洛陽。萬乘旌旗分一半，", "心寄華亭一雙鶴，日陪高步繞池塘。"]'),
('yuding-56','酬樂天衫酒見寄','劉禹錫','唐','御定全唐诗','yuding','','[]','酒法眾傳吳米好，舞衣偏尚越羅輕。動搖浮蟻香濃甚，',40,'御定全唐詩/json/360.json','["酒法眾傳吳米好，舞衣偏尚越羅輕。動搖浮蟻香濃甚，", "終朝相憶終年別，對景臨風無限情。"]'),
('yuding-57','自左馮歸洛下酬樂天兼呈裴令公','劉禹錫','唐','御定全唐诗','yuding','','[]','新恩通籍在龍樓，分務神都近舊丘。自有園公紫芝侶，',40,'御定全唐詩/json/360.json','["新恩通籍在龍樓，分務神都近舊丘。自有園公紫芝侶，", "更接東山文酒會，始知江左未風流。"]'),
('yuding-58','秋齋獨坐寄樂天兼呈吳方之大夫','劉禹錫','唐','御定全唐诗','yuding','','[]','空齋寂寂不生塵，藥物方書繞病身。纖草數莖勝靜地，',40,'御定全唐詩/json/360.json','["空齋寂寂不生塵，藥物方書繞病身。纖草數莖勝靜地，", "同向洛陽閑度日，莫教風景屬他人。"]'),
('yuding-59','和樂天齋戒月滿夜對道場偶懷詠','劉禹錫','唐','御定全唐诗','yuding','','[]','常修清淨去繁華，人識王城長者家。案上香煙鋪貝葉，',40,'御定全唐詩/json/360.json','["常修清淨去繁華，人識王城長者家。案上香煙鋪貝葉，", "明日若過方丈室，還應問為法來邪。"]'),
('yuding-60','吳方之見示獨酌小醉首篇樂天續有酬答皆含戲謔極至風流兩篇之中並蒙見屬輒呈濫吹益美來章','劉禹錫','唐','御定全唐诗','yuding','','[]','閑門共寂任張羅，靜室同虛養太和。塵世歡娛開意少，',40,'御定全唐詩/json/360.json','["閑門共寂任張羅，靜室同虛養太和。塵世歡娛開意少，", "計會雪中爭挈榼，鹿裘鶴氅遞相過。"]'),
('yuding-61','酬樂天齋滿日裴令公置宴席上戲贈','劉禹錫','唐','御定全唐诗','yuding','','[]','一月道場齋戒滿，今朝華幄管弦迎。銜杯本自多狂態，',40,'御定全唐詩/json/360.json','["一月道場齋戒滿，今朝華幄管弦迎。銜杯本自多狂態，", "平陽不獨容賓醉，聽取喧呼吏舍聲。"]'),
('yuding-62','酬樂天偶題酒甕見寄','劉禹錫','唐','御定全唐诗','yuding','','[]','從君勇斷拋名後，世路榮枯見幾回。門外紅塵人自走，',40,'御定全唐詩/json/360.json','["從君勇斷拋名後，世路榮枯見幾回。門外紅塵人自走，", "何幸相招同醉處，洛陽城裏好池台。"]'),
('yuding-63','酬樂天請裴令公開春加宴','劉禹錫','唐','御定全唐诗','yuding','','[]','高名大位能兼有，恣意遨遊是特恩。二室煙霞成步障，',40,'御定全唐詩/json/360.json','["高名大位能兼有，恣意遨遊是特恩。二室煙霞成步障，", "弦管常調客常滿，但逢花處即開樽。"]'),
('yuding-64','樂天示過敦詩舊宅有感一篇吟之泫然追想昔事因成繼和以寄苦懷','劉禹錫','唐','御定全唐诗','yuding','','[]','淒涼同到故人居，門枕寒流古木疏。向秀心中嗟棟宇，',40,'御定全唐詩/json/360.json','["淒涼同到故人居，門枕寒流古木疏。向秀心中嗟棟宇，", "忽憶前言更惆悵，丁寧相約速懸車。"]'),
('yuding-65','寄和東川楊尚書慕巢兼寄西川繼之二公近從弟兄情分偏睦早忝遊舊因成是詩','劉禹錫','唐','御定全唐诗','yuding','','[]','太華蓮峰降嶽靈，兩川棠樹接郊坰。政同兄弟人人樂，',40,'御定全唐詩/json/360.json','["太華蓮峰降嶽靈，兩川棠樹接郊坰。政同兄弟人人樂，", "各拋筆硯誇旄鉞，莫遣文星讓將星。"]'),
('yuding-66','和樂天洛下雪中宴集寄汴州李尚書','劉禹錫','唐','御定全唐诗','yuding','','[]','洛城無事足杯盤，風雪相和歲欲闌。樹上因依見寒鳥，',40,'御定全唐詩/json/360.json','["洛城無事足杯盤，風雪相和歲欲闌。樹上因依見寒鳥，", "遙想兔園今日會，瓊林滿眼映旗竿。"]'),
('yuding-67','和牛相公游南莊醉後寓言戲贈樂天兼見示','劉禹錫','唐','御定全唐诗','yuding','','[]','城外園林初夏天，就中野趣在西偏。薔薇亂髮多臨水，',40,'御定全唐詩/json/360.json','["城外園林初夏天，就中野趣在西偏。薔薇亂髮多臨水，", "白家唯有杯觴興，欲把頭盤打少年。"]'),
('yuding-68','樂天以愚相訪沽酒致歡，因成七言聊以奉答','劉禹錫','唐','御定全唐诗','yuding','','[]','少年曾醉酒旗下，同輩黃衣頷亦黃。蹴踏青雲尋入仕，',40,'御定全唐詩/json/360.json','["少年曾醉酒旗下，同輩黃衣頷亦黃。蹴踏青雲尋入仕，", "猶勝獨居荒草院，蟬聲聽盡到寒螿。"]'),
('yuding-0','和思黯憶南莊見示','劉禹錫','唐','御定全唐诗','yuding','','[]','丞相新家伊水頭，智囊心匠日增修。化成池沼無痕跡，',40,'御定全唐詩/json/361.json','["丞相新家伊水頭，智囊心匠日增修。化成池沼無痕跡，", "從來天下推尤物，合屬人間第一流。"]'),
('yuding-1','酬思黯見示小飲四韻','劉禹錫','唐','御定全唐诗','yuding','','[]','拋卻人間第一官，俗情驚怪我方安。兵符相印無心戀，',40,'御定全唐詩/json/361.json','["拋卻人間第一官，俗情驚怪我方安。兵符相印無心戀，", "追呼故舊連宵飲，直到天明興未闌。"]'),
('yuding-2','和僕射牛相公春日閑坐見懷','劉禹錫','唐','御定全唐诗','yuding','','[]','官曹崇重難頻入，第宅清閒且獨行。階蟻相逢如偶語，',40,'御定全唐詩/json/361.json','["官曹崇重難頻入，第宅清閒且獨行。階蟻相逢如偶語，", "東洛池台怨拋擲，移文非久會應成。"]'),
('yuding-3','酬元九侍禦贈璧竹鞭長句','劉禹錫','唐','御定全唐诗','yuding','','[]','碧玉孤根生在林，美人相贈比雙金。初開郢客緘封後，',40,'御定全唐詩/json/361.json','["碧玉孤根生在林，美人相贈比雙金。初開郢客緘封後，", "何時策馬同歸去，關樹扶疏敲鐙吟。"]'),
('yuding-4','酬竇員外使君，寒食日途次松滋渡，先寄示四韻','劉禹錫','唐','御定全唐诗','yuding','','[]','楚鄉寒食橘花時，野渡臨風駐彩旗。草色連雲人去住，',40,'御定全唐詩/json/361.json','["楚鄉寒食橘花時，野渡臨風駐彩旗。草色連雲人去住，", "非是湓城舊司馬，水曹何事與新詩。"]'),
('yuding-5','寄楊八拾遺','劉禹錫','唐','御定全唐诗','yuding','','[]','聞君前日獨庭爭，漢帝偏知白馬生。忽領簿書遊太學，',40,'御定全唐詩/json/361.json','["聞君前日獨庭爭，漢帝偏知白馬生。忽領簿書遊太學，", "為謝同僚老博士，范雲來歲即公卿。"]'),
('yuding-6','酬竇員外郡齋宴客偶命柘枝因見寄兼呈張十一院長元九侍御','劉禹錫','唐','御定全唐诗','yuding','','[]','分憂餘刃又從公，白羽胡床嘯詠中。彩筆諭戎矜倚馬，',40,'御定全唐詩/json/361.json','["分憂餘刃又從公，白羽胡床嘯詠中。彩筆諭戎矜倚馬，", "若問騷人何處所，門臨寒水落江楓。"]'),
('yuding-7','謝竇員外旬休早涼見示詩','劉禹錫','唐','御定全唐诗','yuding','','[]','新秋十日浣朱衣，鈴閣無聲公吏歸。風韻漸高梧葉動，',40,'御定全唐詩/json/361.json','["新秋十日浣朱衣，鈴閣無聲公吏歸。風韻漸高梧葉動，", "更報明朝池上酌，人知太守字玄暉。"]'),
('yuding-8','南海馬大夫遠示著述兼酬拙詩軋著微誠再有長句時蔡戎未弭故見於篇末','劉禹錫','唐','御定全唐诗','yuding','','[]','漢家旄節付雄才，百越南溟統外台。身在絳紗傳六藝，',40,'御定全唐詩/json/361.json','["漢家旄節付雄才，百越南溟統外台。身在絳紗傳六藝，", "聞道楚氛猶未滅，終須旌旆掃雲雷。"]'),
('yuding-9','和南海馬大夫聞楊侍郎出守郴州因有寄上之作','劉禹錫','唐','御定全唐诗','yuding','','[]','忽驚金印駕朱轓，遂別鳴珂聽曉猿。碧落仙來雖暫謫，',40,'御定全唐詩/json/361.json','["忽驚金印駕朱轓，遂別鳴珂聽曉猿。碧落仙來雖暫謫，", "一詠瓊瑤百憂散，何勞更樹北堂萱。"]'),
('yuding-10','馬大夫見示浙西王侍禦贈答詩因命同作','劉禹錫','唐','御定全唐诗','yuding','','[]','憶逐羊車凡幾時，今來舊府統戎師。象筵照室會詞客，',40,'御定全唐詩/json/361.json','["憶逐羊車凡幾時，今來舊府統戎師。象筵照室會詞客，", "秣陵從事何年別，一見瓊章如素期。"]'),
('yuding-11','寄唐州楊八歸厚','劉禹錫','唐','御定全唐诗','yuding','','[]','淮安古地擁州師，畫角金饒旦夕吹。淺草遙迎鷫鸘馬，',40,'御定全唐詩/json/361.json','["淮安古地擁州師，畫角金饒旦夕吹。淺草遙迎鷫鸘馬，", "何況遷喬舊同伴，一雙先入鳳凰池。"]'),
('yuding-12','寄朗州溫右史曹長','劉禹錫','唐','御定全唐诗','yuding','','[]','暫別瑤墀鴛鷺行，彩旗雙引到沅湘。城邊流水桃花過，',40,'御定全唐詩/json/361.json','["暫別瑤墀鴛鷺行，彩旗雙引到沅湘。城邊流水桃花過，", "雲台公業家聲在，征詔何時出建章。"]'),
('yuding-13','酬楊司業巨源見寄','劉禹錫','唐','御定全唐诗','yuding','','[]','辟雍流水近靈台，中有詩篇絕世才。渤海歸人將集去，',40,'御定全唐詩/json/361.json','["辟雍流水近靈台，中有詩篇絕世才。渤海歸人將集去，", "莫道專城管雲雨，其如心似不然灰。"]'),
('yuding-14','酬國子崔博士立之見寄','劉禹錫','唐','御定全唐诗','yuding','','[]','健筆高科早絕倫，後來無不揖芳塵。遍看今日乘軒客，',40,'御定全唐詩/json/361.json','["健筆高科早絕倫，後來無不揖芳塵。遍看今日乘軒客，", "煩君遠寄相思曲，慰問天南一逐臣。"]'),
('yuding-15','張郎中籍遠寄長句開緘之日已及新秋因舉目前仰酬高韻','劉禹錫','唐','御定全唐诗','yuding','','[]','南宮詞客寄新篇，清似湘靈促柱弦。京邑舊游勞夢想，',40,'御定全唐詩/json/361.json','["南宮詞客寄新篇，清似湘靈促柱弦。京邑舊游勞夢想，", "對此獨吟還獨酌，知音不見思愴然。"]'),
('yuding-16','浙東元相公書歎梅雨鬱蒸之候，因寄七言','劉禹錫','唐','御定全唐诗','yuding','','[]','稽山自與岐山別，何事連年鸑鷟飛。百辟商量舊相入，',40,'御定全唐詩/json/361.json','["稽山自與岐山別，何事連年鸑鷟飛。百辟商量舊相入，", "今日看書最惆悵，為聞梅雨損朝衣。"]'),
('yuding-17','酬嚴給事賀加五品兼簡同制水部李郎中','劉禹錫','唐','御定全唐诗','yuding','','[]','九天雨露傳青詔，八舍郎官換綠衣。初佩銀魚隨仗入，',40,'御定全唐詩/json/361.json','["九天雨露傳青詔，八舍郎官換綠衣。初佩銀魚隨仗入，", "聞道水曹偏得意，霞朝霧夕有光輝。"]'),
('yuding-18','裴相公大學士見示答張秘書謝馬詩並群公屬和因命追作','劉禹錫','唐','御定全唐诗','yuding','','[]','草玄門戶少塵埃，丞相並州寄馬來。初自塞垣銜苜蓿，',40,'御定全唐詩/json/361.json','["草玄門戶少塵埃，丞相並州寄馬來。初自塞垣銜苜蓿，", "不與王侯與詞客，知輕富貴重清才。"]'),
('yuding-19','奉和裴侍中將赴漢南留別座上諸公','劉禹錫','唐','御定全唐诗','yuding','','[]','金貂曉出鳳池頭，玉節前臨南雍州。暫輟洪爐觀劍戟，',40,'御定全唐詩/json/361.json','["金貂曉出鳳池頭，玉節前臨南雍州。暫輟洪爐觀劍戟，", "峴首風煙看未足，便應重拜富民侯。"]'),
('yuding-20','和蘇郎中尋豐安裏舊居寄主客張郎中','劉禹錫','唐','御定全唐诗','yuding','','[]','漳濱臥起恣閒遊，宣室征還未白頭。舊隱來尋通德里，',40,'御定全唐詩/json/361.json','["漳濱臥起恣閒遊，宣室征還未白頭。舊隱來尋通德里，", "同學同年又同舍，許君雲路並華輈。"]'),
('yuding-21','酬浙東李侍郎越州春晚即事長句','劉禹錫','唐','御定全唐诗','yuding','','[]','越中藹藹繁華地，秦望峰前禹穴西。湖草初生邊雁去，',40,'御定全唐詩/json/361.json','["越中藹藹繁華地，秦望峰前禹穴西。湖草初生邊雁去，", "明日漢庭征舊德，老人爭出若耶溪。"]'),
('yuding-22','酬淮南牛相公述舊見貽','劉禹錫','唐','御定全唐诗','yuding','','[]','少年曾忝漢庭臣，晚歲空餘老病身。初見相如成賦日，',40,'御定全唐詩/json/361.json','["少年曾忝漢庭臣，晚歲空餘老病身。初見相如成賦日，", "猶有登朝舊冠冕，待公三入拂埃塵。"]'),
('yuding-23','和僕射牛相公追感韋裴六相登庸皆四十餘未五十薨歿豈早榮早枯之義今年將六十猶粗強健因親故勸酒率然成篇并見寄之作','劉禹錫','唐','御定全唐诗','yuding','','[]','坐鎮清朝獨殷然，閑征故事數前賢。用才同踐鈞衡地，',40,'御定全唐詩/json/361.json','["坐鎮清朝獨殷然，閑征故事數前賢。用才同踐鈞衡地，", "猶憐綺季深山裏，唯有松風與石田。"]'),
('yuding-24','和僕射牛相公以離闕庭七年班行親故亡歿十無一人再睹龍顏喜慶雖極感歎風燭能不愴然因成四韻并示集賢中書二相公所和','劉禹錫','唐','御定全唐诗','yuding','','[]','久辭龍闕擁紅旗，喜見天顏拜赤墀。三省英寮非舊侶，',40,'御定全唐詩/json/361.json','["久辭龍闕擁紅旗，喜見天顏拜赤墀。三省英寮非舊侶，", "雲母屏風即施設，可憐榮耀冠當時。"]'),
('yuding-25','和僕射牛相公見示長句','劉禹錫','唐','御定全唐诗','yuding','','[]','靜得天和興自濃，不緣宦達性靈慵。大鵬六月有閑意，',40,'御定全唐詩/json/361.json','["靜得天和興自濃，不緣宦達性靈慵。大鵬六月有閑意，", "唯應加築露臺上，剩見終南雲外峰。"]'),
('yuding-26','和牛相公雨後寓懷見示','劉禹錫','唐','御定全唐诗','yuding','','[]','金火交爭正抑揚，蕭蕭飛雨助清商，曉看紈扇恩情薄，',40,'御定全唐詩/json/361.json','["金火交爭正抑揚，蕭蕭飛雨助清商，曉看紈扇恩情薄，", "當年富貴亦惆悵，何況悲翁發似霜。"]'),
('yuding-27','和陳許王尚書酬白少傅侍郎長句因通簡汝洛舊遊之什','劉禹錫','唐','御定全唐诗','yuding','','[]','寥廓高翔不可追，風雲失路暫相隨。方同洛下書生詠，',40,'御定全唐詩/json/361.json','["寥廓高翔不可追，風雲失路暫相隨。方同洛下書生詠，", "竹林一自王戎去，嵇阮雖貧興未衰。"]'),
('yuding-28','和僕射牛相公寓言二首','劉禹錫','唐','御定全唐诗','yuding','','[]','兩度竿頭立定誇，回眸舉袖拂青霞。盡拋今日貴人樣，',80,'御定全唐詩/json/361.json','["兩度竿頭立定誇，回眸舉袖拂青霞。盡拋今日貴人樣，", "具瞻尊重誠無敵，猶憶洛陽千樹花。", "心如止水鑒常明，見盡人間萬物情。雕鶚騰空猶逞俊，", "只恐重重世緣在，事須三度副蒼生。"]'),
('yuding-29','酬太原狄尚書見寄','劉禹錫','唐','御定全唐诗','yuding','','[]','家聲烜赫冠前賢，時望穹崇鎮北邊。身上官銜如座主，',40,'御定全唐詩/json/361.json','["家聲烜赫冠前賢，時望穹崇鎮北邊。身上官銜如座主，", "仍把天兵書號筆，遠題長句寄山川。"]'),
('yuding-30','酬宣州崔大夫見寄','劉禹錫','唐','御定全唐诗','yuding','','[]','白衣曾拜漢尚書，今日恩光到敝廬。再入龍樓稱綺季，',40,'御定全唐詩/json/361.json','["白衣曾拜漢尚書，今日恩光到敝廬。再入龍樓稱綺季，", "遙想敬亭春欲暮，百花飛盡柳花初。"]'),
('yuding-31','酬皇甫十少尹暮秋久雨喜晴有懷見示','劉禹錫','唐','御定全唐诗','yuding','','[]','雨餘獨坐捲簾帷，便得詩人喜霽詩。搖落從來長年感，',40,'御定全唐詩/json/361.json','["雨餘獨坐捲簾帷，便得詩人喜霽詩。搖落從來長年感，", "何況菊香新酒熟，神州司馬好狂時。"]'),
('yuding-32','再授連州至衡陽酬柳柳州贈別','劉禹錫','唐','御定全唐诗','yuding','','[]','去國十年同赴召，渡湘千里又分岐。重臨事異黃丞相，',40,'御定全唐詩/json/361.json','["去國十年同赴召，渡湘千里又分岐。重臨事異黃丞相，", "桂江東過連山下，相望長吟有所思。"]'),
('yuding-33','望夫山','劉禹錫','唐','御定全唐诗','yuding','','[]','何代提戈去不還，獨留形影白雲間。肌膚銷盡雪霜色，',40,'御定全唐詩/json/361.json','["何代提戈去不還，獨留形影白雲間。肌膚銷盡雪霜色，", "近來豈少征人婦，笑采蘼蕪上北山。"]'),
('yuding-34','懷妓','劉禹錫','唐','御定全唐诗','yuding','','[]','玉釵重合兩無緣，魚在深潭鶴在天。得意紫鸞休舞鏡，',160,'御定全唐詩/json/361.json','["玉釵重合兩無緣，魚在深潭鶴在天。得意紫鸞休舞鏡，", "若向蘼蕪山下過，遙將紅淚灑窮泉。", "鸞飛遠樹棲何處，鳳得新巢想稱心。紅壁尚留香漠漠，", "從此山頭似人石，丈夫形狀淚痕深。", "但曾行處遍尋看，雖是生離死一般。買笑樹邊花已老，", "莫怪詩成無淚滴，盡傾東海也須幹。", "三山不見海沉沉，豈有仙蹤更可尋。青鳥去時雲路斷，", "料得夜來天上鏡，只應偏照兩人心。"]'),
('yuding-35','答東陽於令寒碧圖詩','劉禹錫','唐','御定全唐诗','yuding','','[]','東陽本是佳山水，何況曾經沉隱侯。化得邦人解吟詠，',40,'御定全唐詩/json/361.json','["東陽本是佳山水，何況曾經沉隱侯。化得邦人解吟詠，", "落在尋常畫師手，猶能三伏凜生秋。"]'),
('yuding-36','麻姑山','劉禹錫','唐','御定全唐诗','yuding','','[]','曾遊仙跡見豐碑，除卻麻姑更有誰。雲蓋青山龍臥處，',40,'御定全唐詩/json/361.json','["曾遊仙跡見豐碑，除卻麻姑更有誰。雲蓋青山龍臥處，", "人到便須拋世事，稻田還擬種靈芝。"]'),
('yuding-37','自江陵沿流道中','劉禹錫','唐','御定全唐诗','yuding','','[]','三千三百西江水，自古如今要路津。月夜歌謠有漁父，',40,'御定全唐詩/json/361.json','["三千三百西江水，自古如今要路津。月夜歌謠有漁父，", "行到南朝征戰地，古來名將盡為神。"]'),
('yuding-38','別夔州官吏','劉禹錫','唐','御定全唐诗','yuding','','[]','三年楚國巴城守，一去揚州揚子津。青帳聯延喧驛步，',40,'御定全唐詩/json/361.json','["三年楚國巴城守，一去揚州揚子津。青帳聯延喧驛步，", "惟有九歌詞數首，裏中留與賽蠻神。"]'),
('yuding-39','魚複江中','劉禹錫','唐','御定全唐诗','yuding','','[]','扁舟盡室貧相逐，白髮藏冠鑷更加。遠水自澄終日綠，',40,'御定全唐詩/json/361.json','["扁舟盡室貧相逐，白髮藏冠鑷更加。遠水自澄終日綠，", "風檣好住貪程去，斜日青簾背酒家。"]'),
('yuding-40','巫山神女廟','劉禹錫','唐','御定全唐诗','yuding','','[]','巫山十二鬱蒼蒼，片石亭亭號女郎。曉霧乍開疑卷幔，',40,'御定全唐詩/json/361.json','["巫山十二鬱蒼蒼，片石亭亭號女郎。曉霧乍開疑卷幔，", "何事神仙九天上，人間來就楚襄王。"]'),
('yuding-41','柳絮','劉禹錫','唐','御定全唐诗','yuding','','[]','飄颺南陌起東鄰，漠漠濛濛暗度春。花巷暖隨輕舞蝶，',40,'御定全唐詩/json/361.json','["飄颺南陌起東鄰，漠漠濛濛暗度春。花巷暖隨輕舞蝶，", "何處好風偏似雪，隋河堤上古江津。"]'),
('yuding-42','贈同年陳長史員外','劉禹錫','唐','御定全唐诗','yuding','','[]','明州長史外台郎，憶昔同年翰墨場。一自分襟多歲月，',40,'御定全唐詩/json/361.json','["明州長史外台郎，憶昔同年翰墨場。一自分襟多歲月，", "所歎謬游東閣下，看君無計出恓惶。"]'),
('yuding-43','送周魯儒赴舉詩','劉禹錫','唐','御定全唐诗','yuding','','[]','宋日營陽內史孫，因家占得九疑村。童心便有愛書癖，',40,'御定全唐詩/json/361.json','["宋日營陽內史孫，因家占得九疑村。童心便有愛書癖，", "若逢廣坐問羊酪，從此知名在一言。"]'),
('yuding-44','送曹璩歸越中舊隱詩','劉禹錫','唐','御定全唐诗','yuding','','[]','行盡瀟湘萬里餘，少逢知己憶吾廬。數間茅屋閑臨水，',40,'御定全唐詩/json/361.json','["行盡瀟湘萬里餘，少逢知己憶吾廬。數間茅屋閑臨水，", "剡中若問連州事，唯有千山畫不如。"]'),
('yuding-45','白鷹','劉禹錫','唐','御定全唐诗','yuding','','[]','毛羽斒斕白紵裁，馬前擎出不驚猜。輕拋一點入雲去，',40,'御定全唐詩/json/361.json','["毛羽斒斕白紵裁，馬前擎出不驚猜。輕拋一點入雲去，", "都緣解搦生靈物，所以人人道俊哉。"]'),
('yuding-0','送工部張侍郎入蕃弔祭','劉禹錫','唐','御定全唐诗','yuding','','[]','月窟賓諸夏，雲官降九天。飾終鄰好重，錫命禮容全。',72,'御定全唐詩/json/362.json','["月窟賓諸夏，雲官降九天。飾終鄰好重，錫命禮容全。", "水咽猶登隴，沙鳴稍極邊。路因乘驛近，志為飲冰堅。", "毳帳差池見，烏旗搖曳前。歸來賜金石，榮耀自編年。"]'),
('yuding-1','早秋送台院楊侍禦歸朝','劉禹錫','唐','御定全唐诗','yuding','','[]','仙署棣華春，當時已絕倫。今朝丹闕下，更入白眉人。',72,'御定全唐詩/json/362.json','["仙署棣華春，當時已絕倫。今朝丹闕下，更入白眉人。", "重振高陽族，分居要路津。一門科第足，五府辟書頻。", "鷙鳥得秋氣，法星懸火旻。聖朝寰海靜，所至不埋輪。"]'),
('yuding-2','送陸侍禦歸淮南使府五韻','劉禹錫','唐','御定全唐诗','yuding','','[]','江左重詩篇，陸生名久傳。鳳城來已熟，羊酪不嫌膻。',60,'御定全唐詩/json/362.json','["江左重詩篇，陸生名久傳。鳳城來已熟，羊酪不嫌膻。", "歸路芙蓉府，離堂玳瑁筵。泰山呈臘雪，隋柳布新年。", "曾忝揚州薦，因君達短箋。"]'),
('yuding-3','送令狐相公自僕射出鎮南梁','劉禹錫','唐','御定全唐诗','yuding','','[]','夏木正陰成，戎裝出帝京。沾襟辭闕淚，回首別鄉情。',72,'御定全唐詩/json/362.json','["夏木正陰成，戎裝出帝京。沾襟辭闕淚，回首別鄉情。", "雲樹褒中路，風煙漢上城。前旌轉穀去，後騎踏橋聲。", "久領鴛行重，無嫌虎綬輕。終提一麾去，再入福蒼生。"]'),
('yuding-4','奉送裴司徒令公自東都留守再命太原','劉禹錫','唐','御定全唐诗','yuding','','[]','星使出關東，兵符賜上公。山河歸舊國，管鑰換離宮。',72,'御定全唐詩/json/362.json','["星使出關東，兵符賜上公。山河歸舊國，管鑰換離宮。", "行色旌旗動，軍聲鼓角雄。愛棠餘故吏，騎竹見新童。", "漢壘三秋靜，胡沙萬里空。其如天下望，旦夕詠清風。"]'),
('yuding-5','海陽湖別浩初師','劉禹錫','唐','御定全唐诗','yuding','','[]','近郭看殊境，獨游常鮮歡。逢君駐緇錫，觀貌稱林巒。',96,'御定全唐詩/json/362.json','["近郭看殊境，獨游常鮮歡。逢君駐緇錫，觀貌稱林巒。", "湖滿景方霽，野香春未闌。愛泉移席近，聞石輟棋看。", "風止松猶韻，花繁露未幹。橋形出樹曲，岩影落池寒。", "別路千嶂裏，詩情暮雲端。他年買山處，似此得隳官。"]'),
('yuding-6','許給事見示哭工部劉尚書詩因命同作','劉禹錫','唐','御定全唐诗','yuding','','[]','漢室賢王后，孔門高第人。濟時成國器，樂道任天真。',144,'御定全唐詩/json/362.json','["漢室賢王后，孔門高第人。濟時成國器，樂道任天真。", "特達圭無玷，堅貞竹有筠。總戎寬得眾，市義貴能貧。", "護塞無南牧，馳心拱北辰。乞身來闕下，賜告臥漳濱。", "榮耀初題劍，清羸已拖紳。宮星徒列位，隙日不回輪。", "自昔追飛侶，今為侍從臣。素弦哀已絕，青簡歎猶新。", "未遂揮金樂，空悲撤瑟晨。淒涼竹林下，無複見清塵。"]'),
('yuding-7','武陵書懷五十韻','劉禹錫','唐','御定全唐诗','yuding','','[]','西漢開支郡，南朝號戚藩。四封當列宿，百雉俯清沅。',576,'御定全唐詩/json/362.json','["西漢開支郡，南朝號戚藩。四封當列宿，百雉俯清沅。", "高岸朝霞合，驚湍激箭奔。積陰春暗度，將霽霧先昏。", "俗尚東皇祀，謠傳義帝冤。桃花迷隱跡，楝葉慰忠魂。", "戶算資漁獵，鄉豪恃子孫。照山畬火動，踏月俚歌喧。", "擁楫舟為市，連甍竹覆軒。披沙金粟見，拾羽翠翹翻。", "茗折蒼溪秀，蘋生枉渚暄。禽驚格磔起，魚戲噞喁繁。", "沉約台榭故，李衡墟落存。湘靈悲鼓瑟，泉客泣酬恩。", "露變蒹葭浦，星懸橘柚村。虎咆空野震，鼉作滿川渾。", "鄰里皆遷客，兒童習左言。炎天無冽井，霜月見芳蓀。", "清白家傳遠，詩書志所敦。列科叨甲乙，從宦出丘樊。", "結友心多契，馳聲氣尚吞。士安曾重賦，元禮許登門。", "草檄嫖姚幕，巡兵戊己屯。築台先自隗，送客獨留髡。", "遂結王畿綬，來觀衢室樽。鳶飛入鷹隼，魚目儷璵璠。", "曉燭羅馳道，朝陽辟帝閽。王正會夷夏，月朔盛旗幡。", "獨立當瑤闕，傳呵步紫垣。按章清犴獄，視祭潔蘋蘩。", "禦曆昌期遠，傳家寶祚蕃。繇文光夏啟，神教畏軒轅。", "內禪因天性，雄圖授化元。繼明懸日月，出震統乾坤。", "大孝三朝備，洪恩九族惇。百川宗渤澥，五嶽輔昆侖。", "何幸逢休運，微班識至尊。校緡資筦榷，複土奉山園。", "一失貴人意，徒聞太學論。直廬辭錦帳，遠守愧朱幡。", "巢幕方猶燕，搶榆尚笑鯤。邅回過荊楚，流落感涼溫。", "旅望花無色，愁心醉不惛。春江千里草，暮雨一聲猿。", "問卜安冥數，看方理病源。帶賒衣改制，塵澀劍成痕。", "三秀悲中散，二毛傷虎賁。來憂禦魑魅，歸願牧雞豚。"]'),
('yuding-8','早秋集賢院即事','劉禹錫','唐','御定全唐诗','yuding','','[]','金數已三伏，火星正西流。樹含秋露曉，閣倚碧天秋。',96,'御定全唐詩/json/362.json','["金數已三伏，火星正西流。樹含秋露曉，閣倚碧天秋。", "灰管應新律，銅壺添夜籌。商飆從朔塞，爽氣入神州。", "蕙草香書殿，愧花點禦溝。山明真色見，水靜濁煙收。", "早歲忝華省，再來成白頭。幸依群玉府，末路尚瀛洲。"]'),
('yuding-9','奉和吏部楊尚書太常李卿二相公策免後即事述懷贈答十韻','劉禹錫','唐','御定全唐诗','yuding','','[]','文雅關西族，衣冠趙北都。有聲真漢相，無纇勝隋珠。',120,'御定全唐詩/json/362.json','["文雅關西族，衣冠趙北都。有聲真漢相，無纇勝隋珠。", "當軸龍為友，臨池鳳不孤。九天開內殿，百辟看晨趨。", "誡滿澄欹器，成功別大壚。餘芳在公論，積慶是神扶。", "步武離台席，徊翔集帝梧。銓材秉秦鏡，典樂去齊竽。", "瀟灑風塵外，逢迎詩酒徒。唯應待華誥，更食萬錢廚。"]'),
('yuding-10','晚歲登武陵城顧望水陸悵然有作','劉禹錫','唐','御定全唐诗','yuding','','[]','星象承烏翼，蠻陬想犬牙。俚人祠竹節，仙洞閉桃花。',168,'御定全唐詩/json/362.json','["星象承烏翼，蠻陬想犬牙。俚人祠竹節，仙洞閉桃花。", "城基曆漢魏，江源自賨巴。華表廖王墓，菜地黃瓊家。", "霜輕菊秀晚，石淺水紋斜。樵音繞故壘，汲路明寒沙。", "凊風稍改葉，盧橘始含葩。野橋過驛騎，叢祠發迥笳。", "跳鱗避舉網，倦鳥寄行楂。路塵高出樹，山火遠連霞。", "夕曛轉赤岸，浮靄起蒼葭。軋軋渡水槳，連連赴林鴉。", "叫閽道非遠，賜環期自賒。孤臣本危涕，喬木在天涯。"]'),
('yuding-11','罷郡歸洛陽寄友人','劉禹錫','唐','御定全唐诗','yuding','','[]','遠謫年猶少，初歸鬢已衰。門閑故吏去，室靜老僧期。',72,'御定全唐詩/json/362.json','["遠謫年猶少，初歸鬢已衰。門閑故吏去，室靜老僧期。", "不見蜘蛛集，頻為佝僂欺。穎微囊未出，寒甚穀難吹。", "濩落唯心在，平生有己知。商歌夜深後，聽者竟為誰。"]'),
('yuding-12','經伏波神祠','劉禹錫','唐','御定全唐诗','yuding','','[]','濛濛篁竹下，有路上壺頭。漢壘麏鼯鬥，蠻溪霧雨愁。',72,'御定全唐詩/json/362.json','["濛濛篁竹下，有路上壺頭。漢壘麏鼯鬥，蠻溪霧雨愁。", "懷人敬遺像，閱世指東流。自負霸王略，安知恩澤侯。", "鄉園辭石柱，筋力盡炎洲。一以功名累，翻思馬少遊。"]'),
('yuding-13','和汴州令狐相公到鎮改月偶書所懷','劉禹錫','唐','御定全唐诗','yuding','','[]','受脤新梁苑，和羹舊傅岩。援毫動星宿，垂釣取韜鈐。',264,'御定全唐詩/json/362.json','["受脤新梁苑，和羹舊傅岩。援毫動星宿，垂釣取韜鈐。", "赫奕三川至，歡呼百姓瞻。綠油貔虎擁，青紙鳳凰銜。", "外壘曾無警，中廚亦罷監。推誠人自服，去殺令逾嚴。", "赳赳容皆飾，幡幡口盡鉗。為兄憐庾翼，選婿得蕭咸。", "鬱倔咽喉地，駢臻水陸兼。度橋鳴紺幰，入肆颺雲帆。", "端月當中氣，東風應遠占。管弦喧夜景，燈燭掩寒蟾。", "酒每傾三雅，書能發百函。詞人羞布鼓，遠客獻貂襜。", "歌榭白團扇，舞筵金縷衫。旌旗遙一簇，舄履近相攙。", "花樹當朱閣，晴河逼翠簾。衣風飄靉靆，燭淚滴巉岩。", "玉斝虛頻易，金爐暖更添。映鐶窺豔豔，隔袖見纖纖。", "謝傅何由接，桓伊定不凡。應憐郡齋老，旦夕鑷霜髯。"]'),
('yuding-14','遙賀白賓客分司初到洛中，戲呈馮尹','劉禹錫','唐','御定全唐诗','yuding','','[]','西辭望苑去，東占洛陽才。度嶺無愁思，看山不懊來。',72,'御定全唐詩/json/362.json','["西辭望苑去，東占洛陽才。度嶺無愁思，看山不懊來。", "冥鴻何所慕，遼鶴乍飛回。洗竹通新徑，攜琴上舊台。", "塵埃長者轍，風月故人杯。聞道龍門峻，還因上客開。"]'),
('yuding-15','白侍郎大尹自河南寄示池北新茸水齋即事招賓十四韻兼命同作','劉禹錫','唐','御定全唐诗','yuding','','[]','公府有高政，新齋池上開。再吟佳句後，一似畫圖來。',168,'御定全唐詩/json/362.json','["公府有高政，新齋池上開。再吟佳句後，一似畫圖來。", "結構疏林下，夤緣曲岸隈。綠波穿戶牖，碧甃疊瓊瑰。", "幽異當軒滿，清光繞砌回。潭心澄晚鏡，渠口起晴雷。", "瑤草緣堤種，松煙上島栽。遊魚驚撥剌，浴鷺喜毰毸。", "為客烹林筍，因僧採石苔。酒瓶常不罄，書案任成堆。", "簷外青雀舫，坐中鸚鵡杯。蒲根抽九節，蓮萼捧重台。", "芳訊此時到，勝游何日陪。共譏吳太守，自占洛陽才。"]'),
('yuding-16','和令狐相公謝太原李侍中寄蒲桃','劉禹錫','唐','御定全唐诗','yuding','','[]','珍果出西域，移根到北方。昔年隨漢使，今日寄梁王。',96,'御定全唐詩/json/362.json','["珍果出西域，移根到北方。昔年隨漢使，今日寄梁王。", "上相芳緘至，行台綺席張。魚鱗含宿潤，馬乳帶殘霜。", "染指鉛粉膩，滿喉甘露香。醞成十日酒，味敵五雲漿。", "咀嚼停金盞，稱嗟響畫堂。慚非末至客，不得一枝嘗。"]'),
('yuding-17','和令狐相公玩白菊','劉禹錫','唐','御定全唐诗','yuding','','[]','家家菊盡黃，梁國獨如霜。瑩靜真琪樹，分明對玉堂。',96,'御定全唐詩/json/362.json','["家家菊盡黃，梁國獨如霜。瑩靜真琪樹，分明對玉堂。", "仙人披雪氅，素女不紅妝。粉蝶來難見，麻衣拂更香。", "向風搖羽扇，含露滴瓊漿。高豔遮銀井，繁枝覆象床。", "桂叢慚併發，梅蕊妒先芳。一入瑤華詠，從茲播樂章。"]'),
('yuding-18','令狐相公見示新栽蕙蘭二草之什，兼命同作','劉禹錫','唐','御定全唐诗','yuding','','[]','上國庭前草，移來漢水潯。朱門雖易地，玉樹有餘陰。',72,'御定全唐詩/json/362.json','["上國庭前草，移來漢水潯。朱門雖易地，玉樹有餘陰。", "豔彩凝還泛，清香絕複尋。光華童子佩，柔軟美人心。", "惜晚含遠思，賞幽空獨吟。寄言知音者，一奏風中琴。"]'),
('yuding-19','和令狐相公南齋小宴聽阮咸','劉禹錫','唐','御定全唐诗','yuding','','[]','阮巷久蕪沉，四弦有遺音。雅聲發蘭室，遠思含竹林。',72,'御定全唐詩/json/362.json','["阮巷久蕪沉，四弦有遺音。雅聲發蘭室，遠思含竹林。", "座絕眾賓語，庭移芳樹陰。飛觴助真氣，寂聽無流心。", "影似白團扇，調諧朱弦琴。一毫不平意，幽怨古猶今。"]'),
('yuding-20','和令狐相公九日對黃白二菊花見懷','劉禹錫','唐','御定全唐诗','yuding','','[]','素萼迎寒秀，金英帶露香。繁華照旄鉞，榮盛對銀黃。',72,'御定全唐詩/json/362.json','["素萼迎寒秀，金英帶露香。繁華照旄鉞，榮盛對銀黃。", "琮璧交輝映，衣裳雜彩章。晴雲遙蓋覆，秋蝶近悠揚。", "空想逢九日，何由陪一觴。滿叢佳色在，未肯委嚴霜。"]'),
('yuding-21','令狐僕射與余投分素深縱山川阻修然音問相繼今年十一月僕射疾不起聞予已承訃書寢門長慟後日有使者兩輩持書并詩計其日時已是臥疾手筆盈幅翰墨尚新律詞一篇音韻彌切收淚握管以成報章雖廣陵之弦於今絕矣而蓋泉之感猶庶聞焉焚之繐帳之前附于舊編之末','劉禹錫','唐','御定全唐诗','yuding','','[]','前日寢門慟，至今悲有餘。已嗟萬化盡，方見八行書。',96,'御定全唐詩/json/362.json','["前日寢門慟，至今悲有餘。已嗟萬化盡，方見八行書。", "滿紙傳相憶，裁詩怨索居。危弦音有絕，哀玉韻猶虛。", "忽歎幽明異，俄驚歲月除。文章雖不朽，精魄竟焉如。", "零淚沾青簡，傷心見素車。淒涼從此後，無複望雙魚。"]'),
('yuding-22','和樂天閒園獨賞八韻前以蜂鶴拙句寄呈今辱蝸蟻妍詞見答因成小巧以取大哈','劉禹錫','唐','御定全唐诗','yuding','','[]','永日無人事，芳園任興行。陶廬樹可愛，潘宅雨新晴。',96,'御定全唐詩/json/362.json','["永日無人事，芳園任興行。陶廬樹可愛，潘宅雨新晴。", "傅粉琅玕節，熏香菡萏莖。榴花裙色好，桐子藥丸成。", "柳蠹枝偏亞，桑空葉再生。睢盱欲鬥雀，索漠不言鶯。", "動植隨四氣，飛沉含五情。搶榆與水擊，小大強為名。"]'),
('yuding-23','奉和裴令公新成綠野堂即書','劉禹錫','唐','御定全唐诗','yuding','','[]','藹藹鼎門外，澄澄洛水灣。堂皇臨綠野，坐臥看青山。',120,'御定全唐詩/json/362.json','["藹藹鼎門外，澄澄洛水灣。堂皇臨綠野，坐臥看青山。", "位極卻忘貴，功成欲愛閑。官名司管鑰，心術去機關。", "禁苑淩晨出，園花及露攀。池塘魚撥剌，竹徑鳥綿蠻。", "志在安瀟灑，嘗經歷險艱。高情方造適，眾意望征還。", "好客交珠履，華筵舞玉顏。無因隨賀燕，翔集畫梁間。"]'),
('yuding-24','三月三日與樂天及河南李尹奉陪裴令公泛洛褉飲各賦十二韻','劉禹錫','唐','御定全唐诗','yuding','','[]','洛下今修禊，群賢勝會稽。盛筵陪玉鉉，通籍盡金閨。',144,'御定全唐詩/json/362.json','["洛下今修禊，群賢勝會稽。盛筵陪玉鉉，通籍盡金閨。", "波上神仙妓，岸傍桃李蹊。水嬉如鷺振，歌響雜鶯啼。", "曆覽風光好，沿洄意思迷。棹歌能儷曲，墨客競分題。", "翠幄連雲起，香車向道齊。人誇綾步障，馬惜錦障泥。", "塵暗宮牆外，霞明苑樹西。舟形隨鷁轉，橋影與虹低。", "川色晴猶遠，烏聲暮欲棲。唯餘踏青伴，待月魏王堤。"]'),
('yuding-25','樂天少傅五月長齋廣延緇徒謝絕文友坐成暌間因以戲之','劉禹錫','唐','御定全唐诗','yuding','','[]','五月長齋戒，深居絕送迎。不離通德里，便是法王城。',120,'御定全唐詩/json/362.json','["五月長齋戒，深居絕送迎。不離通德里，便是法王城。", "舉目皆僧事，全家少俗情。精修無上道，結念未來生。", "賓合緇衣占，書堂信鼓鳴。戲童為塔象，啼鳥學經聲。", "黍用青菰角，葵承玉露烹。馬家供薏苡，劉氏餉蕪菁。", "暗網籠歌扇，流塵晦酒鐺。不知何次道，作佛幾時成。"]'),
('yuding-26','酬樂天晚夏閒居欲相訪先以詩見貽','劉禹錫','唐','御定全唐诗','yuding','','[]','池榭堪臨泛，翛然散郁陶。步因驅鶴緩，吟為聽蟬高。',72,'御定全唐詩/json/362.json','["池榭堪臨泛，翛然散郁陶。步因驅鶴緩，吟為聽蟬高。", "林密添新竹，枝低縋晚桃。酒醅晴易熟，藥圃夏頻薅。", "老是班行舊，閑為鄉里豪。經過更何處，風景屬吾曹。"]'),
('yuding-27','酬樂天醉後狂吟十韻','劉禹錫','唐','御定全唐诗','yuding','','[]','散誕人間樂，逍遙地上仙。詩家登逸品，釋氏悟真筌。',120,'御定全唐詩/json/362.json','["散誕人間樂，逍遙地上仙。詩家登逸品，釋氏悟真筌。", "制誥留台閣，歌詞入管弦。處身于木雁，任世變桑田。", "吏隱情兼遂，儒玄道兩全。八關齋適罷，三雅興尤偏。", "文墨中年舊，松筠晚歲堅。魚書曾替代，香火有因緣。", "欲向醉鄉去，猶為色界牽。好吹楊柳曲，為我舞金鈿。"]'),
('yuding-28','牛相公見示新什，謹依本韻次用以抒下情','劉禹錫','唐','御定全唐诗','yuding','','[]','劇韻新篇至，因難始見能。雨天龍變化，晴日鳳鶱騰。',168,'御定全唐詩/json/362.json','["劇韻新篇至，因難始見能。雨天龍變化，晴日鳳鶱騰。", "游海驚何極，聞韶素不曾。愜心時拊髀，擊節日麾肱。", "符彩添隃墨，波瀾起剡藤。揀金光熠熠，累璧勢層層。", "珠媚多藏賈，花撩欲定僧。封來真寶物，寄與愧交朋。", "已老無時疾，長貧望歲登。雀羅秋寂寂，蟲翅曉薨薨。", "羸驥方辭絆，虛舟已絕縆。榮華甘死別，健羨亦生憎。", "玉柱琤瑽韻，金觥雹凸棱。何時良宴會，促膝對華燈。"]'),
('yuding-29','奉和中書崔舍人八月十五日夜玩月二十韻','劉禹錫','唐','御定全唐诗','yuding','','[]','暮景中秋爽，陰靈既望圓。浮精離碧海，分照接虞淵。',240,'御定全唐詩/json/362.json','["暮景中秋爽，陰靈既望圓。浮精離碧海，分照接虞淵。", "迥見孤輪出，高從倚蓋旋。二儀含皎澈，萬象共澄鮮。", "整禦當西陸，舒光麗上玄。從星變風雨，順日助陶甄。", "遠近同時望，晶熒此夜偏。運行調玉燭，潔白應金天。", "曲沼疑瑤鏡，通衢若象筵。逢人盡冰雪，遇景即神仙。", "引素吞銀漢，凝清洗綠煙。皋禽警露下，鄰杵思風前。", "水是還珠浦，山成種玉田。劍沉三尺影，燈罷九枝然。", "象外形無跡，寰中影有遷。稍當雲闕正，未映鬥城懸。", "靜對揮宸翰，閑臨襞彩箋。境同牛渚上，宿在鳳池邊。", "興掩尋安道，詞勝命仲宣。從今紙貴後，不復詠陳篇。"]'),
('yuding-30','奉和淮南李相公早秋即事，寄成都武相公','劉禹錫','唐','御定全唐诗','yuding','','[]','八柱共承天，東西別隱然。遠夷爭慕化，真相故臨邊。',144,'御定全唐詩/json/362.json','["八柱共承天，東西別隱然。遠夷爭慕化，真相故臨邊。", "並進夔龍位，仍齊龜鶴年。同心舟已濟，造膝璧常聯。", "對領專征寄，遙持造物權。鬥牛添氣色，井絡靜氛煙。", "獻可通三略，分甘出萬錢。漢南趨節制，趙北賜山川。", "玉帳觀渝舞，虹旌獵楚田。步嫌雙綬重，夢入九城偏。", "秋雨離情動，新詩樂府傳。聆音還竊抃，不覺撫麼弦。"]'),
('yuding-31','元和癸巳歲仲秋詔發江陵偏師問罪蠻徼命宣慰釋兵歸降凱旋之辰率爾成詠寄荊南嚴司空','劉禹錫','唐','御定全唐诗','yuding','','[]','蠻水阻朝宗，兵符下渚宮。前籌得上策，無戰已成功。',144,'御定全唐詩/json/362.json','["蠻水阻朝宗，兵符下渚宮。前籌得上策，無戰已成功。", "漢使星飛入，夷心草偃同。歌謠開竹棧，拜舞戢桑弓。", "就日知冰釋，投人念鳥窮。網羅三面解，章奏九門通。", "卉服聯操袂，雕題盡鞠躬。降幡秋練白，驛騎晝塵紅。", "火號休傳警，機橋罷亙空。登山不見虜，振旆自生風。", "江遠煙波靜，軍回氣色雄。佇看聞喜後，金石賜元戎。"]'),
('yuding-0','和李六侍禦文宣王廟釋奠作','劉禹錫','唐','御定全唐诗','yuding','','[]','歎息魯先師，生逢周室卑。有心律天道，無位救陵夷。',120,'御定全唐詩/json/363.json','["歎息魯先師，生逢周室卑。有心律天道，無位救陵夷。", "曆聘不能用，領徒空爾為。儒風正禮樂，旅象入蓍龜。", "西狩非其應，中都安足施。世衰由我賤，泣下為人悲。", "遺教光文德，興王葉夢期。土田封後胤，冕服飾虛儀。", "鐘鼓膠庠薦，牲牢郡邑祠。聞君喟然歎，偏在上丁時。"]'),
('yuding-1','和竇中丞晚入容江作','劉禹錫','唐','御定全唐诗','yuding','','[]','漢郡三十六，郁林東南遙。人倫選清臣，天外頒詔條。',96,'御定全唐詩/json/363.json','["漢郡三十六，郁林東南遙。人倫選清臣，天外頒詔條。", "桂水步秋浪，火山淩霧朝。分圻辨風物，入境聞謳謠。", "莎岸見長亭，煙林隔麗譙。日落舟益駛，川平旗自飄。", "珠浦遠明滅，金沙晴動搖。一吟道中作，離思懸層霄。"]'),
('yuding-2','南海馬大夫見惠著述三通勒成四帙上自邃古達于國朝采其菁華至簡如富欽受嘉貺詩以謝之','劉禹錫','唐','御定全唐诗','yuding','','[]','紅旗閱五兵，絳帳領諸生。味道輕鼎食，退公猶筆耕。',72,'御定全唐詩/json/363.json','["紅旗閱五兵，絳帳領諸生。味道輕鼎食，退公猶筆耕。", "青箱傳學遠，金匱納書成。一瞬見前事，九流當抗行。", "編蒲曾苦思，垂竹愧無名。今日承芳訊，誰言贈袞榮。"]'),
('yuding-3','和楊侍郎初至郴州紀事書情題郡齋八韻','劉禹錫','唐','御定全唐诗','yuding','','[]','旌節下朝台，分圭從北回。城頭鶴立處，驛樹鳳棲來。',96,'御定全唐詩/json/363.json','["旌節下朝台，分圭從北回。城頭鶴立處，驛樹鳳棲來。", "舊路芳塵在，新恩馹騎催。裏閭風偃草，鼓舞抃成雷。", "吏散山禽囀，庭香夏蕊開。郡齋堪四望，壁記有三台。", "人訝征黃晚，文非吊屈哀。一吟梁甫曲，知是臥龍才。"]'),
('yuding-4','和東川王相公新漲驛池八韻','劉禹錫','唐','御定全唐诗','yuding','','[]','今日池塘上，初移造物權。苞蔵成別島，沿濁致清漣。',96,'御定全唐詩/json/363.json','["今日池塘上，初移造物權。苞蔵成別島，沿濁致清漣。", "變化生言下，蓬瀛落眼前。泛觴驚翠羽，開幕對紅蓮。", "遠寫風光入，明含氣象全。渚煙籠驛樹，波日漾賓筵。", "曲岸留緹騎，中流轉彩船。無因接元禮，共載比神仙。"]'),
('yuding-5','酬楊八庶子喜韓吳興與餘同遷見贈','劉禹錫','唐','御定全唐诗','yuding','','[]','早遇聖明朝，雁行登九霄。文輕傅武仲，酒逼蓋寬饒。',192,'御定全唐詩/json/363.json','["早遇聖明朝，雁行登九霄。文輕傅武仲，酒逼蓋寬饒。", "舍矢同瞻鵠，當筵共賽梟。琢磨三益重，唱和五音調。", "台柏煙常起，池荷香暗飄。星文辭北極，旗影度東遼。", "直道由來黜，浮名豈敢要。三湘與百越，雨散又雲搖。", "遠守慚侯籍，征還荷詔條。悴容唯舌在，別恨幾魂銷。", "滿眼悲陳事，逢人少舊僚。煙霞為老伴，蒲柳任先凋。", "虎綬懸新印，龍舼理去橈。斷腸天北郡，攜手洛陽橋。", "幢蓋今雖貴，弓旌會見招。其如草玄客，空宇久寥寥。"]'),
('yuding-6','和兵部鄭侍郎省中四松詩十韻','劉禹錫','唐','御定全唐诗','yuding','','[]','右相曆中台，移松武庫栽。紫茸抽組綬，青實長玫瑰。',120,'御定全唐詩/json/363.json','["右相曆中台，移松武庫栽。紫茸抽組綬，青實長玫瑰。", "便有幹霄勢，看成構廈材。數分天柱半，影逐日輪回。", "舊賞臺階去，新知穀口來。息陰常仰望，玩境幾裴回。", "翠粒晴懸露，蒼鱗雨起苔。凝音助瑤瑟，飄蕊泛金罍。", "月桂花遙燭，星榆葉對開。終須似雞樹，榮茂近昭回。"]'),
('yuding-7','酬鄭州權舍人見寄二十韻','劉禹錫','唐','御定全唐诗','yuding','','[]','朱戶淩晨啟，碧梧含早涼。人從桔柣至，書到漆沮傍。',240,'御定全唐詩/json/363.json','["朱戶淩晨啟，碧梧含早涼。人從桔柣至，書到漆沮傍。", "抃會因佳句，情深取斷章。愜心同笑語，入耳勝笙簧。", "憶昔三條路，居鄰數仞牆。學堂青玉案，彩服紫羅囊。", "麟角看成就，龍駒見抑揚。彀中飛一箭，雲際落雙鶬。", "甸邑叨前列，天臺愧後行。鯉庭傳事業，雞樹遂翱翔。", "書殿連鳷鵲，神池接鳳凰。追游蒙尚齒，惠好結中腸。", "鎩翮方抬舉，危根易損傷。一麾憐棄置，五字借恩光。", "汝海崆峒秀，溱流芍藥芳。風行能偃草，境靜不爭桑。", "轉旆趨關右，頒條匝渭陽。病吟猶有思，老醉已無狂。", "塵滿鴻溝道，沙驚白狄鄉。佇聞黃紙詔，促召紫微郎。"]'),
('yuding-8','和牛相公題姑蘇所寄太湖石兼寄李蘇州','劉禹錫','唐','御定全唐诗','yuding','','[]','震澤生奇石，沉潛得地靈。初辭水府出，猶帶龍宮腥。',240,'御定全唐詩/json/363.json','["震澤生奇石，沉潛得地靈。初辭水府出，猶帶龍宮腥。", "發自江湖國，來榮卿相庭。從風夏雲勢，上漢古查形。", "拂拭魚鱗見，鏗鏘玉韻聆。煙波含宿潤，苔蘚助新青。", "嵌穴胡雛貌，纖鋩蟲篆銘。孱顏傲林薄，飛動向雷霆。", "煩熱近還散，餘酲見便醒。凡禽不敢息，浮壒莫能停。", "靜稱垂松蓋，鮮宜映鶴翎。忘憂常目擊，素尚與心冥。", "眇小欺湘燕，團圓笑落星。徒然想融結，安可測年齡。", "採取詢鄉耋，搜求按舊經。垂鉤入空隙，隔浪動晶熒。", "有獲人爭賀，歡謠眾共聽。一州驚閱寶，千里遠揚舲。", "睹物洛陽陌，懷人吳禦亭。寄言垂天翼，早晚起滄溟。"]'),
('yuding-9','浙西李大夫述夢四十韻並浙東元相公酬和斐然繼聲','劉禹錫','唐','御定全唐诗','yuding','','[]','位是才能取，時因際會遭。羽儀呈鸑鷟，鋩刃試豪曹。',480,'御定全唐詩/json/363.json','["位是才能取，時因際會遭。羽儀呈鸑鷟，鋩刃試豪曹。", "洛下推年少，山東許地高。門承金鉉鼎，家有玉璜韜。", "海浪扶鵬翅，天風引驥髦。便知蓬閣閟，不識魯衣褒。", "興發春塘草，魂交益部刀。形開猶抱膝，燭盡遽揮毫。", "昔仕當初筮，逢時詠載橐。懷鉛辨蟲蠹，染素學鵝毛。", "車騎方休汝，歸來欲效陶。南台資謇諤，內署選風騷。", "羽化如乘鯉，樓居舊冠鼇。美香焚濕麝，名果賜幹萄。", "議赦蠅棲筆，邀歌蟻泛醪。代言無所戲，謝表自稱叨。", "蘭焰凝芳澤，芝泥瑩玉膏。對頻聲價出，直久夢魂勞。", "草詔令歸馬，批章答獻獒。銀花懸院榜，翠羽映簾絛。", "諷諫欣然納，奇觚率爾操。禁中時諤諤，天下免忉忉。", "左顧龜成印，雙飛鵠織袍。謝賓緣地密，潔己是心豪。", "五日思歸沐，三春羨眾邀。茶爐依綠筍，棋局就紅桃。", "溟海桑潛變，陰陽炭暗熬。仙成脫屣去，臣戀捧弓號。", "建節辭烏柏，宣風看鷺濤。土山京口峻，鐵甕郡城牢。", "曲島花千樹，官池水一篙。鶯來和絲管，雁起拂麾旄。", "宛轉傾羅扇，迴旋墮玉搔。罰籌長豎纛，觥盞樣如舠。", "山是千重障，江為四面濠。臥龍曾得雨，孤鶴尚鳴皋。", "劍用雄開匣，弓閑蟄受弢。鳳姿嘗在竹，鷃羽不離蒿。", "吳越分雙鎮，東西接萬艘。今朝比潘陸，江海更滔滔。"]'),
('yuding-10','和浙西李大夫伊川卜居','劉禹錫','唐','御定全唐诗','yuding','','[]','早入八元數，嘗承三接恩。飛鳴天上路，鎮壓海西門。',144,'御定全唐詩/json/363.json','["早入八元數，嘗承三接恩。飛鳴天上路，鎮壓海西門。", "清望寰中許，高情物外存。時來誠不讓，歸去每形言。", "洛下思招隱，江幹厭作藩。按經修道具，依樣買山村。", "開鑿隨人化，幽陰為律暄。遠移難得樹，立變舊荒園。", "絕塞通潛徑，平泉占上原。煙霞遙在想，簿領益為繁。", "丹禁虛東合，蒼生望北轅。徒令雙白鶴，五裏自翩翻。"]'),
('yuding-11','省試風光草際浮','劉禹錫','唐','御定全唐诗','yuding','','[]','熙熙春景霽，草綠春光麗。的曆亂相鮮，葳蕤互虧蔽。',72,'御定全唐詩/json/363.json','["熙熙春景霽，草綠春光麗。的曆亂相鮮，葳蕤互虧蔽。", "乍疑芊綿裏，稍動豐茸際。影碎翻崇蘭，浮香轉叢蕙。", "含煙絢碧彩，帶露如珠綴。幸因采掇日，況此臨芳歲。"]'),
('yuding-12','曆陽書事七十韻','劉禹錫','唐','御定全唐诗','yuding','','[]','一夕為湖地，千年列郡名。霸王迷路處，亞父所封城。',576,'御定全唐詩/json/363.json','["一夕為湖地，千年列郡名。霸王迷路處，亞父所封城。", "漢置東南尉，梁分肘腋兵。本吳風俗剽，兼楚語音傖。", "沸井今無湧，烏江舊有名。土台游柱史，石室隱彭鏗。", "曹操祠猶在，濡須塢未平。海潮隨月大，江水應春生。", "憶昨深山裏，終朝看火耕。魚書來北闕，鷁首下南荊。", "雲雨巫山暗，蕙蘭湘水清。章華樹已失，鄂渚草來迎。", "廬阜香爐出，湓城粉堞明。雁飛彭蠡暮，鴉噪大雷晴。", "平野分風使，恬和趁夜程。貴池登陸峻，舂穀渡橋鳴。", "駱驛主人問，悲歡故舊情。幾年方一面，蔔晝便三更。", "助喜杯盤盛，忘機笑語訇。管清疑警鶴，弦巧似嬌鶯。", "熾炭烘蹲獸，華茵織鬥鯨。回裾飄霧雨，急節墮瓊英。", "斂黛凝愁色，施鈿耀翠晶。容華本南國，妝束學西京。", "日落方收鼓，天寒更炙笙。促筵交履舄，痛飲倒簪纓。", "謔浪容優孟，嬌憐許智瓊。蔽明添翠帟，命燭拄金莖。", "坐久羅衣皺，杯頻粉面騂。興來從請曲，意墮即飛觥。", "令急重須改，歡馮醉盡呈。詰朝還選勝，來日又尋盟。", "道別殷勤惜，邀筵次第爭。唯聞嗟短景，不復有餘酲。", "眾散扃朱戶，相攜話素誠。晤言猶亹亹，殘漏自丁丁。", "出祖千夫擁，行廚五熟烹。離亭臨野水，別思入哀箏。", "接境人情洽，方冬饌具精。中流為界道，隔岸數飛甍。", "沙浦王渾鎮，滄洲謝脁城。望夫人化石，夢帝日環營。", "半渡趨津吏，緣堤簇郡甿。場黃堆晚稻，籬碧見冬菁。", "裏社爭來獻，壺漿各自擎。鴟夷傾底寫，粔籹鬥成□。", "採石風傳柝，新林暮擊鉦。繭綸牽撥剌，犀焰照澄泓。"]'),
('yuding-13','和武中丞秋日寄懷簡諸僚故','劉禹錫','唐','御定全唐诗','yuding','','[]','退朝還公府，騎吹息繁陰。吏散秋庭寂，烏啼煙樹深。',96,'御定全唐詩/json/363.json','["退朝還公府，騎吹息繁陰。吏散秋庭寂，烏啼煙樹深。", "威生奉白簡，道勝外華簪。風物清遠目，功名懷寸陰。", "雲衢念前侶，彩翰寫沖襟。涼菊照幽徑，敗荷攢碧潯。", "感時江海思，報國松筠心。空愧壽陵步，芳塵何處尋。"]'),
('yuding-14','和令狐相公春日尋花有懷白侍郎閣老','劉禹錫','唐','御定全唐诗','yuding','','[]','芳菲滿雍州，鸞鳳許同遊。花徑須深入，時光不少留。',72,'御定全唐詩/json/363.json','["芳菲滿雍州，鸞鳳許同遊。花徑須深入，時光不少留。", "色鮮由樹嫩，枝亞為房稠。靜對仍持酒，高看特上樓。", "晴宜連夜賞，雨便一年休。共憶秋官處，餘霞曲水頭。"]'),
('yuding-0','荊州歌二首','劉禹錫','唐','御定全唐诗','yuding','','[]','渚宮楊柳暗，麥城朝雉飛。可憐踏青伴，乘暖著輕衣。',48,'御定全唐詩/json/364.json','["渚宮楊柳暗，麥城朝雉飛。可憐踏青伴，乘暖著輕衣。", "今日好南風，商旅相催發。沙頭檣竿上，始見春江闊。"]'),
('yuding-1','紀南歌','劉禹錫','唐','御定全唐诗','yuding','','[]','風煙紀南城，塵土荊門路。天寒多獵騎，走上樊姬墓。',24,'御定全唐詩/json/364.json','["風煙紀南城，塵土荊門路。天寒多獵騎，走上樊姬墓。"]'),
('yuding-2','視刀環歌','劉禹錫','唐','御定全唐诗','yuding','','[]','常恨言語淺，不如人意深。今朝兩相視，脈脈萬重心。',24,'御定全唐詩/json/364.json','["常恨言語淺，不如人意深。今朝兩相視，脈脈萬重心。"]'),
('yuding-3','三閣辭四首','劉禹錫','唐','御定全唐诗','yuding','','[]','貴人三閣上，日晏未梳頭。不應有恨事，嬌甚卻成愁。',96,'御定全唐詩/json/364.json','["貴人三閣上，日晏未梳頭。不應有恨事，嬌甚卻成愁。", "珠箔曲瓊鉤，仔細見揚州。北兵那得度，浪話判悠悠。", "沉香帖閣柱，金縷畫門楣。回首降幡下，已見黍離離。", "三人出眢井，一身登檻車。朱門漫臨水，不可見鱸魚。"]'),
('yuding-4','紇那曲二首','劉禹錫','唐','御定全唐诗','yuding','','[]','楊柳鬱青青，竹枝無限情。周郎一回顧，聽唱紇那聲。',48,'御定全唐詩/json/364.json','["楊柳鬱青青，竹枝無限情。周郎一回顧，聽唱紇那聲。", "踏曲興無窮，調同詞不同。願郎千萬壽，長作主人翁。"]'),
('yuding-5','淮陰行五首','劉禹錫','唐','御定全唐诗','yuding','','[]','簇簇淮陰市，竹樓緣岸上。好日起檣竿，烏飛驚五兩。',120,'御定全唐詩/json/364.json','["簇簇淮陰市，竹樓緣岸上。好日起檣竿，烏飛驚五兩。", "今日轉船頭，金烏指西北。煙波與春草，千里同一色。", "船頭大銅鐶，摩挲光陣陣。早早使風來，沙頭一眼認。", "何物令儂羨，羨郎船尾燕。銜泥趁檣竿，宿食長相見。", "隔浦望行船，頭昂尾幰幰。無奈晚來時，清淮春浪軟。"]'),
('yuding-6','渾侍中宅牡丹','劉禹錫','唐','御定全唐诗','yuding','','[]','徑尺千餘朵，人間有此花。今朝見顏色，更不向諸家。',24,'御定全唐詩/json/364.json','["徑尺千餘朵，人間有此花。今朝見顏色，更不向諸家。"]'),
('yuding-7','詠紅柿子','劉禹錫','唐','御定全唐诗','yuding','','[]','曉連星影出，晚帶日光懸。本因遺采掇，翻自保天年。',24,'御定全唐詩/json/364.json','["曉連星影出，晚帶日光懸。本因遺采掇，翻自保天年。"]'),
('yuding-8','呂八見寄郡內書懷因而戲和','劉禹錫','唐','御定全唐诗','yuding','','[]','文苑振金聲，循良冠百城。不知今史氏，何處列君名。',24,'御定全唐詩/json/364.json','["文苑振金聲，循良冠百城。不知今史氏，何處列君名。"]'),
('yuding-9','秋風引','劉禹錫','唐','御定全唐诗','yuding','','[]','何處秋風至，蕭蕭送雁群。朝來入庭樹，孤客最先聞。',24,'御定全唐詩/json/364.json','["何處秋風至，蕭蕭送雁群。朝來入庭樹，孤客最先聞。"]'),
('yuding-10','柳花詞三首','劉禹錫','唐','御定全唐诗','yuding','','[]','開從綠條上，散逐香風遠。故取花落時，悠揚占春晚。',72,'御定全唐詩/json/364.json','["開從綠條上，散逐香風遠。故取花落時，悠揚占春晚。", "輕飛不假風，輕落不委地。撩亂舞晴空，發人無限思。", "晴天闇闇雪，來送青春暮。無意似多情，千家萬家去。"]'),
('yuding-11','路傍曲','劉禹錫','唐','御定全唐诗','yuding','','[]','南山宿雨晴，春入鳳凰城。處處聞弦管，無非送酒聲。',24,'御定全唐詩/json/364.json','["南山宿雨晴，春入鳳凰城。處處聞弦管，無非送酒聲。"]'),
('yuding-12','君山懷古','劉禹錫','唐','御定全唐诗','yuding','','[]','屬車八十一，此地阻長風。千載威靈盡，赭山寒水中。',24,'御定全唐詩/json/364.json','["屬車八十一，此地阻長風。千載威靈盡，赭山寒水中。"]'),
('yuding-13','庭竹','劉禹錫','唐','御定全唐诗','yuding','','[]','露滌鉛粉節，風搖青玉枝。依依似君子，無地不相宜。',24,'御定全唐詩/json/364.json','["露滌鉛粉節，風搖青玉枝。依依似君子，無地不相宜。"]'),
('yuding-14','唐郎中宅與諸公同飲酒看牡丹','劉禹錫','唐','御定全唐诗','yuding','','[]','今日花前飲，甘心醉數杯。但愁花有語，不為老人開。',24,'御定全唐詩/json/364.json','["今日花前飲，甘心醉數杯。但愁花有語，不為老人開。"]'),
('yuding-15','題壽安甘棠館二首','劉禹錫','唐','御定全唐诗','yuding','','[]','公館似仙家，池清竹徑斜。山禽忽驚起，沖落半岩花。',48,'御定全唐詩/json/364.json','["公館似仙家，池清竹徑斜。山禽忽驚起，沖落半岩花。", "門前洛陽道，門裏桃花路。塵土與煙霞，其間十餘步。"]'),
('yuding-16','古詞二首','劉禹錫','唐','御定全唐诗','yuding','','[]','軒後初冠冕，前旒為蔽明。安知從複道，然後見人情。',48,'御定全唐詩/json/364.json','["軒後初冠冕，前旒為蔽明。安知從複道，然後見人情。", "簿領乃俗士，清談信古風。吾觀蘇令綽，朱墨一何工。"]'),
('yuding-17','寓興二首','劉禹錫','唐','御定全唐诗','yuding','','[]','常談即至理，安事非常情。寄語何平叔，無為輕老生。',48,'御定全唐詩/json/364.json','["常談即至理，安事非常情。寄語何平叔，無為輕老生。", "世途多禮數，鵬鷃各逍遙。何事陶彭澤，拋官為折腰。"]'),
('yuding-18','詠史二首','劉禹錫','唐','御定全唐诗','yuding','','[]','驃騎非無勢，少卿終不去。世道劇頹波，我心如砥柱。',48,'御定全唐詩/json/364.json','["驃騎非無勢，少卿終不去。世道劇頹波，我心如砥柱。", "賈生明王道，衛綰工車戲。同遇漢文時，何人居貴位。"]'),
('yuding-19','經檀道濟故壘','劉禹錫','唐','御定全唐诗','yuding','','[]','萬里長城壞，荒營野草秋。秣陵多士女，猶唱白符鳩。',24,'御定全唐詩/json/364.json','["萬里長城壞，荒營野草秋。秣陵多士女，猶唱白符鳩。"]'),
('yuding-20','傷段右丞','劉禹錫','唐','御定全唐诗','yuding','','[]','江海多豪氣，朝廷有直聲。何言馬蹄下，一旦是佳城。',24,'御定全唐詩/json/364.json','["江海多豪氣，朝廷有直聲。何言馬蹄下，一旦是佳城。"]'),
('yuding-21','傷獨孤舍人','劉禹錫','唐','御定全唐诗','yuding','','[]','昔別矜年少，今悲喪國華。遠來同社燕，不見早梅花。',24,'御定全唐詩/json/364.json','["昔別矜年少，今悲喪國華。遠來同社燕，不見早梅花。"]'),
('yuding-22','再傷龐尹','劉禹錫','唐','御定全唐诗','yuding','','[]','京兆歸何處，章台空暮塵。可憐鸞鏡下，哭殺畫眉人。',24,'御定全唐詩/json/364.json','["京兆歸何處，章台空暮塵。可憐鸞鏡下，哭殺畫眉人。"]'),
('yuding-23','敬酬微公見寄二首','劉禹錫','唐','御定全唐诗','yuding','','[]','淒涼沃州僧，憔悴柴桑宰。別來二十年，唯餘兩心在。',48,'御定全唐詩/json/364.json','["淒涼沃州僧，憔悴柴桑宰。別來二十年，唯餘兩心在。", "越江千里鏡，越嶺四時雪。中有逍遙人，夜深觀水月。"]'),
('yuding-24','鄂渚留別李二十一表臣大夫','劉禹錫','唐','御定全唐诗','yuding','','[]','高檣起行色，促柱動離聲。欲問江深淺，應如遠別情。',24,'御定全唐詩/json/364.json','["高檣起行色，促柱動離聲。欲問江深淺，應如遠別情。"]'),
('yuding-25','答表臣贈別二首','劉禹錫','唐','御定全唐诗','yuding','','[]','昔為瑤池侶，飛舞集蓬萊。今作江漢別，風雪一徘徊。',48,'御定全唐詩/json/364.json','["昔為瑤池侶，飛舞集蓬萊。今作江漢別，風雪一徘徊。", "嘶馬立未還，行舟路將轉。江頭暝色深，揮袖依稀見。"]'),
('yuding-26','始發鄂渚寄表臣二首','劉禹錫','唐','御定全唐诗','yuding','','[]','祖帳管弦絕，客帆西風生。回車已不見，猶聽馬嘶聲。',48,'御定全唐詩/json/364.json','["祖帳管弦絕，客帆西風生。回車已不見，猶聽馬嘶聲。", "曉發柳林戍，遙城聞五鼓。憶與故人眠，此時猶晤語。"]'),
('yuding-27','出鄂州界懷錶臣二首','劉禹錫','唐','御定全唐诗','yuding','','[]','離席一揮杯，別愁今尚醉。遲遲有情處，卻恨江帆駛。',48,'御定全唐詩/json/364.json','["離席一揮杯，別愁今尚醉。遲遲有情處，卻恨江帆駛。", "夢覺疑連榻，舟行忽千里。不見黃鶴樓，寒沙雪相似。"]'),
('yuding-28','和游房公舊竹亭聞琴絕句','劉禹錫','唐','御定全唐诗','yuding','','[]','尚有竹間路，永無綦下塵。一聞流水曲，重憶餐霞人。',24,'御定全唐詩/json/364.json','["尚有竹間路，永無綦下塵。一聞流水曲，重憶餐霞人。"]'),
('yuding-29','西州李尚書知愚與元武昌有舊遠示二篇吟之泫然因以繼和二首','劉禹錫','唐','御定全唐诗','yuding','','[]','如何贈琴日，已是絕弦時。無複雙金報，空餘掛劍悲。',48,'御定全唐詩/json/364.json','["如何贈琴日，已是絕弦時。無複雙金報，空餘掛劍悲。", "寶匣從此閑，朱弦誰複調。只應隨玉樹，同向土中銷。"]'),
('yuding-30','別蘇州二首','劉禹錫','唐','御定全唐诗','yuding','','[]','三載為吳郡，臨岐祖帳開。雖非謝桀黠，且為一裴回。',48,'御定全唐詩/json/364.json','["三載為吳郡，臨岐祖帳開。雖非謝桀黠，且為一裴回。", "流水閶門外，秋風吹柳條。從來送客處，今日自魂銷。"]'),
('yuding-31','罷和州游建康','劉禹錫','唐','御定全唐诗','yuding','','[]','秋水清無力，寒山暮多思。官閑不計程，遍上南朝寺。',24,'御定全唐詩/json/364.json','["秋水清無力，寒山暮多思。官閑不計程，遍上南朝寺。"]'),
('yuding-32','九日登高','劉禹錫','唐','御定全唐诗','yuding','','[]','世路山河險，君門煙霧深。年年上高處，未省不傷心。',24,'御定全唐詩/json/364.json','["世路山河險，君門煙霧深。年年上高處，未省不傷心。"]'),
('yuding-33','答柳子厚','劉禹錫','唐','御定全唐诗','yuding','','[]','年方伯玉早，恨比四愁多。會待休車騎，相隨出罻羅。',24,'御定全唐詩/json/364.json','["年方伯玉早，恨比四愁多。會待休車騎，相隨出罻羅。"]'),
('yuding-34','館娃宮在舊郡西南硯石山前瞰姑蘇臺傍有采香徑梁天監中置佛寺曰靈巖即故宮也信為絕境因賦二章','劉禹錫','唐','御定全唐诗','yuding','','[]','宮館貯嬌娃，當時意大誇。豔傾吳國盡，笑入楚王家。',48,'御定全唐詩/json/364.json','["宮館貯嬌娃，當時意大誇。豔傾吳國盡，笑入楚王家。", "月殿移椒壁，天花代舜華。唯餘采香徑，一帶繞山斜。"]'),
('yuding-0','聽琴','劉禹錫','唐','御定全唐诗','yuding','','[]','禪思何妨在玉琴，真僧不見聽時心。',32,'御定全唐詩/json/365.json','["禪思何妨在玉琴，真僧不見聽時心。", "秋堂境寂夜方半，雲去蒼梧湘水深。"]'),
('yuding-1','魏宮詞二首','劉禹錫','唐','御定全唐诗','yuding','','[]','日晚長秋簾外報，望陵歌舞在明朝。',64,'御定全唐詩/json/365.json','["日晚長秋簾外報，望陵歌舞在明朝。", "添爐欲爇熏衣麝，憶得分時不忍燒。", "日映西陵松柏枝，下臺相顧一相思。", "朝來樂府長歌曲，唱著君王自作詞。"]'),
('yuding-2','楊枝詞二首','劉禹錫','唐','御定全唐诗','yuding','','[]','迎得春光先到來，淺黃輕綠映樓臺。',64,'御定全唐詩/json/365.json','["迎得春光先到來，淺黃輕綠映樓臺。", "只緣嫋娜多情思，更被春風長倩猜。", "巫峽巫山楊柳多，朝雲暮雨遠相和。", "因想陽臺無限事，來君回唱竹枝歌。"]'),
('yuding-3','竹枝詞二首','劉禹錫','唐','御定全唐诗','yuding','','[]','楊柳青青江水準，聞郎江上唱歌聲。',64,'御定全唐詩/json/365.json','["楊柳青青江水準，聞郎江上唱歌聲。", "東邊日出西邊雨，道是無晴卻有晴。", "楚水巴山江雨多，巴人能唱本鄉歌。", "今朝北客思歸去，回入紇那披綠羅。"]'),
('yuding-4','堤上行三首','劉禹錫','唐','御定全唐诗','yuding','','[]','酒旗相望大堤頭，堤下連檣堤上樓。',96,'御定全唐詩/json/365.json','["酒旗相望大堤頭，堤下連檣堤上樓。", "日暮行人爭渡急，槳聲幽軋滿中流。", "江南江北望煙波，入夜行人相應歌。", "桃葉傳情竹枝怨，水流無限月明多。", "春堤繚繞水徘徊，酒舍旗亭次第開。", "日晚上樓招估客，軻峨大艑落帆來。"]'),
('yuding-5','《踏歌詞四首','劉禹錫','唐','御定全唐诗','yuding','','[]','春江月出大堤平，堤上女郎連袂行。',128,'御定全唐詩/json/365.json','["春江月出大堤平，堤上女郎連袂行。", "唱盡新詞歡不見，紅霞映樹鷓鴣鳴。", "桃蹊柳陌好經過，燈下妝成月下歌。", "為是襄王故宮地，至今猶自細腰多。", "新詞宛轉遞相傳，振袖傾鬟風露前。", "月落烏啼雲雨散，游童陌上拾花鈿。", "日暮江頭聞竹枝，南人行樂北人悲。", "自從雪裏唱新曲，直到三春花盡時。"]'),
('yuding-6','步虛詞二首','劉禹錫','唐','御定全唐诗','yuding','','[]','阿母種桃雲海際，花落子成三千歲。',64,'御定全唐詩/json/365.json','["阿母種桃雲海際，花落子成三千歲。", "海風吹折最繁枝，跪捧瓊盤獻天帝。", "華表千年一鶴歸，凝丹為頂雪為衣。", "星星仙語人聽盡，卻向五雲翻翅飛。"]'),
('yuding-7','阿嬌怨','劉禹錫','唐','御定全唐诗','yuding','','[]','望見葳蕤舉翠華，試開金屋掃庭花。',32,'御定全唐詩/json/365.json','["望見葳蕤舉翠華，試開金屋掃庭花。", "須臾宮女傳來信，言幸平陽公主家。"]'),
('yuding-8','秋詞二首','劉禹錫','唐','御定全唐诗','yuding','','[]','自古逢秋悲寂寥，我言秋日勝春朝。',64,'御定全唐詩/json/365.json','["自古逢秋悲寂寥，我言秋日勝春朝。", "晴空一鶴排雲上，便引詩情到碧霄。", "山明水淨夜來霜，數樹深紅出淺黃。", "試上高樓清入骨，豈如春色嗾人狂。"]'),
('yuding-9','秋扇詞','劉禹錫','唐','御定全唐诗','yuding','','[]','莫道恩情無重來，人間榮謝遞相催。',32,'御定全唐詩/json/365.json','["莫道恩情無重來，人間榮謝遞相催。", "當時初入君懷袖，豈念寒爐有死灰。"]'),
('yuding-10','竹枝詞九首','劉禹錫','唐','御定全唐诗','yuding','','[]','白帝城頭春草生，白鹽山下蜀江清。',288,'御定全唐詩/json/365.json','["白帝城頭春草生，白鹽山下蜀江清。", "南人上來歌一曲，北人莫上動鄉情。", "山桃紅花滿上頭，蜀江春水拍山流。", "花紅易衰似郎意，水流無限似儂愁。", "江上朱樓新雨晴，瀼西春水縠紋生。", "橋東橋西好楊柳，人來人去唱歌行。", "日出三竿春霧消，江頭蜀客駐蘭橈。", "憑寄狂夫書一紙，家住成都萬里橋。", "兩岸山花似雪開，家家春酒滿銀盃。", "昭君坊中多女伴，永安宮外踏青來。", "城西門前灩澦堆，年年波浪不能摧。", "懊惱人心不如石，少時東去複西來。", "瞿塘嘈嘈十二灘，人言道路古來難。", "長恨人心不如水，等閒平地起波瀾。", "巫峽蒼蒼煙雨時，清猿啼在最高枝。", "個裏愁人腸自斷，由來不是此聲悲。", "山上層層桃李花，雲間煙火是人家。", "銀釧金釵來負水，長刀短笠去燒畬。"]'),
('yuding-11','楊柳枝詞九首','劉禹錫','唐','御定全唐诗','yuding','','[]','塞北梅花羌笛吹，淮南桂樹小山詞。',288,'御定全唐詩/json/365.json','["塞北梅花羌笛吹，淮南桂樹小山詞。", "請君莫奏前朝曲，聽唱新翻楊柳枝。", "南陌東城春早時，相逢何處不依依。", "桃紅李白皆誇好，須得垂楊相發揮。", "鳳闕輕遮翡翠幃，龍池遙望麹塵絲。", "禦溝春水相輝映，狂殺長安年少兒。", "金穀園中鶯亂飛，銅駝陌上好風吹。", "城中桃李須臾盡，爭似垂楊無限時。", "花萼樓前初種時，美人樓上鬥腰肢。", "如今拋擲長街裏，露葉如啼欲向誰。", "煬帝行宮汴水濱，數枝楊柳不勝春。", "晚來風起花如雪，飛入宮牆不見人。", "禦陌青門拂地垂，千條金縷萬條絲。", "如今綰作同心結，將贈行人知不知。", "城外春風吹酒旗，行人揮袂日西時。", "長安陌上無窮樹，唯有垂楊管別離。", "輕盈嫋娜占年華，舞榭妝樓處處遮。", "春盡絮花留不得，隨風好去落誰家。"]'),
('yuding-12','浪淘沙九首','劉禹錫','唐','御定全唐诗','yuding','','[]','九曲黃河萬里沙，浪淘風簸自天涯。',288,'御定全唐詩/json/365.json','["九曲黃河萬里沙，浪淘風簸自天涯。", "如今直上銀河去，同到牽牛織女家。", "洛水橋邊春日斜，碧流清淺見瓊砂。", "無端陌上狂風急，驚起鴛鴦出浪花。", "汴水東流虎眼紋，清淮曉色鴨頭春。", "君看渡口淘沙處，渡卻人間多少人。", "鸚鵡洲頭浪颭沙，青樓春望日將斜。", "銜泥燕子爭歸舍，獨自狂夫不憶家。", "濯錦江邊兩岸花，春風吹浪正淘沙。", "女郎剪下鴛鴦錦，將向中流匹晚霞。", "日照澄洲江霧開，淘金女伴滿江隈。", "美人首飾侯王印，儘是沙中浪底來。", "八月濤聲吼地來，頭高數丈觸山回。", "須臾卻入海門去，卷起沙堆似雪堆。", "莫道讒言如浪深，莫言遷客似沙沉。", "千淘萬漉雖辛苦，吹盡狂沙始到金。", "流水淘沙不暫停，前波未滅後波生。", "令人忽憶瀟湘渚，回唱迎神三兩聲。"]'),
('yuding-13','洛中送韓七中丞之吳興口號五首','劉禹錫','唐','御定全唐诗','yuding','','[]','昔年意氣結群英，幾度朝回一字行。',160,'御定全唐詩/json/365.json','["昔年意氣結群英，幾度朝回一字行。", "海北江南零落盡，兩人相見洛陽城。", "自從雲散各東西，每日歡娛卻慘淒。", "離別苦多相見少，一生心事在書題。", "今朝無意訴離杯，何況清弦急管催。", "本欲醉中輕遠別，不知翻引酒悲來。", "駱駝橋上蘋風急，鸚鵡杯中箬下春。", "水碧山青知好處，開顏一笑向何人。", "溪中士女出笆籬，溪上鴛鴦避畫旗。", "何處人間似仙境，春山攜妓採茶時。"]'),
('yuding-14','送廖參謀東游二首','劉禹錫','唐','御定全唐诗','yuding','','[]','九陌逢君又別離，行雲別鶴本無期。',64,'御定全唐詩/json/365.json','["九陌逢君又別離，行雲別鶴本無期。", "望嵩樓上忽相見，看過花開花落時。", "繁花落盡君辭去，綠草垂楊引征路。", "東道諸侯皆故人，留連必是多情處。"]'),
('yuding-15','洛中春末送杜錄事赴蘄州','劉禹錫','唐','御定全唐诗','yuding','','[]','樽前花下長相見，明日忽為千里人。',32,'御定全唐詩/json/365.json','["樽前花下長相見，明日忽為千里人。", "君過午橋回首望，洛城猶自有殘春。"]'),
('yuding-16','夜燕福建盧侍郎宅因送之鎮','劉禹錫','唐','御定全唐诗','yuding','','[]','暫駐旌旗洛水堤，綺筵紅燭醉蘭閨。',32,'御定全唐詩/json/365.json','["暫駐旌旗洛水堤，綺筵紅燭醉蘭閨。", "美人美酒長相逐，莫怕猿聲發建溪。"]'),
